-- Poems batch 356
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('54585c69-d2fd-45ee-ac57-cde9de219a2b','十二時  其一二','釋咸靜','宋','宋诗','song-poetry','','[]','人定亥，念念無常剎那快。',28,'全唐诗/poet.song.74000.json','["人定亥，念念無常剎那快。", "回光省取不遷心，坐照十虛誰對待。"]'),
('7ef9cea0-3647-40bf-b360-71db598ef2e1','拄杖歌','釋咸靜','宋','宋诗','song-poetry','','[]','誰人無一條拄杖，我家收底醜模樣。',192,'全唐诗/poet.song.74000.json','["誰人無一條拄杖，我家收底醜模樣。", "徹頭徹尾節目深，從生至老筋骸壯。", "不須修，何須漆，體段自然成箇格。", "或行或坐儘隨身，或倚或携還任力。", "拋一拋，卓一卓，三界魔王頓驚愕。", "雨雲雷電匝長空，展盡神通難揣摸。", "有時收，有時用，縱奪臨機恣拈弄。", "儻蒙上士入門來，一棒打教知痒痛。", "說道理，沒人情，動著教伊禍患生。", "休誇昔日化龍勢，謾說當年解虎聲。", "挑日月，吞乾坤，劃開一路涅槃門。", "大丈夫兒須執捉，一言不契命難存。"]'),
('34f43220-c0ed-4068-b9e7-526f00ce2efc','偈十二首  其一','釋本才','宋','宋诗','song-poetry','','[]','上封一句，海墨難詮。',30,'全唐诗/poet.song.74000.json','["上封一句，海墨難詮。", "牆壁瓦礫，晝夜流傳。", "若住聽瑩，鷂子沖天。"]'),
('deee344a-d947-4af3-bcbb-47a3ac127339','偈十二首  其二','釋本才','宋','宋诗','song-poetry','','[]','當陽不顯迹，文彩未生前。',56,'全唐诗/poet.song.74000.json','["當陽不顯迹，文彩未生前。", "只箇平常處，壺中別是天。", "別是天，唯自到，緩行急行俱蹉過。", "紅塵數盡去來人，李白元是癡措大。"]'),
('5db571b3-dab0-44c8-b71f-170d23d02e7e','偈十二首  其三','釋本才','宋','宋诗','song-poetry','','[]','色本殊質像，聲元異樂苦。',70,'全唐诗/poet.song.74000.json','["色本殊質像，聲元異樂苦。", "眼耳絕見聞，半夜日輪午。", "日輸午，與誰說，休向虛空重釘橛。", "烱烱森羅相對看，如浄琉璃含寶月。", "無智人前莫說，打汝頭破腦裂。"]'),
('143a099b-0516-4292-abcd-029a8324b57c','偈十二首  其四','釋本才','宋','宋诗','song-poetry','','[]','二由一有，一亦莫守。',54,'全唐诗/poet.song.74000.json','["二由一有，一亦莫守。", "拂子朝到西天，暮歸唐土。", "也無佛，也無祖，夜半日輸正當午。", "露柱燈籠𡎺著時，誰道黄金如糞土。"]'),
('d98c2308-8020-4ce2-bf0a-a21afd2cfb8c','偈十二首  其五','釋本才','宋','宋诗','song-poetry','','[]','清機歷掌，同道方知，格外稱提。',76,'全唐诗/poet.song.74000.json','["清機歷掌，同道方知，格外稱提。", "徒勞䧟啄，句中有句。", "埋沒已靈，句中無句。", "藏身北斗，拈燈籠向佛殿裏。", "即且置將三門來，燈籠上又作麽生。", "自是覷不見，剛道有遮護。"]'),
('cc2d5c50-2750-4697-8cc4-e499d59e756c','偈十二首  其六','釋本才','宋','宋诗','song-poetry','','[]','智身迥出先天地，大用縱橫不易知。',32,'全唐诗/poet.song.74000.json','["智身迥出先天地，大用縱橫不易知。", "鼓舞靈源宣衆妙，人間天上仰無爲。"]'),
('931d551d-eb7e-4471-aea6-c727975396ae','偈十二首  其七','釋本才','宋','宋诗','song-poetry','','[]','雞鳴丑，一顆圓光明已久。',48,'全唐诗/poet.song.74000.json','["雞鳴丑，一顆圓光明已久。", "忽然抖擻起來時，問著依前還漏逗。", "還漏逗，擬欲藏身北斗前，應須合掌南辰後。"]'),
('dbe73082-8d61-4734-a86d-8c5807322142','偈十二首  其八','釋本才','宋','宋诗','song-poetry','','[]','三界無法，何處求心。',36,'全唐诗/poet.song.74000.json','["三界無法，何處求心。", "四大本空，佛依何住。", "直得清寥寥白滴滴，猶是真常流注。"]'),
('84ebc95d-71ba-4cb2-848f-4cbf9e5a42dc','偈十二首  其九','釋本才','宋','宋诗','song-poetry','','[]','上無攀仰，下絕已躬。',68,'全唐诗/poet.song.74000.json','["上無攀仰，下絕已躬。", "喚起懷州牛喫禾，捺下益州馬腹脹。", "從教天下覓醫人，炙豬左膊上。", "奇，奇，是是非非總不知。", "夢回瞥起臨明鏡，洎被張公錯畫眉。"]'),
('e27357a4-fb9c-4f41-a8bb-2067b87f9520','偈十二首  其一○','釋本才','宋','宋诗','song-poetry','','[]','諸佛放光明，助發真實相。',24,'全唐诗/poet.song.74000.json','["諸佛放光明，助發真實相。", "希有諸比丘，是中無比況。"]'),
('2eb8561f-e267-496f-a106-7c5cc2d94194','偈十二首  其一一','釋本才','宋','宋诗','song-poetry','','[]','袖裏暫閑醫國手，岸巾來訪卧雲人。',129,'全唐诗/poet.song.74000.json','["袖裏暫閑醫國手，岸巾來訪卧雲人。", "相逢一笑千峰頂，高下森羅百億身。", "相逢一笑，萬壑風清。", "大冶精金，應無變色。", "黄檗昔遇裴相國，當頭一劄，冷暖自知。", "睦州久契陳尚書，剖露肝腸，清虛廓落。", "正當今日，賓主互換。", "覿體唱酬，似空藏空，如鏡照鏡。", "芥子拈來敲石窟，須知渠是箇中人。"]'),
('650ea103-c209-4a95-8884-b385ee5ccd39','偈十二首  其一二','釋本才','宋','宋诗','song-poetry','','[]','畫餠不足以充饑，大羹必資於敏手。',74,'全唐诗/poet.song.74000.json','["畫餠不足以充饑，大羹必資於敏手。", "浄瓶趯倒，目前贏得大溈山。", "鐵鉢擎來，八萬毛孔皆香發。", "口吞三世即且置，鐵牛不食連鞭草。", "機梭不犯風雲勢，石笋從教劫外抽。"]'),
('5752a331-fa5c-4cf5-aa0b-cb82ac3fc50b','偈十二首  其一三','釋本才','宋','宋诗','song-poetry','','[]','秋風浩浩來，芙蓉花半開。',51,'全唐诗/poet.song.74000.json','["秋風浩浩來，芙蓉花半開。", "秋風蕭蕭去，黄葉填山路。", "大塊本無私，恩威各有遇。", "藏頭白海頭黑，明眼衲僧辨不得。"]'),
('1282be74-c159-4f78-80b4-04220e0bc7b6','頌古二首 達磨見梁武帝。','釋本才','宋','宋诗','song-poetry','','[]','遠泛鯨波入大梁，廓然無聖對君王。',32,'全唐诗/poet.song.74000.json','["遠泛鯨波入大梁，廓然無聖對君王。", "可憐徑寸無人鑑，却與相如依舊藏。"]'),
('9a4ec710-45a4-4e91-ba55-9c2d8b8e3dc7','頌古二首 寶壽開堂，三聖推出一僧。','釋本才','宋','宋诗','song-poetry','','[]','豐城收寶劍，宇宙識人稀。',24,'全唐诗/poet.song.74000.json','["豐城收寶劍，宇宙識人稀。", "不入張華手，焉能別是非。"]'),
('f7231145-55ad-45ac-b201-47b00165f706','偈二首  其一','釋本才','宋','宋诗','song-poetry','','[]','達磨未來，懷藏至寶，頂髻有珠。',40,'全唐诗/poet.song.74000.json','["達磨未來，懷藏至寶，頂髻有珠。", "達磨既來，卞和刖足，楊朱途窮。", "擬議之間，知君罔措。"]'),
('d1efcc19-cd41-46ac-acba-3d86fe9ec8a9','偈二首  其二','釋本才','宋','宋诗','song-poetry','','[]','一法有形該動植，百川湍激競朝宗。',32,'全唐诗/poet.song.74000.json','["一法有形該動植，百川湍激競朝宗。", "昭琴不鼓雲天淡，想像毗耶老病翁。"]'),
('2aa7e5ac-f1df-4bc8-87ff-fe6403b67cd5','頌古二首 風幡。','釋本才','宋','宋诗','song-poetry','','[]','指出風幡俱不是，直言心動亦還非。',32,'全唐诗/poet.song.74000.json','["指出風幡俱不是，直言心動亦還非。", "夜來一片曹溪月，却照儂家舊翠微。"]'),
('96253696-175d-46a8-8ba5-4427757b6644','頌古二首 大禪佛參仰山後到霍山。','釋本才','宋','宋诗','song-poetry','','[]','子陵灘水急如弦，摸得黄魚縮項鯿。',32,'全唐诗/poet.song.74000.json','["子陵灘水急如弦，摸得黄魚縮項鯿。", "提向市中頻索價，他家不著半分錢。"]'),
('a39e2b38-a91f-46ab-8efa-2312c3c91199','偈二首  其一','釋本才','宋','宋诗','song-poetry','','[]','徹，徹，大海乾枯，虛空迸裂。',30,'全唐诗/poet.song.74000.json','["徹，徹，大海乾枯，虛空迸裂。", "四方八面絕遮攔，萬象森羅齊漏泄。"]'),
('0f7d0682-c6a8-48c2-89a4-201fb893b0a7','偈二首  其二','釋本才','宋','宋诗','song-poetry','','[]','一法有形該動植，百川湍激競朝宗。',32,'全唐诗/poet.song.74000.json','["一法有形該動植，百川湍激競朝宗。", "昭琴不鼓雲天淡，想像毗耶老病翁。"]'),
('807ffdd2-483d-463e-9937-22dcb6ebe437','偈','釋空','宋','宋诗','song-poetry','','[]','十方無壁落，四面亦無門。',24,'全唐诗/poet.song.74000.json','["十方無壁落，四面亦無門。", "浄裸裸，赤灑灑，沒可把。"]'),
('c3789d76-5eb5-4e1e-a17d-b4ff793c35e0','野狐話頌','釋空','宋','宋诗','song-poetry','','[]','含血噀人，先污其口。',30,'全唐诗/poet.song.74000.json','["含血噀人，先污其口。", "百丈野狐，失頭狂走。", "驀地喚回，打個筋斗。"]'),
('e9272024-99e1-4aab-b93d-9b2e5c39abc3','頌古 柏樹。','釋空','宋','宋诗','song-poetry','','[]','打人駡人易，勸人休却難。',24,'全唐诗/poet.song.74000.json','["打人駡人易，勸人休却難。", "不識饒人處，急水下高灘。"]'),
('06d6dfd5-24f9-4703-b57f-50b0b455e012','太平曲','釋普初','宋','宋诗','song-poetry','','[]','無爲而爲，神而化之。',50,'全唐诗/poet.song.74000.json','["無爲而爲，神而化之。", "灑德雨以霶霈，鼓仁風而雍熙。", "民如野鹿，上如標枝。", "十八子，知不知。", "哩哩囉，囉囉哩。"]'),
('b949f854-e577-40f1-9a57-e4b2fb49665a','偈','釋從密','宋','宋诗','song-poetry','','[]','開口不是禪，合口不是道。',24,'全唐诗/poet.song.74000.json','["開口不是禪，合口不是道。", "踏步擬進前，全身落荒草。"]'),
('e87d09df-0c1b-4e9f-9563-db2a84dc0488','偈','釋宗密','宋','宋诗','song-poetry','','[]','休把庭華類此身，庭華落後更逢春。',32,'全唐诗/poet.song.74000.json','["休把庭華類此身，庭華落後更逢春。", "此身一往知何處，三界茫茫愁殺人。"]'),
('48ded7c3-1341-4790-87d2-4d8e4205d8b5','偈','知和庵主','宋','宋诗','song-poetry','','[]','竹筧二三升野水，松窗七五片閑雲。',32,'全唐诗/poet.song.74000.json','["竹筧二三升野水，松窗七五片閑雲。", "道人活計祇如此，留與人間作見聞。"]'),
('2ffaeede-ceea-4e86-a0d2-85bba8fb1aab','寶積寺','劉芑','宋','宋诗','song-poetry','','[]','寶積重來異昔年，修廊千步闢山邊。',64,'全唐诗/poet.song.74000.json','["寶積重來異昔年，修廊千步闢山邊。", "南分靈派渠行玉，北敞高臺花雨天。", "日照青林猶带潤，雲收翠崦尚藏烟。", "龐眉老子升猊坐，不惜家風示衆賢。"]'),
('4abd2eb6-464c-47aa-b1b7-573c594bd457','偈','釋普崇','宋','宋诗','song-poetry','','[]','非風非幡無處著，是風是幡無著處。',56,'全唐诗/poet.song.74000.json','["非風非幡無處著，是風是幡無著處。", "遼天俊鶻悉迷蹤，踞地金毛還失措。", "呵呵呵，悟不悟。", "令人轉憶謝三郎，一絲獨釣寒江雨。"]'),
('f10098fd-f2e4-4ab9-89d2-93dc6c24ea15','酬普首座偈','釋持','宋','宋诗','song-poetry','','[]','性空老人何快活，只有三衣并一鉢。',112,'全唐诗/poet.song.74000.json','["性空老人何快活，只有三衣并一鉢。", "叢林端的死心兒，見膽開談心豁豁。", "有時吹笛當言說，一聲吹落西江月。", "桃花菴中快活時，往往觀者舞不徹。", "甚道理，能歡悅，摇手向人應道別。", "堪笑無人知此意，盡道稱鎚硬似鐵。", "難瞞唯有當行家，爲報臨機莫漏泄。"]'),
('883a0441-c6e8-49c2-9af0-9b743842617f','悼普首座偈','釋持','宋','宋诗','song-poetry','','[]','僧不僧，俗不俗，曾得死心親付囑。',100,'全唐诗/poet.song.74000.json','["僧不僧，俗不俗，曾得死心親付囑。", "平生知命只逍遥，行道苦無清浄福。", "東西南北放癡憨，七十七年𢝘怪足。", "黍桶裏著到，波濤裏洗浴，個中誰會無生曲。", "隨潮流去又流歸，莫是菴前戀筇竹。", "呵呵呵，老大哥，快活誰人奈汝何。"]'),
('13489b46-b517-484c-95c0-72553e71dc27','偈','釋持','宋','宋诗','song-poetry','','[]','休將碧落中秋節，來並曹溪無相月。',96,'全唐诗/poet.song.74000.json','["休將碧落中秋節，來並曹溪無相月。", "冷淡無關玉兔光，虛明直透銀蟾穴。", "圓不圓，缺不缺，一道靈光無間歇。", "照人何處不分明，直下承當眼添屑。", "本無生，亦無滅，只有休心最親切。", "採石江頭弄影時，謫仙到此空顛蹶。"]'),
('e8fd0e83-8a87-4007-9ca0-cb9e3a56cae6','中秋不見月偈','釋持','宋','宋诗','song-poetry','','[]','悟心容易息心難，息得心源到處閑。',32,'全唐诗/poet.song.74000.json','["悟心容易息心難，息得心源到處閑。", "斗轉星移天欲曉，白雲依舊覆青山。"]'),
('6f2100fb-41dd-4b88-bb24-e53f1d86516b','嘲妙普偈','釋持','宋','宋诗','song-poetry','','[]','咄哉老性空，剛要餒魚鼈。',24,'全唐诗/poet.song.74000.json','["咄哉老性空，剛要餒魚鼈。", "去不索性去，祇管向人說。"]'),
('2361a457-da06-4c37-8e0c-d2d305870355','偈','釋益','宋','宋诗','song-poetry','','[]','一葉落，天下秋。',24,'全唐诗/poet.song.74000.json','["一葉落，天下秋。", "一塵起，大地收。", "一法透，萬法周。"]'),
('8fe74deb-0164-47f5-9223-91d702b4f756','偈二首  其一','釋鑾','宋','宋诗','song-poetry','','[]','衆賣華兮獨賣松，青青顔色不如紅。',32,'全唐诗/poet.song.74000.json','["衆賣華兮獨賣松，青青顔色不如紅。", "算來終不與時合，歸去來兮翠靄中。"]'),
('62fd4d58-761f-4f20-b628-16dccb83f0dd','偈二首  其二','釋鑾','宋','宋诗','song-poetry','','[]','遁迹隠高峰，高峰又不容。',24,'全唐诗/poet.song.74000.json','["遁迹隠高峰，高峰又不容。", "不如歸錦里，依舊賣青松。"]'),
('c77b58ed-0cdd-47ae-98f0-f34aa2bdd4c4','偈','釋希明','宋','宋诗','song-poetry','','[]','林葉紛紛落，乾坤報早秋。',24,'全唐诗/poet.song.74000.json','["林葉紛紛落，乾坤報早秋。", "分明西祖意，何用更馳求。"]'),
('af8106c1-8d6f-440a-afef-853b6f178b5f','偈','釋道完','宋','宋诗','song-poetry','','[]','古人見此月，今人見此月。',48,'全唐诗/poet.song.74000.json','["古人見此月，今人見此月。", "此月鎮常存，古今人還別。", "若人心似月，碧潭光皎潔。", "决定是心源，此說更無說。"]'),
('a77aaf02-9b39-42a8-af0f-6afea2064081','偈','釋了常','宋','宋诗','song-poetry','','[]','等閑放下，佛手掩不住。',54,'全唐诗/poet.song.74000.json','["等閑放下，佛手掩不住。", "特地收來，大地絕纖埃。", "向君道，莫疑猜，處處頭頭見善財。", "鎚下分明如得旨，無限勞生眼自開。"]'),
('1fff1fb7-95d2-4ccf-bbd3-f47a860a49ba','偈三首  其一','釋慧照','宋','宋诗','song-poetry','','[]','龍安山下，道路縱橫。',86,'全唐诗/poet.song.74000.json','["龍安山下，道路縱橫。", "兜率宮中，樓閣重疊。", "雖非天上，不是人間。", "到者心安，全忘諸念。", "善行者不移雙足，善入者不動雙扉。", "自能笑傲烟蘿，誰管坐消歲月。", "莫教推落巖前石，打破下方遮日雲。"]'),
('caa5db00-32ca-4dbe-bbed-b76b583d4e44','偈三首  其二','釋慧照','宋','宋诗','song-poetry','','[]','端午龍安亦鼓橈，青山雲裏得逍遥。',32,'全唐诗/poet.song.74000.json','["端午龍安亦鼓橈，青山雲裏得逍遥。", "饑餐渴飲無窮樂，誰愛爭先奪錦標。"]'),
('2d417ad0-fb38-49f4-8a22-f88a37926275','偈三首  其三','釋慧照','宋','宋诗','song-poetry','','[]','兜率都無伎倆，也斅諸方榜樣。',56,'全唐诗/poet.song.74000.json','["兜率都無伎倆，也斅諸方榜樣。", "五日一度陞堂，起動許多龍象。", "禪道佛法又無，到此將何供養。", "須知達磨西來，分付一條拄杖。"]'),
('b7fb7cc0-831e-4211-9ed0-b093c6b26438','偈','釋智堯','宋','宋诗','song-poetry','','[]','捏土定千鈞，秤頭不立蠅。',24,'全唐诗/poet.song.74000.json','["捏土定千鈞，秤頭不立蠅。", "箇中些子事，走殺嶺南能。"]'),
('ca678e5a-1a45-4041-8f66-9cd07a1577ed','和忠道者牧牛頌','釋天游','宋','宋诗','song-poetry','','[]','兩角指天，四足踏地。',20,'全唐诗/poet.song.74000.json','["兩角指天，四足踏地。", "拽斷鼻繩，牧甚屎屁。"]'),
('4ffe3de3-7766-486a-be30-2f9c815289d6','偈四首  其一','釋天游','宋','宋诗','song-poetry','','[]','質庫何曾解典牛，祇緣價重實難酬。',32,'全唐诗/poet.song.74000.json','["質庫何曾解典牛，祇緣價重實難酬。", "想君本領無多子，畢竟難禁這一頭。"]'),
('44e2c05b-ea51-4b12-92e5-704d82687d44','偈四首  其二','釋天游','宋','宋诗','song-poetry','','[]','三百五百，銅頭鐵額。',20,'全唐诗/poet.song.74000.json','["三百五百，銅頭鐵額。", "木笛橫吹，誰來接拍。"]'),
('3661b70a-5e4a-4f63-93bb-eaec7a18745e','偈四首  其三','釋天游','宋','宋诗','song-poetry','','[]','寶峰有一訣，對衆分明說。',24,'全唐诗/poet.song.74000.json','["寶峰有一訣，對衆分明說。", "昨夜三更前，烏龜吞却鼈。"]'),
('4d63ec51-3181-4d3d-915f-925627e6bfee','偈四首  其四','釋天游','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',44,'全唐诗/poet.song.74000.json','["晷運推移，日南長至。", "布裩不洗，無來換替。", "大小玉泉，無風浪起。", "雲巖路見不平，直下一鎚粉碎。"]'),
('06790721-d1a2-4a41-9d1b-502bea4f09f7','辭衆頌','釋宗印','宋','宋诗','song-poetry','','[]','四十九年，一場熱鬨。',40,'全唐诗/poet.song.74000.json','["四十九年，一場熱鬨。", "八十七春，老漢獨弄。", "誰少誰多，一般作夢。", "歸去來兮，梅梢雪重。"]'),
('bd222a6b-cb79-473c-bebd-5da2a9561a09','投機頌','釋崇真','宋','宋诗','song-poetry','','[]','萬年倉裏曾饑饉，大海中住儘長渴。',32,'全唐诗/poet.song.74000.json','["萬年倉裏曾饑饉，大海中住儘長渴。", "當初尋時尋不見，如今避時避不得。"]'),
('f363359b-e47e-4176-8654-1dab50ba95c7','頌','釋智','宋','宋诗','song-poetry','','[]','吃官酒，卧官階。',32,'全唐诗/poet.song.74000.json','["吃官酒，卧官階。", "當處死，當處埋。", "沙場無限英靈漢，堆山積嶽露屍骸。"]'),
('fe761515-c612-46f8-b6b7-246fce9dd4db','偈二首  其一','釋德週','宋','宋诗','song-poetry','','[]','舉體露堂堂，十分無罣礙。',36,'全唐诗/poet.song.74000.json','["舉體露堂堂，十分無罣礙。", "千聖不能傳，萬靈咸頂戴。", "擬欲共商量，開口百雜碎。"]'),
('783a8533-48a7-48ae-8256-4f24921329fa','偈二首  其二','釋德週','宋','宋诗','song-poetry','','[]','回互不回互，覷見沒可睹。',40,'全唐诗/poet.song.74000.json','["回互不回互，覷見沒可睹。", "透出祖師關，踏斷人天路。", "呵呵呵，悟不悟，落花流水知何處。"]'),
('66c0990e-5577-43f8-9706-ed0ebc88d8c2','偈','釋子經','宋','宋诗','song-poetry','','[]','和氣生枯枿，寒雲散遠郊。',24,'全唐诗/poet.song.74000.json','["和氣生枯枿，寒雲散遠郊。", "木人占吉兆，夜半露龜爻。"]'),
('339321ea-3594-4c8c-86a0-d705661ac8fa','偈','釋曇清','宋','宋诗','song-poetry','','[]','殺父殺母，佛前懺悔。',35,'全唐诗/poet.song.74000.json','["殺父殺母，佛前懺悔。", "殺佛殺祖，不消懺悔。", "爲甚麽不消懺悔，且得冤家解脫。"]'),
('8c3e0ba2-4021-4502-8ea3-eba1828e9941','偈三首  其一','釋儀','宋','宋诗','song-poetry','','[]','莫分彼我，彼我無殊。',36,'全唐诗/poet.song.74000.json','["莫分彼我，彼我無殊。", "困魚止濼，病鳥棲蘆。", "逡巡不進泥中履，爭得先生一卷書。"]'),
('246d33e8-e53b-48fa-b762-45c376ffa1d9','偈三首  其二','釋儀','宋','宋诗','song-poetry','','[]','無相如來示現身，破魔兵衆絕纖塵。',32,'全唐诗/poet.song.74000.json','["無相如來示現身，破魔兵衆絕纖塵。", "七星斜映風生處，四海還歸舊主人。"]'),
('62d7d455-f921-4047-ab02-917acb9f39b7','偈三首  其三','釋儀','宋','宋诗','song-poetry','','[]','萬派橫流總向東，超然八面自玲瓏。',32,'全唐诗/poet.song.74000.json','["萬派橫流總向東，超然八面自玲瓏。", "萬人膽破沙場上，一箭雙雕落碧空。"]'),
('f14bf170-5511-41e5-ae07-d0f05ea02ea6','偈','釋辯','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物，鑽天鷂子遼天鶻。',56,'全唐诗/poet.song.74000.json','["不是心，不是佛，不是物，鑽天鷂子遼天鶻。", "不度火，不度水，不度爐，離弦箭發沒回途。", "直饒會得十分去，笑倒西來碧眼胡。"]'),
('62521069-be61-45fc-a2a6-91ee493dae99','偈','釋海評','宋','宋诗','song-poetry','','[]','燈籠上作舞，露柱裏藏身。',36,'全唐诗/poet.song.74000.json','["燈籠上作舞，露柱裏藏身。", "深沙神惡發，崑崙奴生嗔。", "一句合頭語，萬劫墮迷津。"]'),
('10bad312-0af6-4e07-a54a-7f122fa79b50','偈三首  其一','釋瑞仙','宋','宋诗','song-poetry','','[]','吾心似秋月，碧潭清皎潔。',96,'全唐诗/poet.song.74000.json','["吾心似秋月，碧潭清皎潔。", "無物堪比倫，教我如何說。", "堪嗟古人心，難與今人說。", "語與時人同，意與時人別。", "今人不會古人意，今日教我如何說。", "直饒會得寒山意，秋月碧潭猶未徹。", "此夜一輪明皎潔，縱目觀瞻不是月。"]'),
('3d35f415-7279-46bc-9bb5-3229d98c9cf6','偈三首  其二','釋瑞仙','宋','宋诗','song-poetry','','[]','棚頭鼓未鳴，部樂未抹搶。',36,'全唐诗/poet.song.74000.json','["棚頭鼓未鳴，部樂未抹搶。", "竿木逞伎倆，著忙出定場。", "懡㦬便回去，一段最光揚。"]'),
('9347269f-8e6c-44da-9c0f-bf3cdcc6477f','偈三首  其三','釋瑞仙','宋','宋诗','song-poetry','','[]','三箇橐駝兩隻脚，日行萬里趁不著。',32,'全唐诗/poet.song.74000.json','["三箇橐駝兩隻脚，日行萬里趁不著。", "而今收在玉泉山，不許時人亂斟酌。"]'),
('e71de187-5f99-4089-acb0-91f570809a92','偈二首  其一','釋法清','宋','宋诗','song-poetry','','[]','萬柳千華暖日開，一華端有一如來。',32,'全唐诗/poet.song.74000.json','["萬柳千華暖日開，一華端有一如來。", "妙談不二虛空藏，動著微言徧九垓。"]'),
('cf24b3fe-4a38-4020-a408-744065bd8f9b','偈二首  其二','釋法清','宋','宋诗','song-poetry','','[]','萬仞崖頭曾借路，百千禪侶盡生疑。',32,'全唐诗/poet.song.74000.json','["萬仞崖頭曾借路，百千禪侶盡生疑。", "只因滿眼多巘嶮，不識天然却問誰。"]'),
('17c77f32-7296-44ad-97c2-67cec327bf92','和馮濟川題枯髏圖','釋法清','宋','宋诗','song-poetry','','[]','形骸在此，其人何在。',20,'全唐诗/poet.song.74000.json','["形骸在此，其人何在。", "日炙風吹，掩彩掩彩。"]'),
('a65eae94-79ed-4cb4-add5-8570bff3225e','偈','法因庵主','宋','宋诗','song-poetry','','[]','巖上桃華開，華從何處來。',24,'全唐诗/poet.song.74000.json','["巖上桃華開，華從何處來。", "靈雲纔一見，回首舞三臺。"]'),
('da4d86c4-6f39-4a71-b900-f078654afa41','偈','釋圓慧','宋','宋诗','song-poetry','','[]','達磨正宗，衲僧巴鼻。',72,'全唐诗/poet.song.74000.json','["達磨正宗，衲僧巴鼻。", "堪嗟迷者成群，開眼瞌睡。", "頭上是天，脚下是地。", "耳朵聞聲，鼻孔出氣。", "敢問雲堂之徒，時中甚麽安置。", "可憐雙林傅大士，却言祇這語聲是。"]'),
('4034a273-30fe-452b-945c-75738cb4fbb2','偈','釋宗泰','宋','宋诗','song-poetry','','[]','會了喚作禪，未悟果然難。',38,'全唐诗/poet.song.74000.json','["會了喚作禪，未悟果然難。", "難難，目前隔箇須彌山。", "悟了易，易易，信口道來無不是。"]'),
('b8f0f319-ab6f-42dd-a96d-72394af882cd','題李伯時畫黄知命騎馿圖','邢居實','宋','宋诗','song-poetry','','[]','長安城頭烏夜棲，長安道上行人稀。',214,'全唐诗/poet.song.74000.json','["長安城頭烏夜棲，長安道上行人稀。", "浮雲卷盡暮天碧，但見明月流清輝。", "君獨騎馿向何處，頭上倒著白接䍦。", "長吟搔首望明月，不學山翁醉似泥。", "到得城中燈火鬧，小兒拍手攔街笑。", "道傍觀者那得知，相逢疑是商山皓。", "龍眠居士畫無比，摇毫弄筆長風起。", "酒酣閉目望窮途，紙上軒昂無乃似。", "君不學長安游俠誇年少，臂鷹挾彈章臺道。", "君不能提携長劍取靈武，指揮猛士驅貔虎。", "胡爲脚踏梁宋塵，終日飄飄無定所。", "武陵桃源春欲暮，白水青山起烟霧。", "竹杖芒鞋歸去來，頭巾任掛三花樹。"]'),
('04fe6e35-b669-4653-a9e3-0812978d5991','寄陳履常','邢居實','宋','宋诗','song-poetry','','[]','十年客京洛，衣袂多黄塵。',288,'全唐诗/poet.song.74000.json','["十年客京洛，衣袂多黄塵。", "所交盡才彥，唯子情相親。", "會合能幾日，歡樂何遽央。", "春風東北來，飄我西南翔。", "驪駒已在門，白日行且晚。", "停觴不能飲，將去更復返。", "把腕捋髭鬚，悲啼類兒女。", "人生非鹿豕，安得常羣聚。", "朝別河上梁，暮涉關山道。", "匹馬逐飛蓬，離恨如春草。", "去去日已遠，行行淚橫臉。", "昨日同袍友，今朝異鄉客。", "來時城南陌，始見梅花白。", "回首漢江頭，黄梅已堪摘。", "杖策登高城，極目迥千里。", "落日下青山，但見白雲起。", "遠望豈當歸，長歌涕如雨。", "歸心如明月，幽夢過潁汝。", "抱膝長相思，故人安可見。", "忽枉數行書，彷彿如對面。", "紛紜輦轂下，冠蓋爭馳逐。", "吹噓多賢豪，肯復念幽獨。", "空齋聽夜雨，深竹聞子規。", "此情不可道，此心君詎知。"]'),
('51b2d524-9105-477b-8547-aca6a5bc9df3','雨後出城馬上作','邢居實','宋','宋诗','song-poetry','','[]','既雨天氣佳，微雲淡如掃。',72,'全唐诗/poet.song.74000.json','["既雨天氣佳，微雲淡如掃。", "欲尋烟際鐘，騎馬河邊草。", "紫椹飽黄鸝，人家夏蠶老。", "田婦踏繅車，隔籬語音好。", "嗟我一何愚，讀書浪枯槁。", "不及此中人，中年客長道。"]'),
('d0bd1771-9253-46ae-8782-b7fca725e9d6','秋風三疊寄秦少游  其一','邢居實','宋','宋诗','song-poetry','','[]','秋風夕起兮白露爲霜，草木憔悴兮竊獨悲此衆芳。',78,'全唐诗/poet.song.74000.json','["秋風夕起兮白露爲霜，草木憔悴兮竊獨悲此衆芳。", "明月皎皎兮照空房，晝日苦短兮夜未央。", "有美一人兮天一方，欲往從之兮路渺茫。", "登山無車兮涉水無航，願言思子兮使我心傷。"]'),
('06b11f7c-d95b-4352-881c-5963c592c806','秋風三疊寄秦少游  其二','邢居實','宋','宋诗','song-poetry','','[]','秋風淅淅兮雲冥冥，鴟梟晝號兮蟋蟀夜鳴。',81,'全唐诗/poet.song.74000.json','["秋風淅淅兮雲冥冥，鴟梟晝號兮蟋蟀夜鳴。", "歲月徂邁兮忽如流星，少壯幾時兮老冉冉其相仍。", "展轉反側兮從夜達明，悵獨處此兮誰適爲情。", "長歌激烈兮涕泣交零，願言思子兮使我心怦。"]'),
('4c3b83fe-48f1-4df8-beb7-698ae7fa690e','秋風三疊寄秦少游  其三','邢居實','宋','宋诗','song-poetry','','[]','秋風浩蕩兮天宇高，羣山逶迤兮溪谷寂寥。',77,'全唐诗/poet.song.74000.json','["秋風浩蕩兮天宇高，羣山逶迤兮溪谷寂寥。", "登高望遠兮不自聊，駕言適野兮誰與遊遨。", "空原無人兮四顧蕭條，猨狖與伍兮麋鹿爲曹。", "浮雲千里兮歸路遥，願言思子兮使我心勞。"]'),
('f8aa71c7-bf2f-4555-8d62-8d9ac7e21842','明妃引','邢居實','宋','宋诗','song-poetry','','[]','漢宮有女顔如玉，淺畫蛾眉遠山綠。',320,'全唐诗/poet.song.74000.json','["漢宮有女顔如玉，淺畫蛾眉遠山綠。", "披香殿裏夜吹笙，未央宮中朝理曲。", "絳紗蒙籠雙蠟燭，簫鼓聲傳春漏促。", "玉輦三更別院歸，夜深月照黄金屋。", "莓苔滿院無行迹，總爲君王未相識。", "上天仙人骨法別，人間畫工畫不得。", "嫣然一笑金輿側，玉貌三千斂顔色。", "羅幃繡戶掩風香，一朝遠嫁單于國。", "金鳳羅衣爲誰縷，長袖弓彎不堪舞。", "一別昭陽舊院花，淚灑臙脂作紅雨。", "回頭不見雲間闕，黄河半渡新冰滑。", "馬蹄已踏遼碣塵，天邊尚掛長門月。", "黄沙不似長安道，薄暮微雲映衰草。", "羌人馬上鳴胡笳，綠髮朱顔爲君老。", "西風蕭蕭郅水寒，啼痕不斷幾闌干。", "年年看盡南飛雁，一去天涯竟不還。", "少年將軍健如虎，日夕撞鐘搥大鼓。", "寶刀生澀旌旗捲，漢宮嫁盡嬋娟女。", "寂寞邊城日將暮，三尺角弓調白羽。", "安得猛士霍嫖姚，縛取呼韓作編戶。"]'),
('dad6b023-d945-4ea1-b244-d9d20461e525','和黄魯直平原郡齋秋還二首  其一','邢居實','宋','宋诗','song-poetry','','[]','木落天高憶舊居，幾時歸去带經鋤。',32,'全唐诗/poet.song.74000.json','["木落天高憶舊居，幾時歸去带經鋤。", "黄花爛漫無人折，柿葉翻紅正好書。"]'),
('b72f6cbf-94ec-4db9-9935-e6510f30da88','和黄魯直平原郡齋秋還二首  其二','邢居實','宋','宋诗','song-poetry','','[]','目送愁雲盡日愁，寒來著破舊貂裘。',32,'全唐诗/poet.song.74000.json','["目送愁雲盡日愁，寒來著破舊貂裘。", "憑誰說與西風道，留取花間點綴秋。"]'),
('adacfed5-c6d4-41d6-b884-9f18b64b0b7e','送晁以道','邢居實','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君官泰山北，我住漢江東。',24,'全唐诗/poet.song.74000.json','["君官泰山北，我住漢江東。", "異國俱爲客，清樽恨不同。"]'),
('07358496-c41f-4622-9cb9-107968354369','棗陽道中','邢居實','宋','宋诗','song-poetry','','[]','春仲賦南征，歲暮復北走。',96,'全唐诗/poet.song.74000.json','["春仲賦南征，歲暮復北走。", "區區徒爾爲，慚愧道旁堠。", "岐路劇羊腸，重崗九十九。", "馬疲須著鞭，袖短難藏手。", "與君從此別，把袂倚衰柳。", "百年但如斯，不日成老醜。", "我本四方人，飄泊誰爲偶。", "有意問山神，此生復來否。"]'),
('a06c6428-c43c-4868-94d3-f794fcec5da2','秋日泛舟走筆呈同遊諸公','邢居實','宋','宋诗','song-poetry','','[]','秋波瀲灧泛橫溪，小楫輕舟逐浪移。',64,'全唐诗/poet.song.74000.json','["秋波瀲灧泛橫溪，小楫輕舟逐浪移。", "遠浦遥山俱慘淡，浴鳬飛鷺共差池。", "苦嫌斜日侵棋局，安得長竿理釣絲。", "歸去傾家新釀酒，還須來趁菊花時。"]'),
('132e68e7-4346-457d-a5de-72df633ce02b','句  其一','邢居實','宋','宋诗','song-poetry','','[]','微意平生在江海，塵冠今日爲君彈。',16,'全唐诗/poet.song.74000.json','["微意平生在江海，塵冠今日爲君彈。"]'),
('dff806f0-f94b-43a3-a7e1-9d9c87940984','句  其二','邢居實','宋','宋诗','song-poetry','','[]','高歌感人心，心悲將柰何。',12,'全唐诗/poet.song.74000.json','["高歌感人心，心悲將柰何。"]'),
('9eae68c2-ada6-48be-9f7b-4e5eb99d1d51','豫章行','謝逸','宋','宋诗','song-poetry','','[]','豫章棟梁材，託身南山阿。',120,'全唐诗/poet.song.74000.json','["豫章棟梁材，託身南山阿。", "王者建大厦，匠氏施斧柯。", "萬夫挽不行，留滯在河滸。", "自非浪滔天，何由至王所。", "根雖埋土中，葉已隨風飛。", "惟餘爨下柯，那得復相依。", "風吹兼雨打，日居復月諸。", "誓朽泥塗間，不及櫟與樗。", "匠氏慎無悔，豫章當自寬。", "人生類如此，才難聖所嘆。"]'),
('93eae849-9e5c-41db-813b-b38157386fed','讀陶淵明集','謝逸','宋','宋诗','song-poetry','','[]','淵明從遠公，了此一大事。',108,'全唐诗/poet.song.74000.json','["淵明從遠公，了此一大事。", "下視區中賢，略不可人意。", "不如歸田園，萬事付一醉。", "揮觴賦新詩，詩成聊自慰。", "初不求世售，世亦不我貴。", "意到語自工，心真理亦邃。", "何必聞虞韶，讀此可忘味。", "我欲追其韵，恨無三尺喙。", "嗟嘆之不足，作詩示同志。"]'),
('31641cda-cead-4bf0-91ab-e1566e462300','和王立之見贈四首  其一','謝逸','宋','宋诗','song-poetry','','[]','王子遺我詩，五言若長城。',48,'全唐诗/poet.song.74000.json','["王子遺我詩，五言若長城。", "誰謂永嘉末，復聞正始聲。", "咄嗟千人廢，雍容一坐傾。", "端能勵節義，何必五鼎烹。"]'),
('eec21f1a-a8df-421f-b878-8bd49fd29847','和王立之見贈四首  其二','謝逸','宋','宋诗','song-poetry','','[]','蛙蛤沒泥塗，鯢鰍游畎澮。',48,'全唐诗/poet.song.74000.json','["蛙蛤沒泥塗，鯢鰍游畎澮。", "豈知北溟鯤，翱翔九霄外。", "長安夸奢子，奔走逐冠蓋。", "古寺有佳人，幽吟發清籟。"]'),
('e328eb1d-3eb0-4f8f-ba4f-06cd89f4fb57','和王立之見贈四首  其三','謝逸','宋','宋诗','song-poetry','','[]','按劍毛先生，睨柱藺相如。',48,'全唐诗/poet.song.74000.json','["按劍毛先生，睨柱藺相如。", "欲市萬世名，非由十斛珠。", "善養浩然氣，外澤心不臞。", "桃花自春風，何用賦玄都。"]'),
('73e1d335-944b-44c7-9e90-66904b65ac11','和王立之見贈四首  其四','謝逸','宋','宋诗','song-poetry','','[]','鍾鳴戒夜行，途遠畏日暮。',48,'全唐诗/poet.song.74000.json','["鍾鳴戒夜行，途遠畏日暮。", "王良鞭驥子，一躍僅十步。", "怪事書咄咄，白髮生故故。", "未暇陳九事，亟歸讀四庫。"]'),
('fd20c57b-5c69-4290-9cf5-cce742df5ede','和徐教授與董元達','謝逸','宋','宋诗','song-poetry','','[]','徐穉卧不起，青衫老柴門。',48,'全唐诗/poet.song.74000.json','["徐穉卧不起，青衫老柴門。", "仲舒著繁露，要明王道尊。", "相逢非竟日，此懷誰與論。", "朗詠鄱陽篇，江南烟雨昏。"]'),
('90519fa3-fcca-4519-8799-a17c28e73056','吳迪吉載酒永安寺會者十一分韵賦詩以字爲韵予用逸字','謝逸','宋','宋诗','song-poetry','','[]','延陵多賢孫，傑然者迪吉。',240,'全唐诗/poet.song.74000.json','["延陵多賢孫，傑然者迪吉。", "上書因自訟，賓客禁私覿。", "瞑目數歸期，閉口防罰直。", "謁告呼朋儕，笑談洗憂慼。", "開樽青蓮界，逍遥以永日。", "翩翩客鼎來，草草筵初秩。", "子珍樂易人，開談見胸臆。", "宗魯與人交，坦然無畛域。", "君澤學古談，論議簡而質。", "伯更廊廟具，綠髮居師席。", "澤民泮水英，每試輒中的。", "叔野飽書史，胸中萬卷積。", "文美秉天機，溫如蒼玉璧。", "文康氣雄豪，目睨天宇窄。", "中邦最清修，操履有繩尺。", "樂之似長康，癡絕故無匹。", "坐客皆奇才，椎鈍莫如逸。", "諸人或見賞，頗愛性真率。", "不求身後名，但喜杯中物。", "世故了不知，一醉吾事畢。"]'),
('385a778c-0798-4395-8d7c-41e8a64a47e0','謝吳迪吉以麻源桃實法製黄精見遺','謝逸','宋','宋诗','song-poetry','','[]','平生剛直心，真率類狂絞。',144,'全唐诗/poet.song.74000.json','["平生剛直心，真率類狂絞。", "居首富兒門，肉食亦不飽。", "北堂老髮垂，喜懼我心攪。", "瘦妻首飛蓬，敢謂美而佼。", "婦姑宵不寐，清餓常至卯。", "幸頼親友人，饋送亦稍稍。", "崔嵬華子岡，秀嶺橫參昴。", "木桃芘菟竹，歲永樛枝撓。", "千年採掇餘，曾近麻姑爪。", "喧喧聲利區，獻酬呈獪狡。", "分甘及衡門，古心君獨拗。", "作詩報嘉惠，質野言非巧。"]'),
('80883f9a-04e6-406e-ba9e-7b6c00b0c5a8','遊逍遥寺以野寺江天豁山扉花木幽爲韵探得山字','謝逸','宋','宋诗','song-poetry','','[]','進不驕富貴，立朝如在山。',132,'全唐诗/poet.song.74000.json','["進不驕富貴，立朝如在山。", "退若羞貧賤，林泉作闠闤。", "喧靜本無相，了在一念間。", "人皆諳此理，何事可作難。", "每月一會面，十客九不閒。", "良時况易失，逝者不復還。", "老境不汝貸，毛髮半已斑。", "游從皆勝事，棲息况禪關。", "茲會若不勉，對客恐厚顔。", "諸人胸曠達，高韵不可攀。", "此意固同曉，作詩勉我頑。"]'),
('5001ca20-33e7-4a40-9021-ea172ee56f71','游文美清曠亭各以字爲韵','謝逸','宋','宋诗','song-poetry','','[]','人生一月間，開口笑幾日。',108,'全唐诗/poet.song.74000.json','["人生一月間，開口笑幾日。", "况復歲云暮，在堂悲蟋蟀。", "胡不爲强歡，唧唧復唧唧。", "吾徒塵外姿，開懷見真率。", "達如商山皓，清若竹林逸。", "相逢各拊掌，一笑萬事失。", "主人清曠士，作堂記其實。", "願無負此堂，不爲勢利怵。", "時時敘離闊，中散志意畢。"]'),
('6ab7b9c4-b3cb-4b89-bda9-1cd64a81bd56','懷李希聲','謝逸','宋','宋诗','song-poetry','','[]','木落野空曠，天迥江湖深。',108,'全唐诗/poet.song.74000.json','["木落野空曠，天迥江湖深。", "登樓眺遐荒，朔風吹壯襟。", "望望不能去，勤我思賢心。", "此心何所思，思我逍遥子。", "掛冠卧秋齋，閱世齊慍喜。", "念昔造其室，微言契名理。", "擊考天玉球，四坐清音起。", "別來越三祀，洋洋猶在耳。", "宵長夢寐勤，月明渡淮水。"]'),
('391343a7-28d3-4050-b210-f13557bcde8c','送臨川教授葉端仁赴闕  其一','謝逸','宋','宋诗','song-poetry','','[]','丸丸松柏林，結根臨古道。',60,'全唐诗/poet.song.74000.json','["丸丸松柏林，結根臨古道。", "未逢匠石徒，歲久空合抱。", "聖人建明堂，良材日登造。", "左右乏先容，地遥安可到。", "願言勵歲寒，不改雪霜操。"]'),
('a4c9b235-f7cd-438d-9d17-4b0ceea5bb93','送臨川教授葉端仁赴闕  其二','謝逸','宋','宋诗','song-poetry','','[]','嘉林有石龜，眎尾知千齡。',60,'全唐诗/poet.song.74000.json','["嘉林有石龜，眎尾知千齡。", "支床氣愈老，巢蓮身始輕。", "鑽灼占休咎，胸中疑惑明。", "納錫藏太卜，决策安朝廷。", "吾徒昧倚伏，禍福何由徵。"]'),
('c0a7e406-a38d-4203-8ad1-3dd41d4b5f0f','同吳迪吉汪信民遊西塔寺分韵賦詩以荷花日落酣爲韵探得荷花字  其一','謝逸','宋','宋诗','song-poetry','','[]','曲肱清夢殘，曉鼓喧鳴鼉。',96,'全唐诗/poet.song.74000.json','["曲肱清夢殘，曉鼓喧鳴鼉。", "披衣步庭除，白露傾圓荷。", "俄聞剝啄聲，佳客來相過。", "爲言城市喧，邀我游山阿。", "步入青蓮界，諸峰鬰嵯峨。", "清香郁軟語，竟日同婆娑。", "吾人嗜好僻，與世殊臼窠。", "茲游慎勿廣，恐爲俗客呵。"]'),
('2e285f7b-aa19-40ca-bec1-9942942c5790','同吳迪吉汪信民遊西塔寺分韵賦詩以荷花日落酣爲韵探得荷花字  其二','謝逸','宋','宋诗','song-poetry','','[]','林間露警鶴，城頭日翻鴉。',84,'全唐诗/poet.song.74000.json','["林間露警鶴，城頭日翻鴉。", "荷香曉逾清，山色秋更佳。", "寺有老比丘，視世如虛花。", "茶香語有味，境靜思無邪。", "夕陽動歸興，天末散餘霞。", "徘徊不忍去，南樓吹曉笳。", "更約秋夜來，小船卧蒹葭。"]'),
('ed693907-9133-4fdb-9b3e-442fb1a1c0c8','游西塔寺分韵得異字','謝逸','宋','宋诗','song-poetry','','[]','天刑不可解，何以補我劓。',120,'全唐诗/poet.song.74000.json','["天刑不可解，何以補我劓。", "同訪老比丘，步至城南寺。", "脫冠飯其腹，咀嚼風雨駛。", "四壁吼怒雷，稍稍衆客睡。", "而余與汪侯，敬諮第一義。", "山僧笑不答，飲食自知味。", "豈無一樽酒，把盞得竟醉。", "不知虛靜中，自有無窮意。", "賦詩非不工，聊以助游戲。", "莫學玉川子，弄筆嘲同異。"]'),
('6fce535c-8525-4e71-bb32-b7cf252ff016','游西塔寺分韵得溪字','謝逸','宋','宋诗','song-poetry','','[]','綠篠蒙修塗，圓荷媚清溪。',96,'全唐诗/poet.song.74000.json','["綠篠蒙修塗，圓荷媚清溪。", "步屧便清風，欻見古招提。", "入門眼界浄，端如刮金篦。", "升堂各趺坐，野語無町畦。", "吾徒性真率，可追阮與嵇。", "安能觸世網，甕底藏醯雞。", "愛此清曠境，不知夕陽西。", "歸騎去聯翩，城頭烏夜啼。"]'),
('ac3be663-bad2-4fb0-8f3c-821e1c88c4d5','與諸友游南湖分韵得紅字','謝逸','宋','宋诗','song-poetry','','[]','不通泮宮籍，端居常屢空。',156,'全唐诗/poet.song.74000.json','["不通泮宮籍，端居常屢空。", "貧知俗益薄，老覺書有功。", "寂無裹飯客，門前翳蒿蓬。", "平生眼底人，粗知吾困窮。", "招呼城南遊，飯我枵腸空。", "亭午得一飽，哦詩和秋蟲。", "捫腹步南湖，緩带披凉風。", "漸見波心蓮，頗憶新妝紅。", "徐酌穆生醴，宛如和露濃。", "三咽不知味，百盞無醉容。", "但可勝茶湯，留餉東坡翁。", "儒生本酸寒，獨處罹百凶。", "不謁魏元君，粗免惡少攻。"]'),
('15971445-039d-4286-ae3d-83d2c78aa727','送鹿好古','謝逸','宋','宋诗','song-poetry','','[]','邑小民事簡，琴樽有餘歡。',96,'全唐诗/poet.song.74000.json','["邑小民事簡，琴樽有餘歡。", "才高氣雖雄，心夷神自閑。", "吐辭如春風，萬象生筆端。", "向識杏壇老，不應嘆才難。", "山近雪雲密，風動梅香寒。", "銅龍曉鼓鳴，畫舸揚漪瀾。", "丈夫重離別，感慨傷朱顔。", "努力事明主，慎勿輕掛冠。"]'),
('84a99d21-2cb1-4c7f-b5ae-dca23c00002a','送李明道','謝逸','宋','宋诗','song-poetry','','[]','我老不聞道，抱疴卧蓬室。',96,'全唐诗/poet.song.74000.json','["我老不聞道，抱疴卧蓬室。", "有客晨叩門，竦若秋山直。", "借問爲誰何，吾祖乃太白。", "傾懷露底藴，始恨晚相得。", "時時出詩語，詞源極湍激。", "格律竟不凡，窺祖見窗壁。", "飄然別我去，此道誰知識。", "世豈乏金龜，恐無賀賓客。"]'),
('40e38fc9-16af-45e1-8091-55e75914ca27','送吳秀才赴辟廱','謝逸','宋','宋诗','song-poetry','','[]','吾家阿連詩，美如青精飯。',84,'全唐诗/poet.song.74000.json','["吾家阿連詩，美如青精飯。", "君嘗從之遊，賸馥潤青簡。", "我老世所憎，百推無一挽。", "君獨頻叩門，問我句中眼。", "此行赴功名，舊習暫鋤鏟。", "霜清山驛寒，酒醒夜聞雁。", "挑燈誦我詩，聊供一笑莞。"]'),
('381f0d18-c2e2-4ef8-bede-0620ed9d3682','金谿董秀彥孚聞竹溪六逸之風而悅之作堂面修竹名之曰逸乞余文表章其義予病不能苦思作五言詩以遺之','謝逸','宋','宋诗','song-poetry','','[]','太白列仙人，名綴雲房籍。',96,'全唐诗/poet.song.74000.json','["太白列仙人，名綴雲房籍。", "天上官長嚴，寧爲世間客。", "醉揖巢父輩，相從竹溪逸。", "朝衫不上船，拜舞墮巾幘。", "氣吞高力士，傲睨天地窄。", "董侯慕斯人，作堂榜其壁。", "流俗嗜聲利，如舐刀上蜜。", "慎勿徇流俗，與侯併爲七。"]'),
('9bc2662c-dfa2-4a3e-b88c-481798a5ed99','和王閑叟見贈兼簡李商老','謝逸','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','綠髮工詞章，白頭困州縣。',72,'全唐诗/poet.song.74000.json','["綠髮工詞章，白頭困州縣。", "老氣吞兒曹，胸中書萬卷。", "遺我盈把珠，璀璨輝組練。", "何時遊匡廬，登堂識君面。", "更邀謫仙人，共醉山間院。", "願君出樊素，可供一笑倩。"]'),
('775bd7fc-3a04-4e53-88a7-4672cf6e09eb','和洪老贈寂大師','謝逸','宋','宋诗','song-poetry','','[]','道人居笑庵，游戲大海寂。',204,'全唐诗/poet.song.74000.json','["道人居笑庵，游戲大海寂。", "鈎深無近用，鏡古有精識。", "運籌不減良，任俠頗如劇。", "未傳東土衣，不通左階籍。", "歸自丹霞山，閉門不浪出。", "室中拂未秉，戶外屨已積。", "非關一念致，要是三昧力。", "疊衾洗鉢外，何以度永日。", "孤坐老此生，恐爲世情測。", "談笑作佛事，豈不勝佔畢。", "垂手試入廛，貪夫願投璧。", "大木倒百圍，山靈不敢惜。", "壯觀佛宇麗，鬼工莫儔匹。", "衆生嗜欲利，如兒舐刀蜜。", "睹此大莊嚴，一瞬萬緣失。", "何時却閉門，養此幻化質。", "老大百不知，面带黄瓜色。"]'),
('9445e598-3e1a-4210-8399-805a06ec28b2','觀蔡規畫山水圖','謝逸','宋','宋诗','song-poetry','','[]','蔡生老江南，山水涵眼界。',72,'全唐诗/poet.song.74000.json','["蔡生老江南，山水涵眼界。", "揮灑若無心，筆端生萬怪。", "樹杪聳烟鬟，雲端懸縞带。", "繫舟枯柳根，茅屋臨清派。", "掃壁掛高堂，肅肅起清籟。", "君名定不朽，第恐縑素敗。"]'),
('1c76fc2a-8aba-4054-aeb4-3e1969769727','題捉玉軒','謝逸','宋','宋诗','song-poetry','','[]','劍池渺人物，孫子劍池傑。',72,'全唐诗/poet.song.74000.json','["劍池渺人物，孫子劍池傑。", "身不滿五尺，胸次極岑絕。", "客來捉玉麈，清談霏鋸屑。", "至道初不煩，彈指萬緣滅。", "端能領此意，麈柄行當折。", "對客了忘言，真成溫伯雪。"]'),
('332b40af-ca21-4d30-be23-a3de700c4f0b','題止蘧軒','謝逸','宋','宋诗','song-poetry','','[]','天籟號萬竅，水石相吐吞。',72,'全唐诗/poet.song.74000.json','["天籟號萬竅，水石相吐吞。", "俛仰一瞬間，羣動了無痕。", "乃知性分內，喧靜本同根。", "君獨詣此理，懷抱清而溫。", "談笑民事辦，庭無鳬鶩喧。", "隠几餞日夕，隙月窺黄昏。"]'),
('2ab65b4e-d692-4667-be46-d3bb6557a1d7','汪文彬載酒率諸人過予溪堂觀芝草以煌煌靈芝一年三秀爲韵探得煌字','謝逸','宋','宋诗','song-poetry','','[]','天瑞必應誠，和氣可致祥。',96,'全唐诗/poet.song.74000.json','["天瑞必應誠，和氣可致祥。", "我如拆襪線，平生無寸長。", "胡爲蓬蓽下，靈芝秀煌煌。", "諸人喜事者，載酒來溪堂。", "環觀三嘆息，作詩助揄揚。", "似聞天道遠，吉凶命靡常。", "在德雖爲瑞，無德恐爲殃。", "願服朋友戒，修德敢怠荒。"]'),
('a5cfa772-e928-4cf8-a242-2f568a9e1b26','敝廬遣興','謝逸','宋','宋诗','song-poetry','','[]','無客且閉門，有興即賦詩。',72,'全唐诗/poet.song.74000.json','["無客且閉門，有興即賦詩。", "盤餐隨厚薄，妻兒同飽饑。", "讀書不求解，識字不必奇。", "拂榻卧清晝，隠几消良時。", "林鶑韵古木，萍魚闖幽池。", "敝廬亦足樂，陶令真吾師。"]'),
('a7df0a8a-3bfc-4483-a9d3-14eef02c1c06','與諸人分韵詠古碑探得羅池廟記以池字爲韵','謝逸','宋','宋诗','song-poetry','','[]','德不蓋當代，名欲萬世垂。',120,'全唐诗/poet.song.74000.json','["德不蓋當代，名欲萬世垂。", "刻石期後人，石與名俱隳。", "子厚名世士，投荒死南夷。", "柳民懷遺愛，作廟臨羅池。", "韓公記其事，沈子書其詞。", "韓詞昭萬古，沈詩妙一時。", "名實兩無愧，後世傳不疑。", "古人共閒燕，翰墨相娛嬉。", "食不設寒具，玩此前賢碑。", "願作集古錄，模楷歐少師。"]'),
('b907ae87-d889-486e-b7f1-879eabca36ca','王立之園亭七咏 頓有亭','謝逸','宋','宋诗','song-poetry','','[]','富貴幻天機，饑寒撼關楗。',108,'全唐诗/poet.song.74000.json','["富貴幻天機，饑寒撼關楗。", "參前橫利害，俗眼青白眩。", "蘇黄兩玉人，落筆傳九縣。", "向來竄遐荒，棄捐若秋扇。", "王侯介如石，乃心不可轉。", "投之古錦囊，不遺俗子翫。", "近來夸奢子，嗜好亦稍變。", "有客來借觀，君無唾其面。", "酌酒對銀鉤，吞聲勿復辯。"]'),
('f86aaee9-44e7-4328-acaa-51736ec09255','王立之園亭七咏 漱醉亭','謝逸','宋','宋诗','song-poetry','','[]','我家北斗南，卜居近山塢。',108,'全唐诗/poet.song.74000.json','["我家北斗南，卜居近山塢。", "浚井得清泉，鑿池不擇土。", "京城井鱗鱗，厥味半甘苦。", "誰知城南園，有泉白如乳。", "門前車馬喧，客醉日亭午。", "呼童轉轆轤，銅瓶掛修組。", "漱齒得甘凉，如風滌煩暑。", "心清談辯駛，舌端灑飛雨。", "但恐醉復醒，君眠客不去。"]'),
('b283950e-f6f3-4dbc-8a22-4e92b807e8e5','王立之園亭七咏 大裘軒','謝逸','宋','宋诗','song-poetry','','[]','小人拙生事，三冬卧無帳。',96,'全唐诗/poet.song.74000.json','["小人拙生事，三冬卧無帳。", "忍寒東窗底，坐待朝曦上。", "徐徐晨光晞，稍稍氣血暢。", "薰然四體和，恍若醉春釀。", "此法秘勿傳，不易車百兩。", "君胡得此法，開軒亦東向。", "蘇公名大裘，意豈在萬丈。", "但觀名軒心，人人如挾纊。"]'),
('9a29a85e-3d7b-4089-9f49-35383b59bbe5','王立之園亭七咏 泠然齋','謝逸','宋','宋诗','song-poetry','','[]','枕簟置一榻，几杖置一筵。',96,'全唐诗/poet.song.74000.json','["枕簟置一榻，几杖置一筵。", "掃空浄如水，洗心學僧禪。", "何必快哉風，襟懷自泠然。", "是身豈無垢，要以道洗湔。", "儻不念清凉，恐爲煩暑纏。", "雖居土囊口，內熱如烹煎。", "我自悟此理，三伏扇可捐。", "定知與列子，相友以忘年。"]'),
('234251ba-9ab3-40d2-8150-f20572c88d5b','王立之園亭七咏 介庵','謝逸','宋','宋诗','song-poetry','','[]','庵居已是介，又以介名庵。',96,'全唐诗/poet.song.74000.json','["庵居已是介，又以介名庵。", "胡爲酷好介，毋乃在律貪。", "人生要當介，君侯恐不堪。", "富貴不相貸，安得坐禪龕。", "客去自無事，客來不妨談。", "但能了諸幻，起卧俱無慚。", "慎勿作住想，如繭縛老蠶。", "興來出庵去，叢林禪可參。"]'),
('2573546e-45a8-4644-a9b4-05e2f3b14ca4','王立之園亭七咏 載酒堂','謝逸','宋','宋诗','song-poetry','','[]','平生揚子雲，識字造奇古。',96,'全唐诗/poet.song.74000.json','["平生揚子雲，識字造奇古。", "時有好事人，載酒問訓詁。", "君乃貴公子，趣向亦如許。", "讀書如雞鳴，勤不亂風雨。", "亦有問字客，携壺就君語。", "君初不作難，應答了無忤。", "戶外屨如雲，作堂蔽寒暑。", "林甫端能來，勿與談杕杜。"]'),
('22f0df63-240b-4240-b664-7fd54bc6fc70','王立之園亭七咏 永日亭','謝逸','宋','宋诗','song-poetry','','[]','靜坐寂無事，一日似兩日。',96,'全唐诗/poet.song.74000.json','["靜坐寂無事，一日似兩日。", "聞之東坡公，此語妙無匹。", "晨漱夕曲肱，百年過如擲。", "投身聲利場，更覺居諸疾。", "而君定何人，能使羲輪軼。", "雖無揮日戈，自得魯陽術。", "但見弦望移，了不記甲乙。", "優游聊卒歲，何必日鼓瑟。"]'),
('8ef12e6c-5e4c-4b8b-b151-4b6257b9b416','月中觀梅花懷月上人','謝逸','宋','宋诗','song-poetry','','[]','梅清不受塵，月浄本無垢。',120,'全唐诗/poet.song.74000.json','["梅清不受塵，月浄本無垢。", "微風更解事，排遣香入牖。", "倏思阿明語，清與此花偶。", "天資已超軼，况得善師友。", "洞然胸明白，欲掃不容帚。", "客來相視笑，不知語出口。", "平生憎俗人，未語輒先嘔。", "不逢屈突生，寧食艾三斗。", "乃知我輩中，如師亦稀有。", "但想月中梅，作詩清如晝。"]'),
('72a7a000-7efd-4042-b029-f2eca8b1f345','贈權師','謝逸','宋','宋诗','song-poetry','','[]','權師純孝人，精誠動坤軸。',108,'全唐诗/poet.song.74000.json','["權師純孝人，精誠動坤軸。", "廬墓冽寒泉，色照師眼綠。", "守此不動心，種彼無瑕玉。", "湛浄涵一德，清凉壓三伏。", "漱齒回餘甘，烹茶發新馥。", "浣衣頮面餘，灌溉蔬畦足。", "他年功用成，虹氣森巖谷。", "何時懷璧來，不必藏韞匵。", "摩挲壞衲中，出示老尊宿。"]'),
('e84efd03-bad9-490c-ba15-ccdf0ddf7e3a','夏夜雜興  其一','謝逸','宋','宋诗','song-poetry','','[]','飛飛空中螢，曄曄揚其光。',48,'全唐诗/poet.song.74000.json','["飛飛空中螢，曄曄揚其光。", "假此寸草資，乘陰爭煒煌。", "膠膠雞既鳴，杲杲升扶桑。", "神奇復臭腐，爾生何可長。"]'),
('a242b675-8ab6-47b2-9b7b-b80834858754','夏夜雜興  其二','謝逸','宋','宋诗','song-poetry','','[]','零露棲圓荷，月明清灑灑。',48,'全唐诗/poet.song.74000.json','["零露棲圓荷，月明清灑灑。", "旋轉如走丸，細碎不盈把。", "勁風度橫塘，珠璣畢傾瀉。", "胡不被蓼蕭，徽音播詩雅。"]'),
('e8b39091-fe9a-437c-a760-f3525aca7120','夏夜雜興  其三','謝逸','宋','宋诗','song-poetry','','[]','蚯蚓本微蟲，託生在泥滓。',48,'全唐诗/poet.song.74000.json','["蚯蚓本微蟲，託生在泥滓。", "飲泉食槁壤，既飽鳴自恣。", "軀小無他腸，氣盡聲乃止。", "雖無招憂累，奈何聒吾耳。"]'),
('b051eca5-9044-49fc-85d5-946222848432','夏夜雜興  其四','謝逸','宋','宋诗','song-poetry','','[]','青青棘籬蔓，碧色侵琅玕。',48,'全唐诗/poet.song.74000.json','["青青棘籬蔓，碧色侵琅玕。", "嶷嶷枝葉茂，縈紆矛戟間。", "風露豈不佳，弱質危難安。", "願言依松柏，永與同歲寒。"]'),
('ae6f2b9f-3485-4b20-b971-7b0186d26d83','夏夜雜興  其五','謝逸','宋','宋诗','song-poetry','','[]','飛蚊鼓翅鳴，薨薨喧室中。',48,'全唐诗/poet.song.74000.json','["飛蚊鼓翅鳴，薨薨喧室中。", "敢憎聲似雷，實憚喙如鋒。", "飲血雖可飽，噬膚竟何功。", "得時不足貴，少皞行西風。"]'),
('b46fb835-d84c-4c17-a8d0-d87faf204cb1','夏夜雜興  其六','謝逸','宋','宋诗','song-poetry','','[]','翳翳庭中草，瑣細不可名。',48,'全唐诗/poet.song.74000.json','["翳翳庭中草，瑣細不可名。", "風來徒自偃，雨過胡爲青。", "芟夷去根本，勿使復滋榮。", "竟無補世事，區區何所生。"]'),
('81890360-5641-4abb-95ba-d267026ae513','夏夜雜興  其七','謝逸','宋','宋诗','song-poetry','','[]','燕燕巢梁端，飄摇畏風雨。',48,'全唐诗/poet.song.74000.json','["燕燕巢梁端，飄摇畏風雨。", "永夜不得眠，啾啾子求哺。", "秋風毛羽成，分飛不相顧。", "慎勿毀其室，此室安且固。"]'),
('482cee31-a4d0-48b6-83a7-50e1cfd8332b','夏夜雜興  其八','謝逸','宋','宋诗','song-poetry','','[]','窗前兩梧桐，清陰覆東牆。',48,'全唐诗/poet.song.74000.json','["窗前兩梧桐，清陰覆東牆。", "孫枝絡珊瑚，圭葉裁琳瑯。", "良材中琴瑟，幽棲期鳳凰。", "願先海岱貢，移根栽嶧陽。"]'),
('40595d22-0d33-405a-b012-f505bdf825e5','夏夜雜興  其九','謝逸','宋','宋诗','song-poetry','','[]','姮娥駕望舒，餘光粲天步。',48,'全唐诗/poet.song.74000.json','["姮娥駕望舒，餘光粲天步。", "飛廉鼓清籟，蕭蕭響庭戶。", "身欲從之游，悵望不能去。", "哦詩廣九辯，庶幾托風賦。"]'),
('686b79f4-5fff-483f-bf36-d55e043bec47','送曾伯長','謝逸','宋','宋诗','song-poetry','','[]','曾侯江南英，文章有家法。',84,'全唐诗/poet.song.74000.json','["曾侯江南英，文章有家法。", "堅壁仁義塗，勢若太山壓。", "跫然過我語，如熱得清箑。", "爲言行赴官，扁舟泛苕霅。", "炙手公卿門，眼底端不乏。", "吾人倘聞道，執圭同荷鍤。", "謂予言不信，捧盤與君歃。"]'),
('61113b98-cd8c-4c01-b681-a22e008b973f','送汪叔野  其一','謝逸','宋','宋诗','song-poetry','','[]','汪子軀幹小，勁氣橫秋霜。',96,'全唐诗/poet.song.74000.json','["汪子軀幹小，勁氣橫秋霜。", "纍纍諸儒中，軒然無老蒼。", "平生讀書功，短檠照夜窗。", "相從近兩年，覺我舊學荒。", "爲言將遠適，隨兄泛瀟湘。", "欲濯塵土心，胸懷吞九江。", "願言勉此志，無爲憂患傷。", "待得秋雁飛，寄書來草堂。"]'),
('a3586691-c320-4eeb-91bd-f6b373f922a7','送汪叔野  其二','謝逸','宋','宋诗','song-poetry','','[]','兩汪皆於菟，季也何其怒。',84,'全唐诗/poet.song.74000.json','["兩汪皆於菟，季也何其怒。", "三年屏鮮腴，藜藿未嘗飫。", "鐵心不可拗，出語等刀鋸。", "貪夫既激昂，壯士亦驚顧。", "落筆波濤翻，可接乃兄武。", "科名蓋餘事，文章徒媚嫵。", "欲築平生基，更師黄叔度。"]'),
('8f9a7039-96f6-4f17-8541-26d6ff4f9cf6','哭陳居士','謝逸','宋','宋诗','song-poetry','','[]','國欲求忠臣，忠臣乃孝子。',84,'全唐诗/poet.song.74000.json','["國欲求忠臣，忠臣乃孝子。", "爲臣若不忠，泉下顙有泚。", "居士邱園英，參禪得佛髓。", "家有兩男兒，孝秀冠閭里。", "大兒守名教，小兒飽書史。", "頎然諸子孫，眉目皆可喜。", "人言居士亡，居士實不死。"]'),
('f803f460-dd1e-4758-8938-f57d542d12ba','翻經臺','謝逸','宋','宋诗','song-poetry','','[]','吾祖牧臨汝，滯訟清公庭。',108,'全唐诗/poet.song.74000.json','["吾祖牧臨汝，滯訟清公庭。", "胥吏退雁鶩，疏簾挂寒廳。", "鼓角喚幽夢，草色池塘青。", "雙旌引五馬，駕言出郊坰。", "足躡雲端屐，手展貝葉經。", "稅駕妙高臺，几硯陳軒櫺。", "朱墨紛在眼，梵宇森如星。", "臺傾人已寂，聲名藹餘馨。", "想公忘言處，角挂山中羚。"]'),
('59de8dfb-5a59-4929-a63d-c10c1e34d4c4','三益齋詩','謝逸','宋','宋诗','song-poetry','','[]','元龍湖海豪，蓋代聲籍籍。',120,'全唐诗/poet.song.74000.json','["元龍湖海豪，蓋代聲籍籍。", "只今觀耳孫，才皆萬夫敵。", "叔兮美無度，伯也古遺直。", "當年種玉翁，什襲裹雙璧。", "期公垂天雲，佐郡試戢翼。", "尚開柴桑徑，引領望三益。", "嘗聞築燕臺，千里走樂劇。", "市骨捐千金，廐乘盡虎脊。", "公乃真好事，屣履見逢掖。", "定知子輿輩，一笑皆莫逆。"]'),
('e1a266d8-2b9b-4688-be18-8ff26c85f35d','游西塔寺分韵賦詩懷汪信民以淵明停雲詩豈無他人念子實多爲韵探得念字','謝逸','宋','宋诗','song-poetry','','[]','昨夜山頭月，照我盃瀲灧。',240,'全唐诗/poet.song.74000.json','["昨夜山頭月，照我盃瀲灧。", "今朝雲外山，寸碧若新染。", "人境兩清絕，座客只君欠。", "俗子百無用，勝士一可念。", "君如苕溪女，不粧有幽艷。", "又如白墮醪，雖久味愈釅。", "雄文山有雲，高論圭無玷。", "胸懷極坦夷，了不限城塹。", "胡不侍明光，峨冠佩長劍。", "甯甘廣文冷，青燈對鉛槧。", "何當襥被歸，莫待孟光窆。", "放杖先生席，罷趨邦君坫。", "晚行蟬噪山，曉起雞號店。", "到家先過我，信若符節驗。", "門前馬未嘶，屋上烏可占。", "呼兒拂几席，喚婦熨襦襜。", "欲具韓子餐，恐乏魚菜贍。", "但當蒸瓠壺，莫笑盧公儉。", "老氣得酒豪，灰寒尚復焰。", "虛心叩至道，膏肓待君砭。"]'),
('ba4e99e7-3db8-4b51-b268-5d1c5cb8afc0','游西塔寺分韵詠雙蓮以太華峰頭玉井蓮爲韵探得華字','謝逸','宋','宋诗','song-poetry','','[]','元君始雲翔，華姑繼羽化。',144,'全唐诗/poet.song.74000.json','["元君始雲翔，華姑繼羽化。", "獨留曾與黎，高風配崧華。", "不隨二女嬪，豈羨兩喬嫁。", "尚餘脂澤念，多生緣未謝。", "化爲芬利陀，耦立遠公社。", "翠趺分雙歧，並萼肩相亞。", "挹袖薰風晨，携手凉月夜。", "交枝艷散霞，同氣香飄麝。", "疏影競清妍，幽姿鬭閒暇。", "何時各零落，秋高霜露下。", "洗妝見冰肌，乘雲返姑射。", "此論傳者誰，黄鵠爲予話。"]'),
('8af4e3a8-0b5e-4505-ab8a-f9d419c4d850','遊西塔寺探得王夷甫玉柄麈尾以柄字爲韵','謝逸','宋','宋诗','song-poetry','','[]','甯馨捉麈手，玉色相輝映。',120,'全唐诗/poet.song.74000.json','["甯馨捉麈手，玉色相輝映。", "携持賓滿堂，韵與談俱勝。", "溫潤德堪比，鮮潔面可鏡。", "扣几聲逾清，指月色彌瑩。", "名壓范增斗，價重齊侯磬。", "晉朝妙人物，此公名最盛。", "風流固足賞，不救當時病。", "雖云王謝許，我老獨不稱。", "肉緩形頗穢，語拙存直性。", "但慕杜陵翁，長鑱白木柄。"]'),
('a595b7ad-2a70-4dcf-a696-fcd1927300ad','擬峴臺  其一','謝逸','宋','宋诗','song-poetry','','[]','耿耿抱孤韵，寂寂扃柴扉。',132,'全唐诗/poet.song.74000.json','["耿耿抱孤韵，寂寂扃柴扉。", "束書卧環堵，交遊車馬稀。", "風流佳公子，妙齡秉天機。", "邀予步層臺，目送孤鴻飛。", "山影漾清渚，翠色侵人衣。", "漁浦晚烟暝，霽雰蒙夕暉。", "靜言思叔子，悵然澹忘歸。", "坐有庖丁手，奏刀心術微。", "萬象含毫端，縑素聊一揮。", "古來勝達士，欻如朝露晞。", "吾人各勉力，毋爲鄒湛譏。"]'),
('913780a4-0ca5-4df1-a6c1-539c62f9fa8c','擬峴臺  其二','謝逸','宋','宋诗','song-poetry','','[]','取友遍四海，江夏真無雙。',108,'全唐诗/poet.song.74000.json','["取友遍四海，江夏真無雙。", "憐我守幽獨，閉門卧北窗。", "折簡呼勝士，炊黍羞羊腔。", "相邀出蓬蓽，登高臨大江。", "江山擬峴首，清絕冠此邦。", "豈惟慕叔子，耆舊皆敦龐。", "蟄龍卧諸葛，雛鳳伏老龐。", "寂寞千載後，斯人可心降。", "願言各努力，勿立憍慢幢。"]'),
('a4b7e30d-2598-468a-a8c6-f34615b43eee','端溪硯','謝逸','宋','宋诗','song-poetry','','[]','琢雕山骨奇，磨礲發光炯。',60,'全唐诗/poet.song.74000.json','["琢雕山骨奇，磨礲發光炯。", "體潤雲氣生，寒泉洌幽井。", "平生心腹交，陳玄及毛穎。", "德重不傾側，中虛且淵靜。", "置之棐几間，吾身日三省。"]'),
('127fa640-7554-4be2-8b4d-f78e301c700c','吳子珍家分韵詠席上果探得橘子以橘字爲韵','謝逸','宋','宋诗','song-poetry','','[]','巴邛清霜後，獨餘兩大橘。',48,'全唐诗/poet.song.74000.json','["巴邛清霜後，獨餘兩大橘。", "一朝剖而食，四老欣然出。", "乃知避世士，退藏務深密。", "吾邦富此果，味不數萍實。"]'),
('f735c1e9-47ad-47a1-8292-4b502f9918bf','寄洪駒父戲傚其體','謝逸','宋','宋诗','song-poetry','','[]','令尹吳楚豪，奇胸開八窗。',96,'全唐诗/poet.song.74000.json','["令尹吳楚豪，奇胸開八窗。", "人物秀春柳，詩句妙澄江。", "築室名壁陰，鑿牖延朱光。", "呻吟六藝學，心醉倚胡床。", "毛錐摘秋穎，繭紙截水蒼。", "渾洒有能事，著勳翰墨場。", "翼翼魯泮宮，國士徵無雙。", "行且職教事，儒風成一邦。"]'),
('c7813203-7cb6-42ae-a181-70a043bc82c5','寄徐師川戲效其體','謝逸','宋','宋诗','song-poetry','','[]','不見徐侯久，夢繞西山陽。',96,'全唐诗/poet.song.74000.json','["不見徐侯久，夢繞西山陽。", "斯人天下士，秀拔無等雙。", "捉麈望青天，意氣吞八荒。", "平生學古功，胸次羅典章。", "商略造理窟，清論排風霜。", "弄筆有佳思，哦詩懷漫郎。", "恐非江湖客，黑頭侍明光。", "不忘溫處士，羣書亦可將。"]'),
('acb8f814-c389-4071-bf3b-1481ed13fda6','懷呂聘君','謝逸','宋','宋诗','song-poetry','','[]','彼美邱園秀，風韵何洒落。',156,'全唐诗/poet.song.74000.json','["彼美邱園秀，風韵何洒落。", "考槃盱水湄，貧賤不隕穫。", "冰椀薦溪毛，縞衣佩蘭若。", "和嶠松森森，王恭柳濯濯。", "文采南山豹，野逸青田鶴。", "獨振大雅音，黄鐘在牛鐸。", "綠蘿結春陰，修篁解夏籜。", "登山挹飛溜，自得仁智樂。", "頼有好事人，携酒慰寂寞。", "王路今坦夷，胡爲束高閣。", "堆盤爛生光，纍纍照巾羃。", "香霧欲噀人，未食先流液。", "何當見四老，授我隠居術。"]'),
('53671f3f-2dcf-4d1b-92d8-938cc204e830','傷徐文學','謝逸','宋','宋诗','song-poetry','','[]','鶢鶋止魯郊，豈樂太牢具。',108,'全唐诗/poet.song.74000.json','["鶢鶋止魯郊，豈樂太牢具。", "冥冥萬里鴻，弋人何敢慕。", "東海儒林秀，落筆妙詞賦。", "蹭蹬江湖秋，低徊老韋布。", "晚從使者舉，奉檄喜而懼。", "白髮照青衫，奄忽死中路。", "功名安在哉，竟以儒冠誤。", "去就各有時，壽夭亦無據。", "竚立倚江樓，注目烟村暮。"]'),
('c6f3d0c8-c52f-4fb8-9edf-cd826c96545d','懷汪信民','謝逸','宋','宋诗','song-poetry','','[]','長沙隔重湖，蒼莽無四壁。',108,'全唐诗/poet.song.74000.json','["長沙隔重湖，蒼莽無四壁。", "騷魂駕鬼車，月黑陰火赤。", "念彼泮宮老，官居寄禪寂。", "雖綰參軍綬，尚带山林色。", "蕭然列仙癯，粹氣潤圭璧。", "坐見屈在牆，作詩弔沈溺。", "鄙夫不解事，勇退如六鷁。", "安得快哉風，吹我垂天翼。", "不假蜚霞佩，置身在君側。"]'),
('e5124a11-d666-4893-9425-6d5a763298da','懷汪信民村居','謝逸','宋','宋诗','song-poetry','','[]','金風吐商管，秀色浮山椒。',72,'全唐诗/poet.song.74000.json','["金風吐商管，秀色浮山椒。", "苔乾石骨瘦，水落溪毛凋。", "埃塵暗箯輿，風霜緇客貂。", "藜羹浥野飯，松醪酌村瓢。", "會當對榻語，竹塢風蕭蕭。", "浣腸去舊學，詞源湧春潮。"]'),
('66667dff-0d21-4b36-bb18-a976c33ab172','送胡民望入京','謝逸','宋','宋诗','song-poetry','','[]','龜以氣而壽，龍以仁而靈。',60,'全唐诗/poet.song.74000.json','["龜以氣而壽，龍以仁而靈。", "蛇以無足行，蚓以無腸鳴。", "大哉天地間，百怪不可名。", "洋洋西津水，念子行西征。", "與道如有聞，雁來當寄聲。"]'),
('576aac4a-2154-4ed7-9359-0a9f974be4eb','寄洪龜父戲效其體  其一','謝逸','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','落落匡山老，晴江瑩眉宇。',84,'全唐诗/poet.song.74000.json','["落落匡山老，晴江瑩眉宇。", "問道崆峒墟，枯槎泛江滸。", "歸歟謝遠游，曲肱卧環堵。", "磅礴萬物表，動植見吞吐。", "曜靈旋磨蟻，四氣遽如許。", "咄咄千載事，俯仰變今古。", "安得仙人杖，頹齡爲君拄。"]'),
('243a3aec-2add-40bd-adaf-6112ea73cacc','寄洪龜父戲效其體  其二','謝逸','宋','宋诗','song-poetry','','[]','幡然起東皋，曳裾入西洛。',60,'全唐诗/poet.song.74000.json','["幡然起東皋，曳裾入西洛。", "且捧毛義檄，莫躡虞卿屩。", "智囊發新縢，經笥啟塵鑰。", "治國端有計，何惜萬金藥。", "回睨黄公壚，夐爾河山邈。"]'),
('fae3277e-6bb7-4bb3-9c48-9d16ff8da638','八月十五夜與諸友游南湖玩月','謝逸','宋','宋诗','song-poetry','','[]','黄昏出東門，月在房心間。',108,'全唐诗/poet.song.74000.json','["黄昏出東門，月在房心間。", "步繞古柳隄，疏影迷清灣。", "趺坐湖上亭，物肅景自閑。", "桂影摇濁醪，波光照酡顔。", "高懷浩無際，妙語險莫攀。", "夜深風露冷，投宿敲禪關。", "時聞橋下泉，决决鳴珮環。", "茲游尋舊約，正朔已七頒。", "緬想泮宮老，邈在淮南山。"]'),
('7707a630-0c5f-47af-8b8d-d0f9381cb3ca','中秋與二三子賞月分韵得中字','謝逸','宋','宋诗','song-poetry','','[]','雨洗天宇凈，微雲捲凉風。',84,'全唐诗/poet.song.74000.json','["雨洗天宇凈，微雲捲凉風。", "今夕定何夕，月圓秋氣中。", "驚雁掠沙水，寒鴉繞梧桐。", "嘉我二三子，笑語春冰融。", "酒酣吐秀句，醉筆翩征鴻。", "夜闌燈光亂，清影棲房櫳。", "似聞霓裳曲，笛聲吟老龍。"]'),
('0450357c-c515-48c3-82ce-a00939e4489c','游西塔寺分韵得處字','謝逸','宋','宋诗','song-poetry','','[]','西風脫木葉，感時煎百慮。',132,'全唐诗/poet.song.74000.json','["西風脫木葉，感時煎百慮。", "癡坐北窗底，哦詩不能句。", "同舍二三子，邀我城南去。", "風於湖上亭，臨流坐箕踞。", "菡萏晚紅垂，冷香襲巾屨。", "湖西青蓮界，竹陰有微路。", "老僧迎我笑，洗鉢供匕箸。", "齋厨野飯香，園蔬摘朝露。", "清言洗心胸，幸免杯酒汙。", "人生會合難，駛若風中霧。", "明晨想茲游，凄凉在何處。"]'),
('b551f1fd-76d3-49b3-b152-457c211fcaf5','懷季智伯以洪龜父贈智伯詩氣蓋關中季子心爲韵探得蓋字','謝逸','宋','宋诗','song-poetry','','[]','初聞季子賢，詞源漲萬派。',84,'全唐诗/poet.song.74000.json','["初聞季子賢，詞源漲萬派。", "未倒蔡邕屣，先傾程本蓋。", "自從得斯人，議論頗宏大。", "邇來卧苫塊，病骨劇疲瘵。", "茲游獨不預，頗覺氣宇隘。", "平生憎俗物，每見意即敗。", "後會君强起，免食三年艾。"]'),
('1d253efc-ceda-472d-ba1c-30bf690a29a5','集西塔寺懷亡友汪信民以言念君子溫其如玉爲韵探得念字','謝逸','宋','宋诗','song-poetry','','[]','禍福初無門，吉凶本不僭。',192,'全唐诗/poet.song.74000.json','["禍福初無門，吉凶本不僭。", "跖壽顔夭折，此理竟誰驗。", "貴不嗇讒邪，富獨饒聚斂。", "施施驕妻妾，百索無一欠。", "貞士抱清真，藜藿常不饜。", "人生鬼揶揄，奄忽就窀窆。", "吾友汪夫子，才力百夫贍。", "獨立流俗中，如山不可塹。", "青衫困冷官，半世守寒儉。", "自從斯人亡，吾生良可厭。", "弦絕伯牙琴，墓挂徐卿劍。", "但餘清溪編，萬丈垂光焰。", "朝來雨新霽，湖波清瀲灧。", "禪堂凈巾屨，僧榻凉枕簟。", "追尋舊遊蹤，歷歷皆可念。", "矢詩寓一哀，苦淚漬鉛槧。"]'),
('31925f80-7394-4d47-a091-2e84111765cb','和陳倅宜黄書事','謝逸','宋','宋诗','song-poetry','','[]','鄙夫拙生事，日晚兒號冬。',120,'全唐诗/poet.song.74000.json','["鄙夫拙生事，日晚兒號冬。", "白駒穿甕牖，曲肱起猶慵。", "懶惰百無營，有酒時復中。", "孰知廊廟具，征驂犯寒風。", "行役豈不苦，王事不我容。", "勞佚雖有命，造物似不公。", "仰羨沖天鶴，孤飛邈難從。", "頼有雲外山，所至如迎逢。", "是中有深意，高懷可默通。", "何當浮大白，一醉百念空。"]'),
('9080f7e5-6c30-4406-b7f6-3c63a18e40a2','冬至日陳倅席上分賦一陽來復探得復字','謝逸','宋','宋诗','song-poetry','','[]','陽進君子升，陰退小人伏。',84,'全唐诗/poet.song.74000.json','["陽進君子升，陰退小人伏。", "此理洞然明，不疑更何卜。", "微和回根荄，餘光借草木。", "但看堂前梅，南枝已芬馥。", "東齋况虛明，樽有荔枝綠。", "燈花不予欺，玉蟲間金粟。", "吾道行將伸，斯言可三復。"]'),
('1ece3e3d-f99b-40cb-9d82-bacd4e9337d1','嘲潘邠老未娶','謝逸','宋','宋诗','song-poetry','','[]','潘侯平生心，初不喜婚宦。',168,'全唐诗/poet.song.74000.json','["潘侯平生心，初不喜婚宦。", "中年又喪妻，二子尚幼丱。", "孤燈秋夢寒，頗思美目盼。", "初時似不堪，既久亦習慣。", "斯人天機深，堅壁却憂患。", "濁醪只獨斟，布衣誰補綻。", "豈不溉釜鬵，無人煮藜莧。", "買婢供使令，頗遭俗子訕。", "北風吹枯桑，天寒歲云晏。", "人生不百年，一世如夢幻。", "勿謂淵泉深，巨魚亦可汕。", "何當呼蹇修，便可買羔雁。", "中饋端有人，嫁娶豈難辦。", "爲君乞樊素，伴我老山澗。"]'),
('4604b318-fed0-4288-8f59-34075a0fef37','陳倅席上分韵得我字','謝逸','宋','宋诗','song-poetry','','[]','竹林牆外梢，梅蘂簷前朵。',96,'全唐诗/poet.song.74000.json','["竹林牆外梢，梅蘂簷前朵。", "萬籟寂無聲，夜闌耿燈火。", "通守塵外姿，體道忘人我。", "邀客文字飲，麈風清四座。", "酒酣誦新詩，老氣激衰惰。", "公詩如天驥，逸韵謝韁鎖。", "小人窘駑足，十步常九跛。", "願公勤鞭策，他年逢飯顆。"]'),
('adee0747-7932-48bf-b3de-ddd6ee2c46a5','夜過朱仲觀飲明日雪作','謝逸','宋','宋诗','song-poetry','','[]','夜飲錦瑟傍，歌吹盈耳根。',180,'全唐诗/poet.song.74000.json','["夜飲錦瑟傍，歌吹盈耳根。", "歸聞窗外竹，摵摵風葉喧。", "夢覺室生白，曉起欲填門。", "平地委璀璨，虛亭舞翩翻。", "洒樹輕復揚，觸幔急且掀。", "望遠恐連雲，積厚疑壓坤。", "光動浮屋椽，影亂紛池盆。", "散漫迷大江，依稀認前村。", "雀噤咮自束，鴉濕翅不鶱。", "把玩手欲龜，咀嚼舌必捫。", "風黨怒未解，火媒寒不溫。", "簷有冰柱懸，門無屐齒痕。", "遊倦不訪戴，愁多惟卧袁。", "何時天宇霽，炙背負晴暄。", "王門若可擬，持以獻至尊。"]'),
('d10e00d0-279f-4ceb-936a-40d8d01ace27','廣壽寺','謝逸','宋','宋诗','song-poetry','','[]','學道護心城，養生戒眉斧。',84,'全唐诗/poet.song.74000.json','["學道護心城，養生戒眉斧。", "靜知世味薄，老愜野僧語。", "散步給孤園，邀我會心侶。", "塵清不瞇眼，境靜可冰暑。", "蓮社宗遠公，竹溪仰巢父。", "此道不異世，今人豈媿古。", "當念貧時交，重勿棄如土。"]'),
('2e0d9df1-7814-4983-9053-9df003233688','龍沙詞五疊贈清逸先生','謝逸','宋','宋诗','song-poetry','','[]','雁雲蜚兮鯉沉，高者可弋兮下可罾。',193,'全唐诗/poet.song.74000.json','["雁雲蜚兮鯉沉，高者可弋兮下可罾。", "龍沙之上足以忘機兮，于以觀魚鳥之情。", "修眉浮空兮，鑒寒瀨之澄凝，茹紫芝兮濯纓。", "逍遥乎龍沙之上兮，可樂者山水之情。", "草芊芊兮垂柳陰陰，黄落兮霜寒露零。", "龍沙之上足以忘懷兮，于以觀草木之情。", "秋風兮月明，吹我衣裳兮照吾曲肱。", "逍遥乎龍沙之上兮，可樂者風月之情。", "百夫逐鹿兮，失得之營心。", "有鹿兮雖竭蹷其何悲。", "向知鹿不吾得兮，曾不如其已。", "不吾得則已兮，又何有于龍沙之君子也。"]'),
('a4e875d6-6d38-4d22-98a5-d1f4ee115fa8','寄題高彥應長官碧鮮閣','謝逸','宋','宋诗','song-poetry','','[]','先生手種千竿竹，儼如壯士衣冠肅。',96,'全唐诗/poet.song.74000.json','["先生手種千竿竹，儼如壯士衣冠肅。", "林端結閣挹清風，閣上幽人峙雙玉。", "春風飛盡玄都花，秋霜半落平泉木。", "試傍池邊訪此君，雪虐風饕不改綠。", "我有惠施書五車，不解子山愁萬斛。", "何時一醉藉清影，更邀明月同君宿。"]'),
('94123b48-9ab4-44a5-9f19-cc85f5483962','汪信民頃赴符離約謁告還家爲盛集戲作詩嘲之以助一笑仍率諸友同賦','謝逸','宋','宋诗','song-poetry','','[]','君如霜鶻精爽老，目睨雲霄長側腦。',208,'全唐诗/poet.song.74000.json','["君如霜鶻精爽老，目睨雲霄長側腦。", "不種河陽滿縣花，手披泮水收芹藻。", "閉門較藝防請謁，門外賓朋跡如掃。", "饑腸得酒吼怒雷，牙頰生烟喉吻燥。", "青燈枕上夢蛾眉，驚魄酷怕寒砧擣。", "縱未休糧仙骨輕，丹田亦合生梨棗。", "歸來清狂尚未減，懷抱向人輒傾倒。", "不作孟公投轄飲，乃欲悲吟效郊島。", "明年東風破柳條，萬里晴江波浩浩。", "此時扁舟挽不留，依舊儒官守枯槁。", "只今有酒不浪飲，迎臘寒梅爲誰好。", "相將風雪不饒人，拂面飛花故相惱。", "期君三日不如盟，定作回波嘲栲栳。"]'),
('77d5c2fe-955b-4209-ac54-589d2fe76a00','訪吳子珍新居','謝逸','宋','宋诗','song-poetry','','[]','歲晚窮愁催急晷，吾人學道心如水。',96,'全唐诗/poet.song.74000.json','["歲晚窮愁催急晷，吾人學道心如水。", "共訪延陵季子孫，呼兒酌酒烹雙鯉。", "新有揚雄宅一區，舊聞孟母鄰三徙。", "卜居清曠慕長統，近市喧囂慚晏子。", "但得門容長者車，何須聲有尚書履。", "他年羔雁列君庭，吉士恐爲君子使。"]'),
('54d74a93-070b-4ab6-ba7a-6d4aec9bbb0d','送子侃禪師','謝逸','宋','宋诗','song-poetry','','[]','薛老峰前古游俠，脫冠賣劍翦鬚鬣。',112,'全唐诗/poet.song.74000.json','["薛老峰前古游俠，脫冠賣劍翦鬚鬣。", "閉關孤坐百念空，面上老色如秋葉。", "飄然飛錫華子岡，浪逐西風移步屧。", "攝衣升堂搥大鼓，是中不賞嗇夫喋。", "四衆圍繞如堵牆，要觀霹靂飛牙頰。", "人生一夢幾時覺，相逢栩栩皆蝴蝶。", "何當蠟屐從師遊，遮莫馮驩老彈鋏。"]'),
('b0afeed5-410b-4e6f-ae6d-aa0cf1e99a03','丈軒詩','謝逸','宋','宋诗','song-poetry','','[]','謫仙獨立風埃外，函丈席間藏法界。',64,'全唐诗/poet.song.74000.json','["謫仙獨立風埃外，函丈席間藏法界。", "食前不愧孟子譏，容膝尚笑陶生隘。", "若知北斗可藏身，定是須彌堪納芥。", "不容廣坐九百萬，誰信維摩室本大。"]'),
('e1b7ced6-3bf8-4ff7-bb5c-999e52cb62c1','游寶應寺分詠古蹟探得顔魯公戒壇碑以壇字爲韵','謝逸','宋','宋诗','song-poetry','','[]','魯公虹氣胸中蟠，發爲心畫妙筆端。',144,'全唐诗/poet.song.74000.json','["魯公虹氣胸中蟠，發爲心畫妙筆端。", "嚴如禮樂陳太廟，肅若朝會羅千官。", "想見誚杞叱希烈，不憂米罄無晨餐。", "曩憑熊軾守此土，浮屠受戒陞高壇。", "手磨蒼珉紀歲月，大書深刻期不刓。", "至今父老見必拜，尚餘墮淚碑斕斑。", "爭摹墨本走四海，購求不惜千金殫。", "挂之虛堂拂塵壁，凜然六月陰風寒。", "豈惟賊臣斂衽避，厲鬼不得神其姦。"]'),
('79acc66a-71b3-4a06-9a21-478e444aa0e1','送董元達','謝逸','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u79bb\u522b", "\u65f7\u8fbe", "\u529d\u6170"]','讀書不作儒生酸，躍馬西入金城關。',96,'全唐诗/poet.song.74000.json','["讀書不作儒生酸，躍馬西入金城關。", "塞垣苦寒風氣惡，歸來面皺鬚眉斑。", "先皇召見延和殿，議論慷慨天開顔。", "謗書盈篋不復辯，脫身來看江南山。", "長江滾滾蛟龍怒，扁舟此去何當還。", "大梁城裏定相見，玉川破屋應數間。"]'),
('f41fd3d7-1d6e-461c-8510-e015e3a1718d','寄題黄文昌觴詠亭','謝逸','宋','宋诗','song-poetry','','[]','門前五柳陶淵明，歸卧柴桑呼不醒。',104,'全唐诗/poet.song.74000.json','["門前五柳陶淵明，歸卧柴桑呼不醒。", "錦官城西杜少陵，醉挹浣花溪水橫。", "几杖顛倒盃盤傾，似聞殷殷金石聲。", "乃知達士未忘情，一觴一詠有餘清。", "銀盃落手新詩成，仰視寥廓鴻冥冥。", "富貴于我浮雲輕，興來慎勿騎長鯨。", "人言唯君可卿卿。"]'),
('6256ba8b-6ce6-4612-9c86-bf8943afaa2e','送姜和父','謝逸','宋','宋诗','song-poetry','','[]','掠眼年光洒飛雹，三載從游只如昨。',128,'全唐诗/poet.song.74000.json','["掠眼年光洒飛雹，三載從游只如昨。", "似聞買船修水來，俄見呼童理歸橐。", "酸寒自是臨川尉，况值凶年羣盜作。", "干戈陌上玩經史，金鼓聲中挹杯杓。", "上官喑嗚百吏怖，人皆唯唯君諤諤。", "此行作邑亂山中，安得校書天祿閣。", "歸謁黄龍老比邱，乞取囊中萬金藥。", "吾體潰悶假雙井，信信致之亦不惡。"]'),
('76b2823f-c798-4daf-b834-dd72ae733019','送趙德甫侍親淮東','謝逸','宋','宋诗','song-poetry','','[]','茂陵少年白面郎，手携五弦望八荒。',176,'全唐诗/poet.song.74000.json','["茂陵少年白面郎，手携五弦望八荒。", "欹帆側柁轉天末，瞿塘灧澦一葦航。", "向來問字識揚子，年未二十如老蒼。", "林花蜚盡春事了，粲然一笑西山陽。", "幅巾相從竟日坐，虛堂掃地焚清香。", "人物已共遠峰秀，談辯更與薰風凉。", "黄梅雨洗天界凈，驅車出門指太行。", "朝侯暮烹不足道，人生離別安得常。", "丈夫許與重氣義，兒女惜別徒慘傷。", "觀君瀟洒負奇氣，恐是天廄真乘黄。", "願言待價無速售，世間駔儈皆王良。"]'),
('55eb01e3-a4b6-45e4-a8ca-42e5dbb7a69d','送狄朝議','謝逸','宋','宋诗','song-poetry','','[]','狄公鶚立橫清秋，真氣端能回萬牛。',128,'全唐诗/poet.song.74000.json','["狄公鶚立橫清秋，真氣端能回萬牛。", "平生作郡有老手，退食燕寢清香浮。", "鞭笞得名亦不惡，一官何足償百憂。", "豈如清浄政不撓，男耕女桑民力優。", "小人瑣瑣不足錄，惡詩蒙公三過讀。", "自聞歸棹理江干，北望傷懷何刺促。", "胡不强爲此邦留，懸知季月當泛菊。", "願言他日持節來，一洗蒼生愁萬斛。"]'),
('757a940f-85ef-490b-bcf6-1363751f9770','遊逍遥寺詠庭前柏樹以老杜病柏詩偃蹙龍虎姿生當風雲會爲韵得蹙字','謝逸','宋','宋诗','song-poetry','','[]','歲寒在天知後凋，受命於地稟正獨。',128,'全唐诗/poet.song.74000.json','["歲寒在天知後凋，受命於地稟正獨。", "楂枒枝幹撐青冥，凜然正色不可辱。", "霹靂霽威霜雪避，奴視椅桐友松竹。", "孔明廟邊凍蟻食，御史臺中老烏宿。", "何如結根阿蘭那，葉映高僧胡眼綠。", "楚多楩柟剪伐盡，大國要材梁夏屋。", "何時匠石運斤風，不使龍姿久偃蹙。", "反觀樗櫟老臃腫，永保天年長受福。"]'),
('0a2b99a8-7eb6-4cea-9a9c-05995e45d28d','送惠洪上人','謝逸','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','真凈養兒如養羊，敗羣者去羊不傷。',176,'全唐诗/poet.song.74000.json','["真凈養兒如養羊，敗羣者去羊不傷。", "洪師斗擻蔬筍氣，白晝穴我夫子牆。", "粥魚齋鼓了無礙，坐禪不廢談文章。", "老師頷之笑不語，壞衲百孔穿寒光。", "洞庭風號波浪吼，笑揖逐客談船窗。", "六月赤脚登大庾，黄茆瘴裏餐檳榔。", "天宮不合困兩鳥，洪徐接翼鳴南昌。", "毛羣羽族不敢喘，師乃啁唽鳴其旁。", "欻起四明狂客念，揚瀾恨不一葦航。", "男兒行役良自苦，水有鮫鰐陸豺狼。", "何當啖芋撥牛糞，拗折拄杖挂鉢囊。"]'),
('44ca1ae7-dbd5-4634-8d3b-7e18b0367abd','懷李方叔','謝逸','宋','宋诗','song-poetry','','[]','儒林丈人稱兩蘇，一言爲重輕璠璵。',64,'全唐诗/poet.song.74000.json','["儒林丈人稱兩蘇，一言爲重輕璠璵。", "見君誦詩出險語，撫掌絕倒徒驚呼。", "貴耳賤目亦不惡，虎豹何殊犬羊鞟。", "勸君掩舌卧衡門，莫賦悲秋任摇落。"]'),
('e5cdc836-8f38-4967-8372-2765d57564ba','送李希顔','謝逸','宋','宋诗','song-poetry','','[]','長安少年清似玉，腰垂黄金雙鬢綠。',128,'全唐诗/poet.song.74000.json','["長安少年清似玉，腰垂黄金雙鬢綠。", "吹噓氣焰高岑樓，胡不容公置一足。", "腦脂遮眼卧三年，滿榻秋風對修竹。", "戶內殷殷金石聲，牙籤插架三萬軸。", "箋詩作傳起凡例，斷簡殘編紛在目。", "題輿粵國正秋風，石瘦水清山詰曲。", "先聲霹靂挾仁氣，父老歡呼胥吏肅。", "莫思蓴菜賦歸歟，天上要公調鼎餗。"]'),
('725f2132-5a44-4fde-8ef3-8a9eed672af7','送袁公發','謝逸','宋','宋诗','song-poetry','','[]','袁公落筆清如風，妙齡場屋聲摩空。',80,'全唐诗/poet.song.74000.json','["袁公落筆清如風，妙齡場屋聲摩空。", "陸沉簿領三十載，晚節自號無求翁。", "朝廷公卿半親舊，誰能挽致青雲中。", "參天老柏耐霜雪，始知不與蕭艾同。", "俛首下邑亦良苦，此行定入明光宮。"]'),
('412a7f8a-ccfb-4903-ac95-10647a5e473c','送譚子仁游太學','謝逸','宋','宋诗','song-poetry','','[]','沓沓舉子萬馬奔，傾動場屋風塵昏。',112,'全唐诗/poet.song.74000.json','["沓沓舉子萬馬奔，傾動場屋風塵昏。", "失身白袍青幕底，平生乾沒三家村。", "今君觸熱去鄉縣，矯如野鶴離雞羣。", "筆端萬字灑飛雹，豈畏食葉春蠶喧。", "廣文先生倒屣待，三舍弟子氣可吞。", "琴書在笥馬在門，看看山上復有山。", "願君莫忘大刀頭，何年駟馬君當還。"]'),
('638aec7d-fb22-4386-acd0-3f703ab2a217','豫章別李元中宣德','謝逸','宋','宋诗','song-poetry','','[]','舊聞諸李隠龍眠，伯時已老元中少。',144,'全唐诗/poet.song.74000.json','["舊聞諸李隠龍眠，伯時已老元中少。", "一行作吏各天涯，故人落落疏星曉。", "西山影裏識君面，碧照章江眸子瞭。", "向來問道渺多歧，只今領略歸玄妙。", "老鳳垂頭噤不語，古木槎枒噪春鳥。", "身在幕府心江湖，左胥右律但坐嘯。", "第愁一葉釣魚舟，不容七尺堂堂表。", "我今歸卧靈谷雲，君應紫禁鶑花繞。", "相思有夢到茅齋，細雨青燈坐林杪。"]'),
('04559a24-c4e0-4569-8850-c40d976e0d13','與諸友訪黄宗魯宗魯置酒于思猷亭席上分韵賦思猷亭詩各以姓爲韵予得謝字','謝逸','宋','宋诗','song-poetry','','[]','我見俗子避百舍，一錢不直灌夫駡。',144,'全唐诗/poet.song.74000.json','["我見俗子避百舍，一錢不直灌夫駡。", "靈谷峰前汝水湄，誰信無雙有江夏。", "平生眼底無可人，子猷粗與吾同社。", "故栽修竹共歲寒，不與繁花鬭榮謝。", "疏陰時過少陵樽，斜枝最入蕭郎畫。", "强排風雨作寒聲，巧留雪月延深夜。", "三伏炎蒸自可逃，一榻清凉那肯借。", "願言閉關謝俗子，勿與此曹俱日化。", "但得風味如晉人，縱無此君自瀟洒。"]'),
('a89a629c-f08e-4100-9438-f26cffb20d10','從黄宗魯乞怪石','謝逸','宋','宋诗','song-poetry','','[]','織女支機棄不用，老盧墜腰誰見收。',112,'全唐诗/poet.song.74000.json','["織女支機棄不用，老盧墜腰誰見收。", "君從何處得此石，恐有鬼物爲君偷。", "不堪壓作搗練石，仆在牆東如卧牛。", "何如置我清溪上，奇峰崒嵂臨清流。", "鄙夫鬚髯銳如戟，青眸皓齒不我儔。", "惟有泉石肯相伴，不索吾米無所求。", "何時突兀入眼界，白頭相對忘百憂。"]'),
('8db6b582-57f5-402f-b8d2-7aaff8d58035','代送柳權郡','謝逸','宋','宋诗','song-poetry','','[]','河東夫子文中虎，筆端揮灑如飛雨。',128,'全唐诗/poet.song.74000.json','["河東夫子文中虎，筆端揮灑如飛雨。", "餘波覃及百世孫，翰墨風流照今古。", "文章清麗有典則，胸懷恢廓無城府。", "擁麾山郡民氣和，萬頃黄雲富禾黍。", "公餘雅會羅嘉賓，高論崢嶸揮玉麈。", "皂蓋雙旌別汝江，去作他邦民父母。", "佇看祖席列岐亭，梅影橫斜媚村塢。", "定知玉詔下丹墀，宰府要公調鼎俎。"]'),
('aeef274d-a541-4bcf-a340-031152d4b0f3','送鄒元佐還鄉','謝逸','宋','宋诗','song-poetry','','[]','白雲英英天末飛，紅蕖脈脈澗底靜。',64,'全唐诗/poet.song.74000.json','["白雲英英天末飛，紅蕖脈脈澗底靜。", "北堂姑老冢婦勤，鄒侯感物動幽興。", "蹔將平生說詩口，試言禍福知天命。", "五行推步聊復爾，恐君胸中有水鏡。"]'),
('bb668018-08c9-4b65-9fce-3500f706993e','送高彥應','謝逸','宋','宋诗','song-poetry','','[]','小儒百鳥喧春風，大儒老鳳栖梧桐。',80,'全唐诗/poet.song.74000.json','["小儒百鳥喧春風，大儒老鳳栖梧桐。", "諸生談經用一律，夫子不答如病聾。", "迺知胸次有妙理，此心矯矯誰與同。", "臨川决曹亦良苦，三年掉臂桁楊中。", "懸知此行不落寞，陛下近用韓相公。"]'),
('39432877-ea93-4056-8b1d-446390b2152a','題許邦基却俗軒詩','謝逸','宋','宋诗','song-poetry','','[]','流俗紛紛何足却，爾曹百輩吾能著。',64,'全唐诗/poet.song.74000.json','["流俗紛紛何足却，爾曹百輩吾能著。", "雖同一床各做夢，政恐不妨人作樂。", "俗客自與此君疏，竹洞何曾有關鑰。", "但邀明月對君飲，莫管門前可羅雀。"]'),
('e517e2c4-6129-44f5-8c49-81ec84f80a1b','次張邦式韵','謝逸','宋','宋诗','song-poetry','','[]','君家劍氣干牛斗，焰焰寒光半天倚。',160,'全唐诗/poet.song.74000.json','["君家劍氣干牛斗，焰焰寒光半天倚。", "胡不長携西入秦，曳裾侯門颯珠履。", "奈何俛首桁楊間，手决大獄如傾水。", "不向南樓按歌舞，乃提健筆誇豪靡。", "獨步詩壇數挑戰，雖欲爭鋒吾老矣。", "晚來搜攬饑腹空，戲抱添丁玩岐嶷。", "蒼頭剝啄叩我門，急得長篇驚撫几。", "嗟予敢望幼度才，哦詩粗可玄暉比。", "紫囊成壞本來空，心悟香嚴聊爾爾。", "君如暫輟畫眉手，我亦閉關防折齒。"]'),
('1f52dea0-0766-47dc-b6c8-758846146092','再用前韵','謝逸','宋','宋诗','song-poetry','','[]','我家端無一囊錢，骯髒趙生門可倚。',160,'全唐诗/poet.song.74000.json','["我家端無一囊錢，骯髒趙生門可倚。", "黄綬叢中識君面，眼前如見曲阜履。", "興來曳杖叩齋扉，清坐焚香淡如水。", "有時造語出瑰奇，要令墨客皆風靡。", "仰觀喬木俯流泉，因念吾生行已矣。", "臺若君才萬夫特，風儀秀整秋山嶷。", "行看待詔金馬門，安得嗒然長隠几。", "功名他日似留侯，豈與風流京兆比。", "昨朝篇末畫眉句，始悟前言戲之耳。", "不如共訪彌天釋，真成四海習鑿齒。"]'),
('f38466bb-3511-49bd-bd07-a09684154a61','雪','謝逸','宋','宋诗','song-poetry','','[]','春雲結成三日霖，朔風吹作一尺雪。',64,'全唐诗/poet.song.74000.json','["春雲結成三日霖，朔風吹作一尺雪。", "紛紛委地玉花亂，皎皎照戶虹光發。", "一樽相對老孟光，寒窗癡坐燈明滅。", "踏雪觀梅亦不惡，月夜西樓更清絕。"]'),
('85a9e654-95d0-4e0e-9286-c752255d6a3c','歲晚書懷','謝逸','宋','宋诗','song-poetry','','[]','莫事休休復莫莫，草木歸根定摇落。',64,'全唐诗/poet.song.74000.json','["莫事休休復莫莫，草木歸根定摇落。", "窮冬日月任崢嶸，寒士胸懷要恢廓。", "人言張儀舌尚在，我慚祖逖鞭先著。", "君如端爲梅花歸，請脫青衫對花酌。"]'),
('8ff0979c-deda-4ab2-b918-21520211876a','晚晴','謝逸','宋','宋诗','song-poetry','','[]','輕雲朝作雨，麗日晚開晴。',48,'全唐诗/poet.song.74000.json','["輕雲朝作雨，麗日晚開晴。", "岸草葱葱碧，溪流泯泯清。", "沙汀眠白鷺，烟樹囀黄鶑。", "涉世心無競，支頤眼暫明。"]'),
('b62edce4-01e3-4d71-bab2-3345c03faaa2','寄李彬','謝逸','宋','宋诗','song-poetry','','[]','昔日陶彭澤，何嘗見督郵。',48,'全唐诗/poet.song.74000.json','["昔日陶彭澤，何嘗見督郵。", "江淮寬運漕，幕府得優游。", "故舊誰青眼，功名要黑頭。", "相思懷抱惡，注目倚南樓。"]'),
('66edb904-5eb6-42d8-aff2-b553d2ab7dc5','客至','謝逸','宋','宋诗','song-poetry','','[]','曲肱秋夢覺，剝啄打門聲。',48,'全唐诗/poet.song.74000.json','["曲肱秋夢覺，剝啄打門聲。", "鵲噪柳陰亂，雞喧藤架傾。", "寫詩無阿買，聯句有彌明。", "飲罷各分袂，月凉風露清。"]'),
('8fde50cc-ca32-44b3-ab41-3e6f69b205bf','秋日書懷','謝逸','宋','宋诗','song-poetry','','[]','驟雨池塘漲，飄風枕簟凉。',48,'全唐诗/poet.song.74000.json','["驟雨池塘漲，飄風枕簟凉。", "野田肥雁鶩，官柳噪蜩螗。", "歲月書千古，功名酒一觴。", "塵纓如可濯，携女泛滄浪。"]'),
('5d5ac245-7b3e-4081-8c0b-6842ccd08946','黄通理邀遊南湖','謝逸','宋','宋诗','song-poetry','','[]','不踏南湖路，端居兩見春。',48,'全唐诗/poet.song.74000.json','["不踏南湖路，端居兩見春。", "浮花空過眼，濁酒漫濡脣。", "曳杖惟今日，開樽有故人。", "何須推物理，行樂及佳辰。"]'),
('d2fbde07-4f7b-4b7e-b1d5-6d1e266b21c5','汪信民載酒令表弟吳迪吉邀予同遊南湖  其一','謝逸','宋','宋诗','song-poetry','','[]','古人多齟齬，吾黨故徘徊。',48,'全唐诗/poet.song.74000.json','["古人多齟齬，吾黨故徘徊。", "表弟邀予出，參軍載酒來。", "南湖未新柳，東巷且殘梅。", "但恐辟書至，將軍幕府開。"]'),
('109f3a18-724f-4a65-9977-94d957aaf828','汪信民載酒令表弟吳迪吉邀予同遊南湖  其二','謝逸','宋','宋诗','song-poetry','','[]','東府文雖下，西津艇未橫。',48,'全唐诗/poet.song.74000.json','["東府文雖下，西津艇未橫。", "莫愁官長駡，且伴老夫行。", "飲酒舊無敵，能詩新有聲。", "此樽誰可使，待倩許飛瓊。"]'),
('38d7ecc0-a3d5-4f15-97ed-92a9d3cf15e3','睡起','謝逸','宋','宋诗','song-poetry','','[]','地僻市聲遠，林深荒徑迷。',48,'全唐诗/poet.song.74000.json','["地僻市聲遠，林深荒徑迷。", "家貧惟飯豆，肉貴但羹藜。", "假貸煩鄰里，經營愧老妻。", "曲肱聊自樂，午夢破鳴雞。"]'),
('f0f422a1-0363-476c-b9c0-f64bececadcf','月夜與兒曹露坐庭中','謝逸','宋','宋诗','song-poetry','','[]','夜凉雲幕捲，人靜蓽門扃。',48,'全唐诗/poet.song.74000.json','["夜凉雲幕捲，人靜蓽門扃。", "掃葉風生砌，鈎簾月可庭。", "秋懷因酒壯，老眼對兒青。", "遠愧荀陳氏，應無聚德星。"]'),
('ba840508-a2c6-4824-82bf-11144ca81f60','社日','謝逸','宋','宋诗','song-poetry','','[]','雨柳垂垂葉，風溪澹澹紋。',48,'全唐诗/poet.song.74000.json','["雨柳垂垂葉，風溪澹澹紋。", "清歡唯煮茗，美味祇羹芹。", "飲不遭田父，歸無遺細君。", "東皋農事作，舉趾待耕耘。"]'),
('5b55233a-ce9e-40f5-b804-2b9ab36264f4','南歸渡江去家稍近喜而有作','謝逸','宋','宋诗','song-poetry','','[]','晚渡江南岸，村村水竹居。',48,'全唐诗/poet.song.74000.json','["晚渡江南岸，村村水竹居。", "歸心先倦鳥，樂事羨游魚。", "去國清明後，還家穀雨初。", "懸知農務急，弛擔把犁鋤。"]'),
('98164125-8b8d-4369-8e6d-cd7f14d1d73a','八月十六日夜玩月南湖用老杜韵','謝逸','宋','宋诗','song-poetry','','[]','月減一分魄，風生萬壑秋。',48,'全唐诗/poet.song.74000.json','["月減一分魄，風生萬壑秋。", "山烟連野白，湖水接天流。", "妙語懷支遁，清歌欠莫愁。", "漥樽聊共酌，無羨玉爲舟。"]'),
('857c5b26-8e9b-4912-b8dc-484b47b2c6e4','與宗野宗樸二稚子觀蔬圃  其一','謝逸','宋','宋诗','song-poetry','','[]','干祿心無競，謀生計已疏。',48,'全唐诗/poet.song.74000.json','["干祿心無競，謀生計已疏。", "老催吾學圃，貧減汝觀書。", "細雨同移果，清霜共挽蔬。", "何時江海去，蓑笠伴舂鋤。"]'),
('2b862e07-9cf7-4edd-9f71-7fb1b9990484','與宗野宗樸二稚子觀蔬圃  其二','謝逸','宋','宋诗','song-poetry','','[]','閉戶無賓客，忘憂頼玉魚。',48,'全唐诗/poet.song.74000.json','["閉戶無賓客，忘憂頼玉魚。", "迂疏皆識我，貧賤不關渠。", "散步惟荒圃，端居且敝廬。", "但知師羯末，未可笑宣舒。"]'),
('5a31051e-56bb-422f-b5f6-b4523c8d67aa','擬峴臺','謝逸','宋','宋诗','song-poetry','','[]','董奉山中種杏，玄都觀裏栽桃。',84,'全唐诗/poet.song.74000.json','["董奉山中種杏，玄都觀裏栽桃。", "清曠孰如此地，登臨况是吾曹。", "城下一江水碧，江邊百尺臺高。", "倦蝶舞酣花塢，驚鷗飛掠魚舠。", "客子自來如燕，世事相黏若蠔。", "何當有酒徑醉，凉州不博葡萄。"]'),
('c529a55a-5058-473a-8713-b8dc89da0853','潜心堂','謝逸','宋','宋诗','song-poetry','','[]','潜心便是覓安心，立雪何煩問少林。',64,'全唐诗/poet.song.74000.json','["潜心便是覓安心，立雪何煩問少林。", "羽扇綸巾延客晚，蒲團禪板坐更深。", "要先舟壑藏時悟，莫向風幡動處尋。", "試抉孤峰雲一寸，與民三日作春霖。"]'),
('60d01d82-3bbb-40d1-ba92-53b412d54ad4','和陳仲邦野步城西','謝逸','宋','宋诗','song-poetry','','[]','寺近仙壇西復西，醉中信足路應迷。',64,'全唐诗/poet.song.74000.json','["寺近仙壇西復西，醉中信足路應迷。", "鳴條風勁凋蒲柳，掠岸雲低亂鵠鷖。", "簷外檀欒森翠巘，門前略彴跨清溪。", "葛巾藜杖真瀟散，何必狨鞍鞚月題。"]'),
('d251796c-a7bb-457f-bcdd-f697b523bcfc','寄幼槃弟','謝逸','宋','宋诗','song-poetry','','[]','北闕弓旌未見招，茅亭高卧對山椒。',64,'全唐诗/poet.song.74000.json','["北闕弓旌未見招，茅亭高卧對山椒。", "詩成稚子應能誦，酒熟鄰翁漸可邀。", "寧似杜陵長蹭蹬，不依嚴武更逍遥。", "細思洗馬池邊路，便是成都萬里橋。"]'),
('bf2ed364-3359-4521-9127-bfdaf64c3eae','寄徐師川','謝逸','宋','宋诗','song-poetry','','[]','司業端能乞酒錢，誰憂坐客冷無氈。',64,'全唐诗/poet.song.74000.json','["司業端能乞酒錢，誰憂坐客冷無氈。", "相望建業只千里，不見徐侯今七年。", "江水江花同臭味，海南海北各山川。", "試問烟波何處好，老夫欲理釣魚船。"]'),
('afb40c46-b402-47c2-9eb4-3ed82cc4184f','暮春感懷','謝逸','宋','宋诗','song-poetry','','[]','雨退飛廉决怒雲，百花凈盡掃埃塵。',64,'全唐诗/poet.song.74000.json','["雨退飛廉决怒雲，百花凈盡掃埃塵。", "大千沙界乾坤闊，一段江山日月新。", "浩蕩烟波鯨海晚，漰騰雪浪錦城春。", "誰人獨採南山蕨，窗外休呼祁孔賓。"]'),
('b04af3b1-5004-4db9-93e7-c49e3474eab5','送朱世英  其一','謝逸','宋','宋诗','song-poetry','','[]','妙凈光雲覆八荒，經行聚落得清凉。',64,'全唐诗/poet.song.74000.json','["妙凈光雲覆八荒，經行聚落得清凉。", "閻浮檀水心無染，優鉢羅花體自香。", "赤舄未容趨北闕，綠槐先已兆東牆。", "應真外見中和色，豈在眉間一點黄。"]'),
('5e52c038-96de-4ad3-87c2-0f1778df83be','送朱世英  其二','謝逸','宋','宋诗','song-poetry','','[]','漠漠薰風錦旆翻，綵衣聊復殿名藩。',64,'全唐诗/poet.song.74000.json','["漠漠薰風錦旆翻，綵衣聊復殿名藩。", "行藏有道朱弦直，表裏無瑕白玉溫。", "燕寢妙香凝碧縷，夜談孤月落金盆。", "試將執拂拈槌手，行秉玄圭侍至尊。"]'),
('3e79d474-b66c-4179-8988-edfcc6ed7f81','送朱世英  其三','謝逸','宋','宋诗','song-poetry','','[]','短褐登門每自慚，僅同太史滯周南。',64,'全唐诗/poet.song.74000.json','["短褐登門每自慚，僅同太史滯周南。", "沈迷晚學三無漏，懶慢長疑七不堪。", "平日漫懸高士榻，此行應共德公談。", "他年解組歸來日，尚許南榮見老聃。"]'),
('a6874719-7892-40b2-9f67-3f1fd0cbe2c5','懷吳迪吉','謝逸','宋','宋诗','song-poetry','','[]','朔風吹鬢幅巾斜，飯了呼童碾露芽。',64,'全唐诗/poet.song.74000.json','["朔風吹鬢幅巾斜，飯了呼童碾露芽。", "竹影蕭蕭圍我舍，溪流渺渺對君家。", "古心莫爲世情改，老眼聊憑文字遮。", "安得一蓑烟雨裏，小船載酒卧蘆花。"]'),
('78a1bbdc-ab08-4bf7-b8de-d254992d5f64','送汪叔野水芝法醖','謝逸','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','屏居不到日邊久，安得黄封印赤泥。',64,'全唐诗/poet.song.74000.json','["屏居不到日邊久，安得黄封印赤泥。", "折遍溪堂紅菡萏，釀成湘酎碧玻璃。", "洞庭春色名應減，道院丹泉價益低。", "聊挹小樽供壽母，煩君自注玉東西。"]'),
('58c21204-f104-4fde-9ef7-08f28052a7cf','用汪信民韵送叔野迎婦山陽','謝逸','宋','宋诗','song-poetry','','[]','凉月凄風透客衣，離亭無奈角聲悲。',64,'全唐诗/poet.song.74000.json','["凉月凄風透客衣，離亭無奈角聲悲。", "解圍未設王家障，舉案先齊孟氏眉。", "青眼難兄嗟久別，白頭壽母夢相思。", "胸中若有功名念，莫待鐘鳴漏盡時。"]'),
('5ebda20f-f4de-4f92-bf9c-9e4b44a3a746','與高彥應司理遊南湖','謝逸','宋','宋诗','song-poetry','','[]','飛花瞇目亂紛紛，細草裙腰綠映門。',64,'全唐诗/poet.song.74000.json','["飛花瞇目亂紛紛，細草裙腰綠映門。", "山色入簾清可挹，湖光照座冷無痕。", "揄揚春色煩詩句，排遣愁情頼酒樽。", "預想明年君去後，沙寒竹凈野烟昏。"]'),
('9ec6d2a0-e9da-4f91-82d3-7adede34e620','陪通守承議游鐵山書堂','謝逸','宋','宋诗','song-poetry','','[]','斬新氣象舊書堂，堂裏幽人璧一雙。',64,'全唐诗/poet.song.74000.json','["斬新氣象舊書堂，堂裏幽人璧一雙。", "雨洗花光紅繞舍，風摇竹影碧含窗。", "山橫雲外青螺髻，樹列簷前翠羽幢。", "城上烏啼歸棹急，笛聲嘹亮月澄江。"]'),
('fb1650e4-9fe7-4f62-840d-0e001fc6aa69','次王直方承務見寄韵','謝逸','宋','宋诗','song-poetry','','[]','知君才是出羣雄，憐我生涯獨轉蓬。',64,'全唐诗/poet.song.74000.json','["知君才是出羣雄，憐我生涯獨轉蓬。", "稚子凄凉緣歲惡，鄙夫寂寞坐詩窮。", "百年鼎鼎風埃裏，萬事悠悠醉眼中。", "幸有孟光堪舉案，退居真欲效梁鴻。"]'),
('77df2f92-4f8f-40e7-80f7-7a5a88e1a9d3','陪王守遊明水  其一','謝逸','宋','宋诗','song-poetry','','[]','雨後山川秀滿溪，洞門疑是辟塵犀。',64,'全唐诗/poet.song.74000.json','["雨後山川秀滿溪，洞門疑是辟塵犀。", "白沙翠竹溪光浄，細草幽花野逕迷。", "閒步禪林思蝶化，倦騎朝馬聽雞啼。", "使君自得真消息，祖令須煩大士提。"]'),
('e313951d-0daf-499a-8458-20e17974e9a3','陪王守遊明水  其二','謝逸','宋','宋诗','song-poetry','','[]','山擁雲鬟掃夕霏，千林浮翠髮初晞。',64,'全唐诗/poet.song.74000.json','["山擁雲鬟掃夕霏，千林浮翠髮初晞。", "雷音震谷朱輪轉，霞影摇空綵旆飛。", "曉霧拂襟憐冉弱，晚風掀袂愛清微。", "夕陽樓上吹笳管，歸騎遥瞻兩塔巍。"]'),
('d48125ed-c837-489e-8848-a076c4821fc3','同信民出城南訪正叔共約南湖之遊至今不果信民即有長沙之行恐遂爽約戲作詩以督之','謝逸','宋','宋诗','song-poetry','','[]','初見南湖凍未消，只今流水又平橋。',64,'全唐诗/poet.song.74000.json','["初見南湖凍未消，只今流水又平橋。", "驅除臘雪煩梅蘂，收拾春風倩柳條。", "豈有故人行作別，不將樽酒慰無聊。", "府中諸史皆英妙，早晚相從幸見招。"]'),
('2eefb58f-d7ff-4cb5-82b6-a416a7dbeaef','又飲西塔寺遊南湖用老杜城西陂泛舟詩爲韵','謝逸','宋','宋诗','song-poetry','','[]','未訪稽山棹酒船，先尋小有洞中天。',64,'全唐诗/poet.song.74000.json','["未訪稽山棹酒船，先尋小有洞中天。", "葛巾藜杖輕軒冕，盂飯盤蔬鄙餼牽。", "巢父掉頭休入海，焦生雄辯且驚筵。", "老僧瀹茗供清興，旋拾枯松煮澗泉。"]'),
('bf421891-7beb-4355-b3c8-1ed2525707b6','送梭山朱道人','謝逸','宋','宋诗','song-poetry','','[]','不隨俗客老塵寰，晚節逍遥水石間。',64,'全唐诗/poet.song.74000.json','["不隨俗客老塵寰，晚節逍遥水石間。", "獨佩藥囊來澤國，只留丹竈在梭山。", "身如野鶴更無侶，心似白雲長是閑。", "若見劉仙問消息，幸分餘粒及衰顔。"]'),
('bdde61cc-d332-479a-8cd1-515ef3c2bcba','次韵汪信民見寄','謝逸','宋','宋诗','song-poetry','','[]','直道逢人多齟齬，高懷向我最恢疏。',64,'全唐诗/poet.song.74000.json','["直道逢人多齟齬，高懷向我最恢疏。", "不貪但守司城寶，無澤應辭季武車。", "池種青蓮看妙浄，庭栽翠竹悟真如。", "何年來過溪堂飯，小圃携籃自摘蔬。"]'),
('37eb2168-204c-4f16-8e6e-c43fcae04d54','送常老住疏山','謝逸','宋','宋诗','song-poetry','','[]','師住疏山祇樹園，卧觀雲氣起江村。',64,'全唐诗/poet.song.74000.json','["師住疏山祇樹園，卧觀雲氣起江村。", "百年鼎鼎春風轉，一鉢垂垂老眼昏。", "古殿橫空森鐵鳳，夜潭翻浪落金盆。", "何時繫纜西峰下，松柏陰中獨叩門。"]'),
('88691446-cf3a-432c-a645-8b680a0395bb','聞秦少儀病愈','謝逸','宋','宋诗','song-poetry','','[]','平生四海秦少儀，造化小兒何苦之。',64,'全唐诗/poet.song.74000.json','["平生四海秦少儀，造化小兒何苦之。", "端能浸假求鴞炙，定不泣涕眠牛衣。", "問夢是想理既剖，杯中有蛇心不疑。", "何時過我舉玉趾，不用門生并二兒。"]'),
('88398e86-94b3-40b6-9d06-3c3daf797d7b','游泉庵寺懷璧上人以徐飛錫杖出風塵爲韵探得徐字','謝逸','宋','宋诗','song-poetry','','[]','年少談王陋漢儒，筆端萬字壓嚴徐。',64,'全唐诗/poet.song.74000.json','["年少談王陋漢儒，筆端萬字壓嚴徐。", "昔爲酒客鶑花繞，今作禪林水竹居。", "賤子已捐干祿學，故人休草絕交書。", "春風縱棹遊蕭寺，北望淮山正憶渠。"]'),
('f7e4984b-c401-4969-8ee7-4bf3a8b1ff09','寄洪駒父兼簡潘子真徐師川','謝逸','宋','宋诗','song-poetry','','[]','洪家兄弟皆英妙，仲氏文章獨起予。',64,'全唐诗/poet.song.74000.json','["洪家兄弟皆英妙，仲氏文章獨起予。", "天末何人懷太白，日邊誰子薦相如。", "東湖水落蛙聲窘，南浦雲橫雁影疏。", "莫憶歸鴻揮老淚，强裁詩句和潘徐。"]'),
('d054a268-466c-4e1a-a67b-920e2bea6b03','寄徐師川','謝逸','宋','宋诗','song-poetry','','[]','門外荒園一畝餘，長拋筆硯把犁鉏。',64,'全唐诗/poet.song.74000.json','["門外荒園一畝餘，長拋筆硯把犁鉏。", "天邊風露秋期近，海外交遊音信疏。", "揚子家貧惟嗜酒，嵇康性懶不便書。", "龍沙江水連天闊，尺素何當寄鯉魚。"]'),
('1df1b7db-04fd-4485-b1a2-d3dfc58f65b8','和詹存中種竹','謝逸','宋','宋诗','song-poetry','','[]','斸地移根未滿林，庭前俄見影陰森。',64,'全唐诗/poet.song.74000.json','["斸地移根未滿林，庭前俄見影陰森。", "晚烟漠漠玉雙峙，夜雨蕭蕭龍一吟。", "勁節扶疏真耐老，高才灑落少知音。", "參軍吏隠世情薄，只有此君同我心。"]'),
('08c553b7-d31b-40d0-aeb9-94c2add58545','聞徐師川自京師歸豫章','謝逸','宋','宋诗','song-poetry','','[]','九衢塵裏無停輈，君居陋巷不出遊。',64,'全唐诗/poet.song.74000.json','["九衢塵裏無停輈，君居陋巷不出遊。", "滿城惡少弋鳬雁，對面故人風馬牛。", "別後夢寒燈火夜，歸來眼冷江湖秋。", "馮驩老大食不飽，起視八荒提蒯緱。"]'),
('56c47345-545b-4ff2-ab89-d17dba8e59a8','舟中不寢奉懷齊安潘大臨蘄春林敏功','謝逸','宋','宋诗','song-poetry','','[]','病夫不寐百憂集，起視斗柄東南傾。',64,'全唐诗/poet.song.74000.json','["病夫不寐百憂集，起視斗柄東南傾。", "山林畏隹萬壑笑，天地黯慘孤舟橫。", "此身老矣幾寒暑，四海茫然誰弟兄。", "江西米貴斗三百，好去淮南訪友生。"]'),
('0f6df019-2041-41e2-a37b-222f78ca5760','和陳倅泛舟寄瑩中德翁印老  其一','謝逸','宋','宋诗','song-poetry','','[]','欲尋靖節訪東皋，復憶禪翁隠妙高。',64,'全唐诗/poet.song.74000.json','["欲尋靖節訪東皋，復憶禪翁隠妙高。", "月送征鴻遵露渚，舟隨飛鷺掠雲濤。", "知公氣壓陳驚座，顧我詩慚謝法曹。", "膽落舊聞溫御史，至今蛟獸尚騰逃。"]'),
('0e130f17-105e-4d9e-94de-f3f22fc1a6b0','和陳倅泛舟寄瑩中德翁印老  其二','謝逸','宋','宋诗','song-poetry','','[]','澹雲疏雨羃平皋，樓卧元龍百尺高。',64,'全唐诗/poet.song.74000.json','["澹雲疏雨羃平皋，樓卧元龍百尺高。", "紅旆已飛居易舫，赤心寧畏子胥濤。", "但知守道師前輩，未忍低頭效此曹。", "天遣數公慰人望，萬年富貴恐難逃。"]'),
('07127201-5f7a-4311-a282-f44c7c562971','和陳倅靈壁寄瑩中二首  其一','謝逸','宋','宋诗','song-poetry','','[]','汴上相逢艤畫橈，清愁萬斛若冰消。',64,'全唐诗/poet.song.74000.json','["汴上相逢艤畫橈，清愁萬斛若冰消。", "弟兄直諒推三友，父子公忠擅四朝。", "對鏡如如皆般若，開談句句盡參寥。", "要知往事多虛幻，看取錢塘八月潮。"]'),
('5f34ecf9-1f95-4a91-99d1-cc3bad2178f6','和陳倅靈壁寄瑩中二首  其二','謝逸','宋','宋诗','song-poetry','','[]','風攪張園萬木摇，黯然分袂客魂消。',64,'全唐诗/poet.song.74000.json','["風攪張園萬木摇，黯然分袂客魂消。", "更無餘念留胸次，但有孤忠報聖朝。", "千里烟波舟泛泛，百年事業古寥寥。", "新詩吟就誰能寫，安得巴東遇李潮。"]'),
('2c22226e-7088-4207-85d9-e42537496ab0','重陽示萬同德','謝逸','宋','宋诗','song-poetry','','[]','晚起無營著帽遲，蕭疏霜鬢任風吹。',64,'全唐诗/poet.song.74000.json','["晚起無營著帽遲，蕭疏霜鬢任風吹。", "病懷王子同傾酒，愁憶潘郎共賦詩。", "甯效騷人餐菊蘂，敢希朝士賜萸枝。", "白衣不至慚元亮，空對門生與二兒。"]'),
('148b41ad-e5d6-4658-9915-aba3c3519bbf','郊行書事','謝逸','宋','宋诗','song-poetry','','[]','斬新氣象曉懷清，拂面西風卯酒醒。',64,'全唐诗/poet.song.74000.json','["斬新氣象曉懷清，拂面西風卯酒醒。", "萬物歸根秋寂寂，大田多稼雨冥冥。", "獨逢隔水一山碧，不覺舉頭雙眼青。", "預想明年生事足，不煩結柳使奴星。"]'),
('f70be4ca-2a3d-4089-97c7-495023297633','次董之南韵','謝逸','宋','宋诗','song-poetry','','[]','門外遠山膚寸碧，堂前溪水半篙深。',64,'全唐诗/poet.song.74000.json','["門外遠山膚寸碧，堂前溪水半篙深。", "仰看老鶴有清興，靜聽幽琴無俗音。", "三釜及親君養志，一瓢在巷我甘心。", "向平婚嫁何年畢，杖策長隨支道林。"]'),
('9d4d9247-e246-442b-b1b6-595bd355b357','次季智伯韵','謝逸','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','薄有田園百不憂，詩書自樂更無求。',64,'全唐诗/poet.song.74000.json','["薄有田園百不憂，詩書自樂更無求。", "形容風月三千首，笑傲林泉四十秋。", "豈意騎鯨尋李白，真成夢蝶化莊周。", "誰能倒激西江水，洗我胸中萬斛愁。"]'),
('8646717e-f023-4003-93fc-cc77d4b3a149','寄饒葆光','謝逸','宋','宋诗','song-poetry','','[]','先生骨相不封侯，卜居但得林塘幽。',64,'全唐诗/poet.song.74000.json','["先生骨相不封侯，卜居但得林塘幽。", "家藏蠹簡幾千卷，手校韋編三十秋。", "相知四海孰青眼，高卧一菴今白頭。", "襄陽耆舊節獨苦，只有龐公不入州。"]'),
('9690859a-a562-4431-93d9-5b5b258fba5a','和饒正叔梅花','謝逸','宋','宋诗','song-poetry','','[]','疏影橫斜月色新，肌膚清瘦不禁春。',64,'全唐诗/poet.song.74000.json','["疏影橫斜月色新，肌膚清瘦不禁春。", "侵凌臘雪寒先覺，漏洩東風信最真。", "光滉妝臺人未起，香迷野逕蝶難親。", "飄零點破蒼苔地，安得靈犀爲辟塵。"]'),
('f29a7aa3-657f-4324-9166-76ccd3cf5678','與諸人集陳公美書堂觀雪以朔雪洗盡烟嵐昏爲韵探得烟字','謝逸','宋','宋诗','song-poetry','','[]','踏雪敲門媿履穿，孟公飲我酒盈船。',64,'全唐诗/poet.song.74000.json','["踏雪敲門媿履穿，孟公飲我酒盈船。", "捲簾光動山人帳，入戶寒侵坐客氈。", "急洒江村迷靜練，深藏茅舍認孤烟。", "明年策馬長安去，誰念清吟孟浩然。"]'),
('27cb497f-6008-41c6-846a-228752b0a05b','王立之寄書言其子阿宜漸學作詩及問余稚子夢玉安否作詩奉戲','謝逸','宋','宋诗','song-poetry','','[]','求田問舍是何時，隨分生涯可樂饑。',64,'全唐诗/poet.song.74000.json','["求田問舍是何時，隨分生涯可樂饑。", "夢玉今年初學語，阿宜他日定能詩。", "兩家子弟俱無恙，一體文章是有師。", "但得耕桑了門戶，吾人不用寧馨兒。"]'),
('227a5cb8-de06-404a-a89f-4e734f5b1f0a','復用前韵寄李聲之子阿大','謝逸','宋','宋诗','song-poetry','','[]','東都曾見汝生時，客舍孤吟夜忍饑。',64,'全唐诗/poet.song.74000.json','["東都曾見汝生時，客舍孤吟夜忍饑。", "憶昨能爲鸐鵒舞，祗今應誦脊令詩。", "儻無氣節如元禮，便有功名似藥師。", "問道若知真理窟，且分餘論及吾兒。"]'),
('1e0efca0-ad9b-4079-999b-77066fd11319','寄洪駒父','謝逸','宋','宋诗','song-poetry','','[]','翼翼魯泮宮，國士媺無雙。',24,'全唐诗/poet.song.74000.json','["翼翼魯泮宮，國士媺無雙。", "行且立教化，儒風成一邦。"]'),
('c51d50c6-40af-4fbe-beb0-59d01a5d4eec','以水沈香寄呂居仁戲作六言二首  其一','謝逸','宋','宋诗','song-poetry','','[]','紙帳竹窗夜永，蒲團棐几人閒。',28,'全唐诗/poet.song.74000.json','["紙帳竹窗夜永，蒲團棐几人閒。", "萬籟聲沈沙界，一爐香裊禪關。"]'),
('c62949f4-abcf-4ef4-af41-1700d384d875','以水沈香寄呂居仁戲作六言二首  其二','謝逸','宋','宋诗','song-poetry','','[]','海上人多逐臭，水沈價不論錢。',28,'全唐诗/poet.song.74000.json','["海上人多逐臭，水沈價不論錢。", "自是渠無佛性，非關鼻孔寥天。"]'),
('b30587ee-0d38-4a1f-8ab5-b3bb3c50fbf5','題疊翠軒','謝逸','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','星落江東化梵宮，樓臺金碧駭魚龍。',32,'全唐诗/poet.song.74000.json','["星落江東化梵宮，樓臺金碧駭魚龍。", "此軒端有南康趣，只欠匡廬五老峰。"]'),
('49780bfe-e8ad-4ef0-a523-e9ab0e986f9e','聞幼槃弟歸喜而有作  其一','謝逸','宋','宋诗','song-poetry','','[]','門前楊柳未藏鴉，溪上櫻桃已著花。',32,'全唐诗/poet.song.74000.json','["門前楊柳未藏鴉，溪上櫻桃已著花。", "午夢覺來聞好語，阿連有信欲還家。"]'),
('3aafc0af-0047-443a-a9da-67c872097d1d','聞幼槃弟歸喜而有作  其二','謝逸','宋','宋诗','song-poetry','','[]','風雨多年不對床，便當携被過溪堂。',32,'全唐诗/poet.song.74000.json','["風雨多年不對床，便當携被過溪堂。", "曲肱但作吉祥卧，澆舌惟無般若湯。"]'),
('cbf6cf7b-bad3-4bba-b499-41b14096a524','春雪  其一','謝逸','宋','宋诗','song-poetry','','[]','未放溫風破柳條，先教庭樹雪花飄。',32,'全唐诗/poet.song.74000.json','["未放溫風破柳條，先教庭樹雪花飄。", "初疑乾雨從空墮，不覺香酥著地消。"]'),
('f39157c0-4861-42e7-8336-821d855f55b5','春雪  其二','謝逸','宋','宋诗','song-poetry','','[]','天公不憤小桃開，故剪瑶花伴落梅。',32,'全唐诗/poet.song.74000.json','["天公不憤小桃開，故剪瑶花伴落梅。", "後夜月明風更惡，有人無語獨登臺。"]'),
('285eb167-4f0f-485e-bb58-b0bcd2cd487f','梅六首  其一','謝逸','宋','宋诗','song-poetry','','[]','羅浮山下月紛紛，曾共蘇仙醉一樽。',32,'全唐诗/poet.song.74000.json','["羅浮山下月紛紛，曾共蘇仙醉一樽。", "不是玉妃來墮世，夢中底事見冰魂。"]'),
('23d53c29-d62e-4bda-8a09-7417ce9fc718','梅六首  其二','謝逸','宋','宋诗','song-poetry','','[]','城中桃李休相笑，林下清風汝未知。',32,'全唐诗/poet.song.74000.json','["城中桃李休相笑，林下清風汝未知。", "本是前村深處物，竹籬茅舍却相宜。"]'),
('87f42bc3-6066-40fd-b20b-ea095edb2e9c','梅六首  其三','謝逸','宋','宋诗','song-poetry','','[]','鏤冰疊雪鬭清盈，莫笑肌膚太瘦生。',32,'全唐诗/poet.song.74000.json','["鏤冰疊雪鬭清盈，莫笑肌膚太瘦生。", "底事狂風催結子，要當煮酒趁清明。"]'),
('58462f0e-2292-4c56-ae84-f106f4b7ac4d','梅六首  其四','謝逸','宋','宋诗','song-poetry','','[]','暗香疏影渾無頼，雨打風吹更可憐。',32,'全唐诗/poet.song.74000.json','["暗香疏影渾無頼，雨打風吹更可憐。", "嚼蕊但能供我醉，點妝應是爲君妍。"]'),
('1a99deeb-3d96-4300-8dde-ffdfdbe7ff67','梅六首  其五','謝逸','宋','宋诗','song-poetry','','[]','楊花榆莢風流淺，穠李夭桃氣味凡。',32,'全唐诗/poet.song.74000.json','["楊花榆莢風流淺，穠李夭桃氣味凡。", "只有寒香無俗韵，不煩吹笛惱摻摻。"]'),
('35fd368f-9862-4107-b337-b7e413d50ff0','梅六首  其六','謝逸','宋','宋诗','song-poetry','','[]','老大無人伴我閒，憶梅幽意頗相關。',32,'全唐诗/poet.song.74000.json','["老大無人伴我閒，憶梅幽意頗相關。", "不如移植溪堂後，免使凡夫俗手攀。"]'),
('624337e0-8334-498a-aa8d-033d25838b54','戲題百葉梅花','謝逸','宋','宋诗','song-poetry','','[]','細朵斜枝惱意香，月明疏影媚橫塘。',32,'全唐诗/poet.song.74000.json','["細朵斜枝惱意香，月明疏影媚橫塘。", "懸知不結青青子，故作無情淡淡妝。"]'),
('c498dd3c-a130-45d9-b7d6-b9525d0e60d7','春詞  其一','謝逸','宋','宋诗','song-poetry','','[]','蒲芽荇带遶清池，錦纜牽船水拍堤。',32,'全唐诗/poet.song.74000.json','["蒲芽荇带遶清池，錦纜牽船水拍堤。", "好是淡烟疏雨裏，遠峰青處子規啼。"]'),
('11bb1d47-826d-458c-93ac-a3a73ca9d39a','春詞  其二','謝逸','宋','宋诗','song-poetry','','[]','午睡醒來炷晚香，麝煤冉冉襲衣裳。',32,'全唐诗/poet.song.74000.json','["午睡醒來炷晚香，麝煤冉冉襲衣裳。", "垂楊莫道無才思，故遣飛花入洞房。"]'),
('528111a6-eeed-42fc-ab4e-e053717025de','春詞  其三','謝逸','宋','宋诗','song-poetry','','[]','曲欄干外柳垂垂，羅幕風輕燕子飛。',32,'全唐诗/poet.song.74000.json','["曲欄干外柳垂垂，羅幕風輕燕子飛。", "獨倚危樓思往事，落紅撩亂點春衣。"]'),
('93fe5459-ce15-442d-9739-3f7761302f41','春詞  其四','謝逸','宋','宋诗','song-poetry','','[]','荳蔻梢頭春事休，風飄萬點只供愁。',32,'全唐诗/poet.song.74000.json','["荳蔻梢頭春事休，風飄萬點只供愁。", "杜鵑啼破三更月，夢繞雲間百尺樓。"]'),
('5a816f4e-f7f1-41d0-9e73-e36947edc2e3','春詞  其五','謝逸','宋','宋诗','song-poetry','','[]','院落簾垂春日長，嫩晴天氣牡丹香。',32,'全唐诗/poet.song.74000.json','["院落簾垂春日長，嫩晴天氣牡丹香。", "細看玉面天然白，不及姚家宮樣黄。"]'),
