('4026eb13-7c59-454e-8f2c-198d66d961ca','郊行即事','謝逸','宋','宋诗','song-poetry','','[]','碧浪鱗鱗淺見沙，丹楓林裏兩三家。',32,'全唐诗/poet.song.74000.json','["碧浪鱗鱗淺見沙，丹楓林裏兩三家。", "舟橫渡口漁翁醉，夢覺西江蘆荻花。"]'),
('6d9a2d07-4425-47ec-b922-d691813a5a89','正覺寺','謝逸','宋','宋诗','song-poetry','','[]','避暑訪禪客，頃作城南遨。',132,'全唐诗/poet.song.74000.json','["避暑訪禪客，頃作城南遨。", "秋風颯然來，草木鳴蕭騷。", "復起水東興，兩槳摇輕舫。", "何處可盤礴，有寺臨江皋。", "門戶頗幽邃，野徑深蓬蒿。", "升堂脫冠坐，洗盞傾濁醪。", "初筵談名理，清言洗塵勞。", "徐徐雜詼諧，坦率真吾曹。", "尚餘清凈業，詩成漫揮毫。", "人生一瞬間，逝水行滔滔。", "歸與不秉燭，樓頭霜月高。"]'),
('670756d8-d8aa-4634-816d-5ca2ae14af4e','明水寺','謝逸','宋','宋诗','song-poetry','','[]','城西三十里，山林深且杳。',264,'全唐诗/poet.song.74000.json','["城西三十里，山林深且杳。", "群峰如連環，緣崖一徑小。", "土潤禾稼重，地僻居民少。", "老桂聳亭亭，喬松高矯矯。", "幽露泣溪毛，清風摇綠篠。", "朝來爽氣浮，輕烟橫木杪。", "日暖天清明，野雉鳴有鷕。", "石澗嗽寒泉，泠泠瀉幽沼。", "嵯峨雙石門，屢經樵火燎。", "祇園煥觚稜，十雉周牆繚。", "掃地炷妙香，房櫳深窈窕。", "嗟予嶔崎人，平生百憂擾。", "好古嗜簡編，僻性樂魚鳥。", "每逢山水佳，耳聽眸子瞭。", "况同佳士遊，意氣溢雲表。", "望遠視眈眈，臨危憂悄悄。", "險韵吟競病，怪語作危了。", "華鯨吼脩廊，僧窗曙迷曉。", "炊黍饌來牟，土芝雜荓蓼。", "他時子來歸，伐木芟蘿蔦。", "考室山之陽，高明遠隘湫。", "第恐戀君恩，紫禁烟花繞。"]'),
('40859608-7e94-44c7-a640-b66232daa21b','北津渡','謝逸','宋','宋诗','song-poetry','','[]','竹籬茅舍掩柴扉，衰草寒烟野徑迷。',32,'全唐诗/poet.song.74000.json','["竹籬茅舍掩柴扉，衰草寒烟野徑迷。", "只有白鷗無俗韵，何年相伴老清溪。"]'),
('a60deda6-b27d-44c1-8fe2-b56f03bef631','閨恨','謝逸','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','汲井浣我衣，伐石固我墉。',72,'全唐诗/poet.song.74000.json','["汲井浣我衣，伐石固我墉。", "塵埃不被體，絕無人跡通。", "洋洋西江水，我車不敢渡。", "夙駕豈不早，早行畏多露。", "行止既有義，離合亦有時。", "衆人豈無心，不如我所止。"]'),
('410c6763-b619-44b0-ad9b-2f04e05dc665','鐵柱觀','謝逸','宋','宋诗','song-poetry','','[]','豫章城南老子宮，階前一柱立積鐵。',112,'全唐诗/poet.song.74000.json','["豫章城南老子宮，階前一柱立積鐵。", "云是旌陽役萬鬼，夜半舁來老蛟穴。", "插定三江不沸騰，切勿摇撼乾坤裂。", "蒼苔包裹鱗皴皮，我欲摩挲手屢掣。", "旌陽挈家上天去，只留千夫應門戶。", "西山高處風露寒，茲事恍惚從誰語。", "安得猛士若朱亥，袖往南山擊猛虎。"]'),
('c7a907ed-9768-453b-b0d0-cc6318618419','絕句','謝逸','宋','宋诗','song-poetry','','[]','弄晴數點梨梢雨，門外畫橋寒食路。',32,'全唐诗/poet.song.74000.json','["弄晴數點梨梢雨，門外畫橋寒食路。", "杜鵑飛破草間烟，蝴蝶惹殘花底霧。"]'),
('2edb2bf4-aad3-4bde-bd47-ae93a88bd4d5','桂花  其一','謝逸','宋','宋诗','song-poetry','','[]','白雪凝酥點額黄，薔薇清露濕衣裳。',32,'全唐诗/poet.song.74000.json','["白雪凝酥點額黄，薔薇清露濕衣裳。", "西風掃盡狂蜂蝶，獨伴天邊桂子香。"]'),
('8da22c4f-b8aa-45e9-8900-6e1e52ae7be5','桂花  其二','謝逸','宋','宋诗','song-poetry','','[]','輕薄西風未辦霜，夜揉黄雪作秋光。',32,'全唐诗/poet.song.74000.json','["輕薄西風未辦霜，夜揉黄雪作秋光。", "吹殘六出猶餘四，正似天花更著香。"]'),
('3d13e0fb-42ab-4bfe-9687-4272db4e91ec','秋','謝逸','宋','宋诗','song-poetry','','[]','異鄉寒覺早，故國信來稀。',24,'全唐诗/poet.song.74000.json','["異鄉寒覺早，故國信來稀。", "秋風江上望，一雁正南飛。"]'),
('8b5c3041-9d8d-4e28-8b5b-84eaf1ea9238','梅  其一','謝逸','宋','宋诗','song-poetry','','[]','老杜騎馿入草堂，獨憐江路野梅香。',32,'全唐诗/poet.song.74000.json','["老杜騎馿入草堂，獨憐江路野梅香。", "定知深院黄昏後，疏影橫斜更斷腸。"]'),
('b3748ec5-8835-4f13-a4f1-ffde159b865e','梅  其二','謝逸','宋','宋诗','song-poetry','','[]','瓊酥滴滴綴斜枝，想見香心未吐時。',32,'全唐诗/poet.song.74000.json','["瓊酥滴滴綴斜枝，想見香心未吐時。", "但有仙人殷七七，從教橫笛月中吹。"]'),
('d75c4c91-dd6a-4ab3-b66b-aa329bbb28b0','琴','謝逸','宋','宋诗','song-poetry','','[]','風撼絲桐带月明，羽人乘醉截秋聲。',64,'全唐诗/poet.song.74000.json','["風撼絲桐带月明，羽人乘醉截秋聲。", "七弦妙製饒仙品，二尺良材稱道情。", "池小未開春浪泛，岳低猶欠暮雲生。", "何妨乞與元中術，臨化無妨膝上橫。"]'),
('4425ea14-03a9-408f-ac0e-a176256eee30','右軍墨池','謝逸','宋','宋诗','song-poetry','','[]','張芝學書池水黑，章草如芝古無敵。',198,'全唐诗/poet.song.74000.json','["張芝學書池水黑，章草如芝古無敵。", "右軍睥睨難抗行，恨不臨池作書癖。", "云何汝水之上崔嵬峰，到今方池有遺墨。", "此事不特古老傳，往往故事書簡冊。", "南豐先生欣得之，手揮巨筆飛霹靂。", "云是逸少徜徉山水間，筆墨淋漓此其迹。", "嗚呼勝事妙入神，千年尺水清粼粼。", "有時水面浮墨過，紛紛郁郁非烟雲。", "我書敧傾不成字，秋雁斜行落窗紙。", "印泥沙法安可傳，獨撫餘蹤玩清泚。", "但當一日書一箱，筆蹤或在子欽行。", "他年若榜凌雲殿，定不懸橙白頭如仲將。"]'),
('398bce51-4c87-4774-a3a3-3d85d5a8a7c0','蝴蝶','謝逸','宋','宋诗','song-poetry','','[]','粉翅雙翻大有情，海棠庭院往來輕。',32,'全唐诗/poet.song.74000.json','["粉翅雙翻大有情，海棠庭院往來輕。", "當時只羨滕王巧，一段風流畫不成。"]'),
('f4bf78fc-0a7b-4145-bcbf-89a5ad800c5c','墨梅  其一','謝逸','宋','宋诗','song-poetry','','[]','朝見一枝吐，暮吟疏影寒。',24,'全唐诗/poet.song.74000.json','["朝見一枝吐，暮吟疏影寒。", "亭亭不解語，助我青毫端。"]'),
('bb760647-09a4-4663-a95b-4a2779ed9356','墨梅  其二','謝逸','宋','宋诗','song-poetry','','[]','毫端直似林逋鬼，千年萬年作知己。',32,'全唐诗/poet.song.74000.json','["毫端直似林逋鬼，千年萬年作知己。", "孤山憶有詠殘枝，洗盡鉛華對寒水。"]'),
('75c79bdc-229d-4ab4-9a72-3e366aadc08a','就陳仲邦乞菊','謝逸','宋','宋诗','song-poetry','','[]','芙蓉狼藉拒霜殘，只有黄花巧耐寒。',32,'全唐诗/poet.song.74000.json','["芙蓉狼藉拒霜殘，只有黄花巧耐寒。", "盈把已供陶令醉，落英分與屈原餐。"]'),
('41086e73-54f9-49c9-86b2-8b4aada6526a','彩烟山','謝逸','宋','宋诗','song-poetry','','[]','吾聞沃洲天姥間，又有彩烟之高山。',80,'全唐诗/poet.song.74000.json','["吾聞沃洲天姥間，又有彩烟之高山。", "山上之岡三十里，平視天姥浮青鬟。", "其中隠者吾所羨，身世長與浮雲閒。", "種朮可療九州疾，種稻自給千家餐。", "橘柑棗栗與桑柘，種者不少資者繁。"]'),
('f89c722e-17b7-4c74-ac4f-e80ebf00d9a1','句  其一','謝逸','宋','宋诗','song-poetry','','[]','貪夫蟻旋磨，冷官魚上竿。',12,'全唐诗/poet.song.74000.json','["貪夫蟻旋磨，冷官魚上竿。"]'),
('968d3910-9796-42e8-906d-a1d272976334','句  其二','謝逸','宋','宋诗','song-poetry','','[]','典刑尚可窺前輩，頼有徐洪在豫章。',16,'全唐诗/poet.song.74000.json','["典刑尚可窺前輩，頼有徐洪在豫章。"]'),
('3f7ee968-b53c-41b8-b248-124349872d00','句  其三','謝逸','宋','宋诗','song-poetry','','[]','山寒石髮瘦，水落溪毛彫。',12,'全唐诗/poet.song.74000.json','["山寒石髮瘦，水落溪毛彫。"]'),
('c0f7e556-2b22-4fa5-aee7-54660fb096d1','句  其四','謝逸','宋','宋诗','song-poetry','','[]','細雨來時麋角解，春風歸去馬蹄香。',16,'全唐诗/poet.song.74000.json','["細雨來時麋角解，春風歸去馬蹄香。"]'),
('65073d0e-23fb-4952-907a-b87d8fb22df3','句  其五','謝逸','宋','宋诗','song-poetry','','[]','蕭蕭白露催黄落，剪剪凉飆瘦碧鮮。',16,'全唐诗/poet.song.74000.json','["蕭蕭白露催黄落，剪剪凉飆瘦碧鮮。"]'),
('c1a4cf6c-341b-4038-a695-c104fa162925','句  其六','謝逸','宋','宋诗','song-poetry','','[]','百葉梅梢拂掠黄，風摇雨練亦凄凉。',16,'全唐诗/poet.song.74000.json','["百葉梅梢拂掠黄，風摇雨練亦凄凉。"]'),
('de7c8a7e-a191-4488-ba3d-69427b86787b','句  其七','謝逸','宋','宋诗','song-poetry','','[]','未於蓮社添宗衲，已向蘭亭識道林。',16,'全唐诗/poet.song.74000.json','["未於蓮社添宗衲，已向蘭亭識道林。"]'),
('cd413d6c-72b4-4aa0-b071-1910b2445e70','句  其八','謝逸','宋','宋诗','song-poetry','','[]','千點落花亂春思，杜宇一聲生客愁。',16,'全唐诗/poet.song.74000.json','["千點落花亂春思，杜宇一聲生客愁。"]'),
('b8ee9f8a-0571-4437-99d1-9028464d998d','句  其九','謝逸','宋','宋诗','song-poetry','','[]','狂隨柳絮有時見，舞入梨花何處尋。',16,'全唐诗/poet.song.74000.json','["狂隨柳絮有時見，舞入梨花何處尋。"]'),
('331dd848-4051-46cf-a749-46969b51bbae','句  其一○','謝逸','宋','宋诗','song-poetry','','[]','江天春晚暖風細，相逐賣花人過橋。',16,'全唐诗/poet.song.74000.json','["江天春晚暖風細，相逐賣花人過橋。"]'),
('1b915563-7a05-4d09-802f-210334a963cd','句  其一一','謝逸','宋','宋诗','song-poetry','','[]','少陵苦被詩相惱。',8,'全唐诗/poet.song.74000.json','["少陵苦被詩相惱。"]'),
('bf152e8a-16db-43c1-9859-7d7f099f8a17','句  其一二','謝逸','宋','宋诗','song-poetry','','[]','姚黄魏紫莫相猜。',8,'全唐诗/poet.song.74000.json','["姚黄魏紫莫相猜。"]'),
('6daf5c26-34f0-41f9-8276-77f97e42afb8','句  其一三','謝逸','宋','宋诗','song-poetry','','[]','身似何郎全傅粉，心同韓壽暗偷香。',16,'全唐诗/poet.song.74000.json','["身似何郎全傅粉，心同韓壽暗偷香。"]'),
('36b490ca-a80f-48b1-9beb-aa53364eadd4','句  其一四','謝逸','宋','宋诗','song-poetry','','[]','獨吟高閣對官梅。',8,'全唐诗/poet.song.74000.json','["獨吟高閣對官梅。"]'),
('b1d7fc05-1269-4c25-99ab-fa1e5e81b60c','句  其一五','謝逸','宋','宋诗','song-poetry','','[]','露冷霜乾玉骨寒。',8,'全唐诗/poet.song.74000.json','["露冷霜乾玉骨寒。"]'),
('3bfcf8a5-9658-403a-807c-00c0ef829627','喜晴','趙鼎臣','宋','宋诗','song-poetry','','[]','我田既臧，零雨其濛。',80,'全唐诗/poet.song.74000.json','["我田既臧，零雨其濛。", "嗟我農夫，憂心沖沖。", "穀旦於差，薄言往愬。", "謂天蓋高，上帝臨汝。", "杲杲出日，有嘒其星。", "穫之挃挃，我倉既盈。", "薄采其芹，于彼行潦。", "神之聽之，無德不報。"]'),
('0ed424ac-f575-4c14-9667-aa76a8dd347a','昔我往矣思君子也高陽之從事過瀛之野作河廣詩而匿其名使者唐侯獨見而知之故賦是詩','趙鼎臣','宋','宋诗','song-poetry','','[]','昔我往矣，作爲此詩。',160,'全唐诗/poet.song.74000.json','["昔我往矣，作爲此詩。", "凡百君子，諒不我知。", "惟彼碩人，眷眷懷顧。", "彼何人斯，可與晤語。", "召彼故老，周爰咨詢。", "予忖度之，所謂伊人。", "實獲我心，將恐將懼。", "顔如渥丹，畏此譴怒。", "維彼碩人，顧我則笑。", "如切如磋，匪怒伊教。", "自古在昔，哀鳴嗸嗸。", "褎如充耳，莫我肯勞。", "嗟我農夫，出自幽谷。", "如蜩如螗，其何能淑。", "維彼碩人，追琢其章。", "欲報之德，不可弭忘。"]'),
('e93d6f8c-d2ce-447b-b94c-0bcd50c8d5cf','宣和四年五月辛亥詔以神宗皇帝所書鼎說十二字藏於延英閣臣鼎臣賦詩以紀其事','趙鼎臣','宋','宋诗','song-poetry','','[]','孤臣生苦晚，僅及熙寧初。',204,'全唐诗/poet.song.74000.json','["孤臣生苦晚，僅及熙寧初。", "雖霑化育恩，不睹衣冠餘。", "嗚呼丕顯哉，謨訓存諸書。", "議論略秦漢，制作追唐虞。", "每聞父老言，太息涕淚濡。", "不意垂老年，觀此河出圖。", "禹鼎淪泗水，異說紛相誣。", "蔽之十二言，一洗諸儒迂。", "天意蓋若曰，世定後聖無。", "要當纘禹功，千載與之俱。", "各力所未遑，翼子其付諸。", "崇寧果圖功，繼志若合符。", "屹然奠九鼎，四海安覆盂。", "此書天所錫，制器實權輿。", "巖巖寶閣尊，萬靈所依於。", "嗟爾九州民，跂行與蹶趨。", "瞻之必稽首，過者當下車。"]'),
('2c0a5816-4f82-43ee-ba37-968517710b67','余少時嘗種竹於所居之南號竹隠今二十年矣而隠之志蓋未遂也孫志康善篆嘗欲得竹隠二字題其上因敘所以爲詩以乞之且呈好事諸君子各乞一詩以爲舊隠光華','趙鼎臣','宋','宋诗','song-poetry','','[]','先君昔謝事，勇退不待年。',276,'全唐诗/poet.song.74000.json','["先君昔謝事，勇退不待年。", "區中五畝宅，郭外二頃田。", "歸裝無一金，買書費萬錢。", "余時老萊衣，方冠絕可憐。", "賜第殿東廂，棄官天北邊。", "耕耘具甘旨，采掇求蘭荃。", "積竹南牆下，清陰頗蕭然。", "謂此可隠矣，曰余其老焉。", "人事喜齟齬，壯志誠遷延。", "身遭患難餘，仕爲饑凍牽。", "浮舟客江湖，仗劍臨幽燕。", "兒女道路長，歲月鞍馬捐。", "一與故隠別，逮此成華顛。", "傳聞籜龍兒，一一長刺天。", "出處令人悲，太息夜不眠。", "同舍有孫楚，筆勢何翩翩。", "未甘丞相後，不許中郎前。", "何以慰此君，丐子翰墨妍。", "持歸榜吾隠，不翅青玉鎸。", "異時儻過我，物色揚雄廛。", "貧家何所有，滿林玉碧鮮。", "渭川已太廣，淇澳空自賢。", "君看青琅玕，知我非臞仙。"]'),
('2a2d8fe0-2f10-4c76-8337-4b67d0af2733','次韵滕子濟禮部考古圖','趙鼎臣','宋','宋诗','song-poetry','','[]','蒼史失古法，赤刀有遺書。',240,'全唐诗/poet.song.74000.json','["蒼史失古法，赤刀有遺書。", "經毀秦漢後，器追禹夏初。", "古人不吾接，有感誰與袪。", "尚憐盲左生，文字記魯壺。", "哀哉泗水沒，不復知鬼魖。", "英英華省郎，攟摭收遺餘。", "異書人不識，善本手自摸。", "壁中發科斗，海底出珊瑚。", "篆籀既識職，鐘鼎各應圖。", "要當知百世，何止舉一隅。", "似逢東里生，張華與之俱。", "談傾河海江，下卷鄭白渠。", "我老塵埃中，牒訴慘不舒。", "思陪種柳潛，願逐耦耕沮。", "錦囊不應開，欲和聊復徐。", "頗憐平生心，用意真僻儒。", "識字恨不博，塊焉無與虞。", "圖書許借否，髯滕意何如。", "莫作驪龍仙，靳吝五色珠。", "鴟夷或未辦，當奉酒一盂。"]'),
('5145be3f-9cf3-403d-b39b-15e483aa57d4','讀史戲作','趙鼎臣','宋','宋诗','song-poetry','','[]','相如故倦遊，偃蹇臨邛市。',120,'全唐诗/poet.song.74000.json','["相如故倦遊，偃蹇臨邛市。", "主人敬嘉賓，供具邀車騎。", "酒酣樂未闌，跪進絲桐戲。", "勉鼓一再行，四坐皆心醉。", "潛有知音人，獨會求凰意。", "傾城不待媒，半夜行雲至。", "忽駕軟輪車，遂拋沽酒肆。", "建節還故鄉，拜爵文園吏。", "衛霍老疆埸，嚴朱死謀議。", "摇頭喚不前，日高花裏睡。"]'),
('305d10ea-7f97-49b8-ae0c-3d47b75a9a09','即事','趙鼎臣','宋','宋诗','song-poetry','','[]','昔日同門生，頍弁彯華纓。',72,'全唐诗/poet.song.74000.json','["昔日同門生，頍弁彯華纓。", "當年總角彥，束带揚王庭。", "故人憐我頑，千里特寄聲。", "開緘亦何言，終篇歌鹿鳴。", "舉手謝友人，愧君鄭重情。", "鵬鷃各有適，枉尋余所輕。"]'),
('12ff753d-3d21-4836-be3a-f6191aee32fa','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','久伏東海濱，竊慕暴公子。',48,'全唐诗/poet.song.74000.json','["久伏東海濱，竊慕暴公子。", "一朝乃吾僚，幸會有如此。", "白髮裹青衫，誰要相料理。", "吾猶及老成，餘音聞正始。"]'),
('70e1f148-2280-40ec-9552-c5d371c7a067','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','仕官百僚底，文章兩漢間。',48,'全唐诗/poet.song.74000.json','["仕官百僚底，文章兩漢間。", "著書雖寂寞，此生那可攀。", "結交論意氣，恨別阻河山。", "屢過揚雄宅，令人載酒還。"]'),
('4d9ae71a-122a-406d-ae13-aaa1aea29b9c','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其三','趙鼎臣','宋','宋诗','song-poetry','','[]','霍侯塵土中，衣破露兩肘。',48,'全唐诗/poet.song.74000.json','["霍侯塵土中，衣破露兩肘。", "一錐聊自置，四壁初何有。", "長安可得官，高門日奔走。", "問君求之歟，顧我摇其首。"]'),
('ee98e182-8e82-4adc-bfc3-e4e7a4f81257','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其四','趙鼎臣','宋','宋诗','song-poetry','','[]','翰林門戶壯，九子賢至今。',48,'全唐诗/poet.song.74000.json','["翰林門戶壯，九子賢至今。", "楩楠及豫章，磊落皆成林。", "恨不徧識之，此郎傾蓋深。", "儻封降胡檄，冀子披其襟。"]'),
('9481f913-d3c0-4d78-9242-b6c25454b7d1','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其五','趙鼎臣','宋','宋诗','song-poetry','','[]','形骸本蘧廬，况乃妻子累。',48,'全唐诗/poet.song.74000.json','["形骸本蘧廬，况乃妻子累。", "朝市無恬波，山林有深意。", "可憐箕山孫，骨體真不媚。", "歸歟定何時，寄我招隠字。"]'),
('56b32cfd-37c3-4fce-b493-bd3920707869','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其六','趙鼎臣','宋','宋诗','song-poetry','','[]','髯也伏鹽車，乃實千里足。',48,'全唐诗/poet.song.74000.json','["髯也伏鹽車，乃實千里足。", "其學本孔孟，亂以佛所錄。", "捕景而繫風，雖辯吾不欲。", "如髯真絕倫，恨此持論曲。"]'),
('677d26de-d16c-4530-bded-03fceccd50ab','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其七','趙鼎臣','宋','宋诗','song-poetry','','[]','詞源傾江河，坐覺畎澮褊。',48,'全唐诗/poet.song.74000.json','["詞源傾江河，坐覺畎澮褊。", "王郎清如水，腹有談天辯。", "閉置邱壑中，名譽當自顯。", "而况金其聲，行矣侍從選。"]'),
('4118f9da-816a-4291-ba0a-99387f03682d','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其八','趙鼎臣','宋','宋诗','song-poetry','','[]','俗儒守一編，賤目則貴耳。',48,'全唐诗/poet.song.74000.json','["俗儒守一編，賤目則貴耳。", "不識古人書，豈識天下士。", "君看李長吉，可但州縣已。", "異時鳳來儀，故自阿閣起。"]'),
('1b6837dc-e727-4a0d-83c3-4dceda61f824','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其九','趙鼎臣','宋','宋诗','song-poetry','','[]','濟濟八才子，醖藉有此郎。',48,'全唐诗/poet.song.74000.json','["濟濟八才子，醖藉有此郎。", "交情苦疏豁，子職甚溫良。", "一爲江南行，書疏頗相忘。", "媚婦乃如許，盈盈不下堂。"]'),
('255ff605-020b-41bc-9caa-178b5f5f0965','楊時可作十詩以寄河間詩之所及非吾僚則吾友也因悉次其韵以和之又以其所以贈我者復贈時可作還字韵  其一○','趙鼎臣','宋','宋诗','song-poetry','','[]','參軍喜吏事，咄嗟能輊軒。',48,'全唐诗/poet.song.74000.json','["參軍喜吏事，咄嗟能輊軒。", "短小精悍姿，使人醒睡魂。", "他年解千牛，妙絕難寄言。", "堂堂聖獻肅，吾猶識諸孫。"]'),
('27880e50-1cb4-4354-950f-962445f393be','次韵志康病起','趙鼎臣','宋','宋诗','song-poetry','','[]','八十用鷹揚，萬里封燕頷。',144,'全唐诗/poet.song.74000.json','["八十用鷹揚，萬里封燕頷。", "一擲遂成盧，再索僅得坎。", "命也天所司，欲言吾不敢。", "不見孫先生，有羹長不糝。", "何曾少卑之，坐是得坎窞。", "平生讀書苦，求味在橄欖。", "凜然剛毅姿，身大不及膽。", "滿堂進羶葷，長跪出昌歜。", "嗜好苦乖殊，持此欲誰覽。", "貽我病起詩，慨歎發悲感。", "君看彼棼絲，見用即衡紞。", "得失付天公，吾屬可無憾。"]'),
('2ad9ed16-6df8-4a65-a03a-676f01f2ca37','病目無聊因遊慈雲寺作詩呈諸友','趙鼎臣','宋','宋诗','song-poetry','','[]','造物本兒嬉，萬彙同一甑。',156,'全唐诗/poet.song.74000.json','["造物本兒嬉，萬彙同一甑。", "陰陽燒煮之，有此生老病。", "我今知命年，過二不爲盛。", "此身付天公，窮達聽其令。", "胡爲生纖雲，翳此秋月浄。", "坐令盲老翁，悲嘯雜歌詠。", "醫云肝乘母，交惡若周鄭。", "欲知罍不耻，要在瓶毋罄。", "至言若金篦，刮膜除蔽映。", "咄哉耕田夫，所得已負乘。", "當求揚一廛，遂卜蔣三徑。", "閉目存黄庭，燕坐收雙脛。", "回首謝蓬萊，問路安敢更。"]'),
('e16ce862-9935-4fbe-a87e-cdf2aa598834','次韵杜公美贈張永錫','趙鼎臣','宋','宋诗','song-poetry','','[]','平生喜交遊，臭味在筆墨。',72,'全唐诗/poet.song.74000.json','["平生喜交遊，臭味在筆墨。", "身居大梁下，家寄黄河北。", "異哉長安市，一日見雙璧。", "相逢塵埃中，過眼我獨識。", "從今裋褐姿，不復憔悴色。", "更復許言詩，賜也當避席。"]'),
('c6db9b40-e568-4ee1-936f-7c1c79e13b6f','李漢老見過不及見以詩謝之','趙鼎臣','宋','宋诗','song-poetry','','[]','埋沒簿領中，氣結不得吐。',156,'全唐诗/poet.song.74000.json','["埋沒簿領中，氣結不得吐。", "官柳欲飛花，春事遽如許。", "騎馬出東城，意若鴻鵠舉。", "獨行雖少味，自足寬靡盬。", "歸來兒女曹，怪事說覶縷。", "有客適過翁，身騎五色羽。", "自非翱瀛洲，恐是翔紫府。", "雲來久躊躇，鶴去迷處所。", "我老俗吏中，人物誰比數。", "頼獨有故人，慰藉能傴俯。", "一臂乃失之，遇事真齟齬。", "朝來益癡絕，物色徧庭宇。", "尚尋履迹餘，用意毋乃魯。"]'),
('6aab338e-6cd6-4ec7-b666-dc44b5cb1008','郡僚出塘濼唱和詩次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','水窮瘴海南，陸盡狼胥北。',204,'全唐诗/poet.song.74000.json','["水窮瘴海南，陸盡狼胥北。", "祖宗受之天，以爲冠带國。", "維時耶律氏，好亂樂禍賊。", "夜動鼠穴中，陰計屢以默。", "廷臣請加兵，薄伐陳往則。", "堯舜仁如天，一言羣議塞。", "幽燕亦吾民，此意多不識。", "至信及豚魚，深恩被動植。", "古來戰場地，父老今力穡。", "耘夏水泱泱，穫秋禾翼翼。", "當年守邊將，至今猶血食。", "烏虖戰危事，勝敗有失得。", "祖宗諱言兵，陰功千萬億。", "不見陂塘上，溝塍如組織。", "傳聞天驕兒，頗亦知帝力。", "祖孫相付授，日夜自約勒。", "慎勿負中原，天地父母德。"]'),
('37700527-25d7-471a-9dad-b29e4c37f563','秉之兄受代還京師余送行次甘陵雨三晝夜不止十二日乃雪平地幾尺木壓而折者十三四十五日既別秉之於南郭賦其事以寄王履道王時在大名','趙鼎臣','宋','宋诗','song-poetry','','[]','季秋霜未降，草木尚華滋。',192,'全唐诗/poet.song.74000.json','["季秋霜未降，草木尚華滋。", "蕭索重陽雨，黄菊共凄其。", "謂此膚寸澤，杲杲行復晞。", "那知三日霖，淫潦方在茲。", "我行既齟齬，我車遂逶遲。", "僧房耿不眠，半夜寒侵扉。", "開門怪事發，積雪滿前墀。", "雨師技止此，更復出新奇。", "兒童叫踴躍，僮僕驚嗟咨。", "云此太早計，有眼省見稀。", "天公豈怪我，不樂愁何爲。", "幻此千頃玉，伸我一寸眉。", "呼兒覓酒家，典衣具醇醨。", "醉中見鄉社，命駕將言歸。", "忽憶剡溪友，徑吟招隠詩。", "嗟余興豈盡，無因謁戴逵。"]'),
('54d7db07-52a3-432d-a56c-324bea32127d','送李侗誘中將漕江東','趙鼎臣','宋','宋诗','song-poetry','','[]','顔駟老爲郎，三世終不遇。',156,'全唐诗/poet.song.74000.json','["顔駟老爲郎，三世終不遇。", "奉春脫輓輅，暫見若平素。", "功名豈不佳，用舍真有數。", "况逢堯舜朝，士多無著處。", "赫赫金門開，燕子皆鵷鷺。", "天顔若春溫，戰栗心恐怖。", "奏事幸無他，求福安敢預。", "李侯衡湘來，朝謁苦未屢。", "入對明光宮，爽氣回天顧。", "立持使者節，褒語宣朝路。", "自結明主知，千載實旦暮。", "富貴在子耳，江南那久住。", "努力加飯餐，穩上青雲去。"]'),
('9b50d6e8-22ed-483e-baf7-89c5c619b793','送唐通叟東南鑄錢通叟嘗攝度支員外郎職事與之同舍累月','趙鼎臣','宋','宋诗','song-poetry','','[]','簿領丘山堆，胥吏鳬鶩進。',180,'全唐诗/poet.song.74000.json','["簿領丘山堆，胥吏鳬鶩進。", "不須持酒巵，正自得醉困。", "頼逢同舍郎，照眼珠璧潤。", "堂堂質肅公，勁節森萬仞。", "吾猶識諸孫，王謝有孤韵。", "時時議論餘，尚作前輩峻。", "我老無町畦，出口見方寸。", "端須護疵瑕，未可失瑜瑾。", "奈何不少留，舟楫犯蛟蜃。", "山澤寶欲興，虞衡職方振。", "想常開鴻鑪，不復費游刃。", "明年水衡錢，地應無可頓。", "策勳便封侯，朱紫安足論。", "來趨未央朝，故人應許認。", "疾走當避公，銅臭不可近。"]'),
('d946139f-bc39-4a81-a766-8c902cc6f2d9','次韵李蕭遠送葉少協赴官陳州','趙鼎臣','宋','宋诗','song-poetry','','[]','簿領動移日，塵埃紛滿城。',156,'全唐诗/poet.song.74000.json','["簿領動移日，塵埃紛滿城。", "空令牛馬走，坐見鄙吝生。", "文章雖小技，不激安能鳴。", "邂逅得之子，接語意已驚。", "談鋒苦豪放，心地實坦平。", "凜如君北斗，嘒然吾小星。", "忽聞補吏去，曾不與我評。", "長嘯登扁舟，心遠氣甚英。", "先師仲尼父，昔嘗泥此行。", "寄聲陳父老，君蓋何當傾。", "須知此客佳，館穀幸少宏。", "富貴亦土苴，名聲忌崢嶸。", "請謝郭子橫，去矣勿觥觥。"]'),
('e22d8095-614a-4384-a7df-e6fde32905c2','猶子奕赴官中山奇作詩送之因次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','人生貴天真，圭角何必露。',156,'全唐诗/poet.song.74000.json','["人生貴天真，圭角何必露。", "骯髒世雖憎，豈弟神所許。", "嗟爾守一官，十年不改故。", "兒寒屢號朝，妻饑數啼暮。", "又隨五斗米，遠向千里去。", "中山貔虎屯，北鄙咽喉據。", "我昔少年游，夢景墮飛霧。", "猶思雁塔凉，尚愛石丈主。", "迨汝閒暇時，尋我經行處。", "聊因起遐想，會自有佳趣。", "此外姑置之，勿改平生度。", "功名無巧手，富貴有夷路。", "往復版築中，時來猶舉傅。"]'),
('e6f0e6c2-8181-43ac-8897-8ae0c96788cc','猶子奇從江浙經置陳伯亨之辟八月十日登舟餞之於郊外作是詩以送之','趙鼎臣','宋','宋诗','song-poetry','','[]','于越本夷蠻，弄兵篁竹中。',204,'全唐诗/poet.song.74000.json','["于越本夷蠻，弄兵篁竹中。", "吏士懦不武，未嘗更戰攻。", "私憂顧妻子，聞賊內已訌。", "咄哉林武將，一旦先望風。", "遂令六州民，老稚遭閔凶。", "天子怒赫然，王師出羆熊。", "聊彈一指端，電滅紛已空。", "瘡痍今尚新，噍食若未充。", "如更大病餘，護視須良工。", "平生陳太邱，經濟蟠心胸。", "久持四方節，未食千戶封。", "功名真有時，倉卒果奮庸。", "嗷嗷百萬家，頼此白頭翁。", "汝今從其招，綠水依芙蓉。", "勿以賤自嫌，王事當匪躬。", "江湖日已清，公歸列夔龍。", "行持酒一篘，迎汝國門東。"]'),
('b2624e3b-25c3-43c1-bd3b-760b831c2256','送林德祖致政歸吳中','趙鼎臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','士論常苦高，出語譏古人。',180,'全唐诗/poet.song.74000.json','["士論常苦高，出語譏古人。", "至其取與間，未足了一身。", "官爵細事爾，臭腐實與鄰。", "奈何夸者徒，薄暮猶逡巡。", "平日相語此，反覆甚諄諄。", "頓輸一著先，夫子固絕倫。", "乞身夜上書，妻子不暇詢。", "翩然東南去，笑別平生親。", "江山已在眼，邱壑俄生春。", "聊須震澤水，洗此京洛塵。", "蕭條西湖上，處士迹已陳。", "夫子今繼之，凜然兩逸民。", "疏公不足高，賀老不足珍。", "他年仙骨換，坐嘆傾蓋新。", "期我吳市門，復見梅子真。"]'),
('23e52d55-6220-45f1-9cc9-fc298838531b','崔德符作湖園詩以寄邢子强次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','吏道如棼絲，坐覺意味少。',132,'全唐诗/poet.song.74000.json','["吏道如棼絲，坐覺意味少。", "我豈無一簞，當食自不飽。", "邂逅崔子真，霜林挺孤篠。", "十日九閉門，想見獨傾倒。", "悠悠四十年，識君恨不早。", "晤言曾幾何，告別驚草草。", "昨枉湖上作，盛贊池亭好。", "平生邢子才，投分紵與縞。", "政當樂濠魚，定不驚鷗鳥。", "解榻念君來，此意不待曉。", "似聞百花洲，一雨浄如掃。"]'),
('544fa39b-7fb6-41f8-9615-da7125afaded','次韵陳修仲題會稽宋尉澄暉亭','趙鼎臣','宋','宋诗','song-poetry','','[]','鑑湖繞君家，近在門前路。',108,'全唐诗/poet.song.74000.json','["鑑湖繞君家，近在門前路。", "置亭昔未善，對面無覓處。", "勝地天所儲，造物費陶鑄。", "惟昔居者誰，熟視不知措。", "會逢賞心人，卓犖見深度。", "疏朗引湖山，豁達去屏戶。", "開軒明月來，解榻清風駐。", "初無結駟勞，怪此咄嗟具。", "更得黄絹詞，當煩神物護。"]'),
('bc8143aa-6b21-4d58-ae13-2bc9731f9e47','乙未寒食前一日陪姚季一吳和甫登崇德寺閣賦詩以駕言出游以寫我憂爲韵分得我出二字  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','東風日夜狂，草木困掀簸。',120,'全唐诗/poet.song.74000.json','["東風日夜狂，草木困掀簸。", "牆角數枝紅，春事亦到我。", "平生喜追遊，雖老意尚頗。", "况逢兩飛黄，共欲參蹇跛。", "喟余麋鹿姿，章服强包裹。", "出門天宇寬，自視覺磊砢。", "士峻則少通，務達乃多可。", "悠悠何必然，所得蓋么麽。", "不如全其天，曠蕩出韁鎖。", "東皋幸可耕，太息願未果。"]'),
('c3000550-bc28-4046-9846-af1374122a83','乙未寒食前一日陪姚季一吳和甫登崇德寺閣賦詩以駕言出游以寫我憂爲韵分得我出二字  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','高閣切浮雲，仰觀勢嵂崒。',144,'全唐诗/poet.song.74000.json','["高閣切浮雲，仰觀勢嵂崒。", "興來偶攀躋，意若凌超忽。", "壯哉洛陽都，宮殿聳突兀。", "城中十萬家，古來豪俠窟。", "樓觀何軒昂，花竹爭炳蔚。", "澹澹煙靄間，俯見孤鳥沒。", "緬懷中令君，節鉞耀衮韍。", "鎮守極膏腴，割剝到肌骨。", "黄金不却老，晚節顧佞佛。", "陂陀何爲者，歲久尚奇崛。", "空令吾黨士，登踐許倉卒。", "躊躇不忍歸，待得星斗出。"]'),
('ad766d55-50a0-422d-a14b-27886488581d','五月十八日陪同舍諸友遊慈雲寺','趙鼎臣','宋','宋诗','song-poetry','','[]','室如蝸牛廬，氣若炊飯甑。',156,'全唐诗/poet.song.74000.json','["室如蝸牛廬，氣若炊飯甑。", "身無六尺長，當午意已病。", "今朝忽破顔，夥此佛宇盛。", "長廊引雄風，爽氣回秋令。", "老僧喜客來，簟竹鋪綠浄。", "書生苦易足，妙興發觴詠。", "枯棋響雷雹，新唱雜雅鄭。", "放懷百念空，縱飲雙瓶罄。", "我衰本蒹葭，玉樹紛照映。", "忽驚涉瀛洲，驟喜陪鶴乘。", "日昳尚躊躇，欲去不忍徑。", "歸來掩關卧，汗雨復流脛。", "賜沐幸許休，命駕何妨更。"]'),
('81a7006c-4f20-4db7-9e72-d526674db9fd','八月二十日晚凉可喜秋思浩然乘興獨遊至崇寧寺謁須上人表以次元聞而造焉既歸而作是詩','趙鼎臣','宋','宋诗','song-poetry','','[]','秋風日已佳，今我何不樂。',168,'全唐诗/poet.song.74000.json','["秋風日已佳，今我何不樂。", "出門念所之，興至不待約。", "言乘獨往願，偶信登山脚。", "道人心似灰，白首無住著。", "經旬不下堂，爲我躡芒屩。", "茶瓶既徐進，澗水亦屢酌。", "談從青山遠，思與孤雲薄。", "俯觀市上人，擾擾何紛泊。", "向來簿領中，豈復知寥廓。", "兩侯天下士，皎若雲間鶴。", "肯作噲等伍，此意真不惡。", "少年悅紛華，寒士守寂寞。", "譬如冰與炭，志亦言其各。", "請爲東土游，一繼支許作。"]'),
('ae9d708d-4ff3-473e-b802-c714a672168a','二十日發都門二十三日次潁昌過故府張幾仲舊居','趙鼎臣','宋','宋诗','song-poetry','','[]','入門見華屋，愴然傷我神。',156,'全唐诗/poet.song.74000.json','["入門見華屋，愴然傷我神。", "堂堂想平生，英氣猶逼人。", "園花與檻竹，種植手自親。", "愛之不忍觸，欲去輒逡巡。", "緬懷大觀初，幕府參下賓。", "前驅列貔虎，後乘邀徐陳。", "縱獵轅門曉，賦詩瀛臺春。", "何曾有天驕，安若兒女馴。", "至今帳下吏，往往驅朱輪。", "凄凉十年內，梓樹忽輪囷。", "惟餘一書記，白首走埃塵。", "猥忝刺史符，愧彼吏與民。", "公門那敢辱，往戒猶書紳。"]'),
('0e428334-b165-48b6-b2a0-7f2755fe6dd4','發潁昌留別韓次律蘇叔黨','趙鼎臣','宋','宋诗','song-poetry','','[]','行邁日久遠，親舊日已疏。',156,'全唐诗/poet.song.74000.json','["行邁日久遠，親舊日已疏。", "眼中惟牙官，從我走道途。", "俗狀誰使汝，漸赤由近朱。", "潁川多名士，古來豪俠區。", "歷代愧不能，叩門韓與蘇。", "酌我甕頭春，舞我閨中姝。", "清言發談笑，嘲戲頗不無。", "使我面輒闊，自忘官職粗。", "斐然欲從之，文字相與娛。", "我行未渠央，欲駕復躊躇。", "人生如寄耳，聚散安可圖。", "區區惜別離，此志乃非夫。", "臨風但相思，有使即寄書。"]'),
('f1e416cf-4fe5-44d7-ae1e-6f2097f3c8c9','九月八日曉起絕糧舟中讀書','趙鼎臣','宋','宋诗','song-poetry','','[]','饑腸徹夜鳴，夢亂不能好。',180,'全唐诗/poet.song.74000.json','["饑腸徹夜鳴，夢亂不能好。", "口腹故累余，勉起不待曉。", "貧家無宿糧，庖厨凈如掃。", "力耕可得食，此計真不早。", "居然懷抱惡，坐使百憂繞。", "聊復讀我書，百家觀浩渺。", "古人骨已朽，漫爛列華藻。", "其言忽起予，一覽意自了。", "颯然驚短鬢，怒立何草草。", "壯心激衰懦，豪氣變枯槁。", "捧腹故便便，不食今自飽。", "方知道義力，非但文章巧。", "吾命豈真窮，吾書可長保。", "從今復何事，讀誦以終老。", "不須哀王孫，爲謝淮陰嫗。"]'),
('87a2ad4e-5d9e-40c5-ab16-0d001db010c2','夜行見懷','趙鼎臣','宋','宋诗','song-poetry','','[]','家無儋石儲，日費千鍾飲。',120,'全唐诗/poet.song.74000.json','["家無儋石儲，日費千鍾飲。", "避謗醉爲鄉，嗜眠書作枕。", "忘機鳥已馴，有道魚不淰。", "栖遲天一涯，浪漫歲三稔。", "日月漸悠悠，肺腸空凜凜。", "平生師孔孟，夙昔陋顔沈。", "膺門感恩義，噲等荷題品。", "報德力未能，量己事已審。", "新詩辱雕鎸，浩嘆忘食寢。", "但願酒不空，何事文如錦。"]'),
('e3514171-8bf3-4bc8-bf9e-cc3ca16c5d94','贈翟二淳老','趙鼎臣','宋','宋诗','song-poetry','','[]','去鄉今幾時，未易詰晦朔。',168,'全唐诗/poet.song.74000.json','["去鄉今幾時，未易詰晦朔。", "但聞葦溪頭，稚柳皆把握。", "老豈私我哉，浸潤不頓覺。", "攬鏡忽悟渠，鬢雪頗斑駮。", "喜聞貴人來，文字得商搉。", "故人五十滿，髮黑面丹渥。", "乃知出處間，相去如許邈。", "新詩愈豪放，談笑出飛雹。", "留之不肯住，告別意苦確。", "嗟我獨何愚，斗米尚俛啄。", "詩書久遺忘，志氣日齷齪。", "詎堪剸劇繁，所願斸墝埆。", "歸田不須謀，老圃安用學。", "東皋會相從，共醉村酒濁。"]'),
('b42df6cb-4045-4b7a-ba70-0cbc0984f162','次韵李祖武道中見寄','趙鼎臣','宋','宋诗','song-poetry','','[]','江南綠水幕，塞北黄金臺。',120,'全唐诗/poet.song.74000.json','["江南綠水幕，塞北黄金臺。", "方當漢道隆，威靈暢九垓。", "從軍豈不樂，顧我非其才。", "十年塵土中，滿胸貯黄埃。", "主人恩義重，彈劍思一來。", "居官自忝冒，揣分豈邅徊。", "免識翰林孫，一見青眼開。", "不許執手版，便容持酒盃。", "題詩遠寄我，欲及未開梅。", "北枝寒已甚，正待使君回。"]'),
('dcb6a0d2-c055-4d9b-bc68-2840513fd046','方時敏以茶餉李蕭遠因作詩止茶其弟元若允迪聞之謂茶不可止和其詩復以茶二餠寄其兄三子皆余所善也時敏既止茶不當復受允迪之餉而蕭遠巍然亦不得以獨饗也故次其韵以請二子','趙鼎臣','宋','宋诗','song-poetry','','[]','得士一夔足，我獨交兩方。',168,'全唐诗/poet.song.74000.json','["得士一夔足，我獨交兩方。", "腹有書五車，家無錢一囊。", "人皆不堪憂，慍色渠未嘗。", "大馮河梁上，正作龜頭藏。", "西山挹爽氣，北窗傲羲皇。", "對茗不肯飲，醉倒溫柔鄉。", "泮宮有臞仙，野鶴姿昂昂。", "少年苦書淫，壯歲惟詩昌。", "平生重取與，一介分毫芒。", "受貺獨不辭，大啜意甚長。", "我本田間人，雖老尚木强。", "邊韶請割席，陸羽願升堂。", "破鐺雜薑鹽，煎煮我所當。", "丐子龍鳳骨，澆我藜藿腸。"]'),
('09444b79-2b42-4e66-95c8-0a3b927508c6','既和時敏止茶詩矣而允迪所餉猶未及請再次韵求之','趙鼎臣','宋','宋诗','song-poetry','','[]','鉤繩異曲直，鑿枘殊圓方。',168,'全唐诗/poet.song.74000.json','["鉤繩異曲直，鑿枘殊圓方。", "蛤死不脫殻，錐穎要出囊。", "風蛇互矜憐，蚌鷸相探嘗。", "紛然天壤間，巨細靡不藏。", "孰能使之齊，賢哉我未皇。", "付之將毋同，蠻貊猶故鄉。", "方生天馬駒，頭作千里昂。", "平生剛褊心，立朝慕周昌。", "置之岯山下，所用乃針芒。", "苦憎茶擾人，能妨春夢長。", "季也謂不然，辨理殊堅强。", "我欲兩可之，笙磬同一堂。", "楚人固失矣，齊論亦豈當。", "請歸亡是翁，文字搜枯腸。"]'),
('011c3d72-da42-4635-a60b-58670ed1b9ab','允迪和詩吝茶弗出而約以棋取之再次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','仙人爛柯山，坐隠多奇方。',168,'全唐诗/poet.song.74000.json','["仙人爛柯山，坐隠多奇方。", "我昔夢見之，正爭紫羅囊。", "豈獨寸筦窺，固已一臠嘗。", "至今不語妙，了了皆中藏。", "陋哉王積薪，亦復干帝皇。", "遠矣羊玄保，恨不同閭鄉。", "誰與子方子，忽作鬭雞昂。", "居然鏜其鼓，甚矣子之昌。", "吾師乃庖丁，未嘗嬰刃芒。", "遥知吾髮短，不必終纓長。", "明朝受敵降，築壇千步强。", "沙溪委道周，北苑陳中堂。", "想復聞我言，怒欲奮臂當。", "竟無百勝策，空有九回腸。"]'),
('51cb4e8f-e148-49c0-8e36-930b7b2428fb','余以雙雞餉彭子發初不知其皆雌也既而易之其謬如前子發有詩因次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','家貧苦厭雞，粱稻費畜養。',120,'全唐诗/poet.song.74000.json','["家貧苦厭雞，粱稻費畜養。", "群居頗狼籍，庶類日崇長。", "持以贈東家，料擇增鹵莽。", "經旬默不鳴，先生爲拊掌。", "馬也牝而驪，達士有遺相。", "望之似木雞，何嘗微技癢。", "當令守其雌，不必厲清吭。", "開籠鄭女雙，對舞江妃兩。", "索我於形骸，見爲無乃爽。", "聊復相解頤，風來聞笑響。"]'),
('a90deab3-8b20-4657-8c08-da778b78a498','中秋夜楊時可與狄端叔載酒見過月下聯句','趙鼎臣','宋','宋诗','song-poetry','','[]','月固不可得，客亦未易逢。',264,'全唐诗/poet.song.74000.json','["月固不可得，客亦未易逢。", "相看且一笑，劇飲須千鍾。", "石交事綺語，辯口如劍鋒。", "血指遇巧匠，青蒿倚長松。", "平生所欣慕，今夕獲從容。", "我出元白後，敢躡李杜蹤。", "競誇詞激烈，已覺醉蒙茸。", "虛文矜畫虎，利口極雕龍。", "誰能望塵拜，初不希侯封。", "雲披蟾影白，露浥桂香濃。", "河漢淡無色，烏鵲迷所從。", "要爲青女約，從使蜚廉攻。", "渡河天女懶，搗藥玉兔慵。", "秋凝霜悒悒，晴解雲重重。", "論功有詞客，誤曉驚惰農。", "興從庾亮發，景爲仲宣供。", "夜氣凄以冷，斗杓橫復縱。", "文章余所短，翰墨子之丰。", "酒渴思朝汲，腸饑聞夜舂。", "寧盡杯中蟻，勿聽床下蛩。", "思澀慚追驥，篇成類采葑。", "我眠君且去，莫待鼓鼕鼕。"]'),
('2d291883-5d8a-4564-8b96-9d69beb3cecc','嘲春詩','趙鼎臣','宋','宋诗','song-poetry','','[]','天公是春父，后土是春母。',56,'全唐诗/poet.song.74000.json','["天公是春父，后土是春母。", "風雨作春媒，桃李爲春婦。", "桃李嫁春來幾時，春工不肯使人知。", "昨夜小桃微破萼，漏泄春情春不覺。"]'),
('12576602-63f7-4d61-9e44-6804ffdad934','騎立山禱雨','趙鼎臣','宋','宋诗','song-poetry','','[]','秦頭東銜楚尾及，奠方作鎮神靈集。',64,'全唐诗/poet.song.74000.json','["秦頭東銜楚尾及，奠方作鎮神靈集。", "他山迤邐盡徒趨，中有一峰長騎立。", "雨暘吁嗟走祠下，神往救之如躍馬。", "深中百丈寒潭底，爵名上公地千里。"]'),
('3d8fa26d-3a48-4775-afb0-2c7d5e32d5f2','次韵何德之喜雪','趙鼎臣','宋','宋诗','song-poetry','','[]','北風半夜軒昂變，倒瀉天河飛似霰。',160,'全唐诗/poet.song.74000.json','["北風半夜軒昂變，倒瀉天河飛似霰。", "初驚弱質柔於冰，稍意澄江浄如練。", "心知消息到盃盤，坐覺精神生筆硯。", "曉來竹下失青莎，鵠立細長三四片。", "似欺趙子軀六尺，欲惱何郎書萬卷。", "詩泉要子涌三峽，酒路許吾通一線。", "可憐頃刻縱如花，不奈消流終怯晛。", "經嘗凜冽合增嫌，愛惜爲餘猶眷戀。", "畫莎江上真已奇，歌曲郢中殊不倦。", "自慚追琢費巧心，欲爲不托嗟無麵。"]'),
('bb5befe3-f765-477c-8a0b-a6e290f51300','再次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','何郎文章魯之變，句落毫端紛玉霰。',160,'全唐诗/poet.song.74000.json','["何郎文章魯之變，句落毫端紛玉霰。", "夜長乘雪出詩軸，十里銀光摇素練。", "西山作筆鋒已禿，東海凝冰蓋其硯。", "欲搜月兔出三窟，肯比崑瑶夸一片。", "梁園詞賦不收拾，散落人間今幾卷。", "應憐我窮被雪壓，冷屋號寒命如線。", "故將佳句發陽春，昔也瀌瀌今睹晛。", "白頭嗜酒尚書郎，日給二升心所戀。", "不愁家作四壁空，每得新詩便忘倦。", "啼饑更自有癡兒，妄想朝來天雨麵。"]'),
('566bbf67-2c94-4094-9236-73735d70c9b2','宋京宏甫見和再次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','水花浮空出奇變，散者爲霙圓者霰。',160,'全唐诗/poet.song.74000.json','["水花浮空出奇變，散者爲霙圓者霰。", "天翁大是富家翁，細碎剪雲親染練。", "山陰曉起右軍泣，不見墨池安得硯。", "從來緣水不充饑，此日正堪批作片。", "書生冷淡惡生活，忍凍悲吟詩滿卷。", "不知北里富薰天，舞袖對花裁圈線。", "紅爐熾炭坐生春，本不畏寒那憶晛。", "蘭臺賦風不賦雪，好色豈殊蜂蝶戀。", "不如諸孫藝且賢，蜀烹啖客初無倦。", "諸公速辯欲忘歸，盡磨東莊千斛麵。"]'),
('bdfcd459-b367-4c4a-8a98-57b772317fdd','十一月十七日大雪晝夜不止平地盈數尺十九日雪中與時可載酒相率出郊謁子莊因登爽亭臨軒縱飲四望浩然澒洞一色真奇勝也孫志康畏寒不出已而有詩因次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','小閣僅堪容一席，西望諸山天咫尺。',128,'全唐诗/poet.song.74000.json','["小閣僅堪容一席，西望諸山天咫尺。", "興來踏雪共登臨，徑醉何曾論斗石。", "風前少皞陳堂堂，萬騎銜枚替戾岡。", "傾河倒漢天上落，藍寶荆珍盡捲將。", "海邊屬國寒到骨，簾裏壽陽花滿房。", "恨君閉戶不好奇，三人醉倒君不知。", "須憐暖律易消鑠，行見芳洲生杜若。", "肯捐凍死求一適，聊畏思歸老莊舄。"]'),
('0b04276b-7257-4282-8475-c53b1678e4e6','洪谷值大風宿避賢驛詩','趙鼎臣','宋','宋诗','song-poetry','','[]','客行到處可獨宿，秋夜已長聊晏眠。',64,'全唐诗/poet.song.74000.json','["客行到處可獨宿，秋夜已長聊晏眠。", "北風吹燈最無味，明月照戶真可憐。", "兒女漸有婚嫁逼，富貴久無名利牽。", "欲歸不决坐此耳，展轉悲歌一悵然。"]'),
('ea8347dd-b9c3-413d-81f3-e0980aeaf47c','重陽前數日夜坐不寐偶思江南塞北舊遊作詩呈志康諸友','趙鼎臣','宋','宋诗','song-poetry','','[]','昔在江東作重九，斬新凉氣生杯酒。',208,'全唐诗/poet.song.74000.json','["昔在江東作重九，斬新凉氣生杯酒。", "右軍有宅山最高，歲歲與客登其首。", "菊花弄蘂天未霜，吳兒琵琶能斷腸。", "半天語笑中夜裏，山下人家驚走藏。", "禹穴探書無所得，笑指燕然疑可勒。", "燕南新築黄金臺，乃復招我何爲哉。", "五年醉倒南樓上，樓上黄花無處放。", "將軍喜氣自生春，盡釋風霜作和暢。", "美人低按小秦箏，坐中勸酒一再行。", "風前孟嘉帽欲落，席上孫郎句已成。", "一生散誕無羈束，到處容容尸斗祿。", "况復今年值衆賢，珠玉在側真可憐。", "重陽更欲登高去，莫遣風流減去年。"]'),
('30a07f5e-6334-47bb-bd14-da2cc3df2c96','子莊出獵僕不與聞志康有詩次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','歲窮於冬春未涉，雪入田中餘潤接。',192,'全唐诗/poet.song.74000.json','["歲窮於冬春未涉，雪入田中餘潤接。", "鷹鸇欲擊膽方張，狐兔正肥心已怯。", "忽呼小隊試周旋，直並西山窮射獵。", "將軍約束金鼓震，令尹指麾豺虎懾。", "平原淺草陣橫斜，後勁中權旗曄曄。", "林空肯使逸禽飛，澤竭不煩追騎躡。", "正堪大嚼出饞涎，安用千金酬笑靨。", "風毛漠漠任教吹，雨血紛紛誰所喋。", "不容杜曲隨李廣，顧肯桑間問靈輒。", "廟謨不戰方兩階，邊塵已靜休三捷。", "酩酊如余乃醉仙，雄豪似子真儒俠。", "明朝得雋儻相過，買酒尚堪吾倒篋。"]'),
('e03eba5c-de0d-4cc7-852f-118e9d25d6e4','子莊獵於近郊志康聞之盛贊如皋之舉且督分鮮之餉再以詩往而子莊不報夫踐霜雪跨陵谷以從禽荒之游樂則樂矣然未必賢伉儷之所喜也不然鮮胡爲而不至哉故余再次來韵以索其情','趙鼎臣','宋','宋诗','song-poetry','','[]','愛君談兵如趙涉，往與西人鋒刃接。',192,'全唐诗/poet.song.74000.json','["愛君談兵如趙涉，往與西人鋒刃接。", "尊前或詆次公狂，市上頗疑韓信怯。", "忽然結束變軒昂，駑馬自驅千騎獵。", "狐狸博碩正吾須，鳥雀細微誰女懾。", "風馳白羽欻驚飛，火點紅旗時一曄。", "將叔無狃戒其傷，君足正應防婦躡。", "千金之子不垂堂，坐使顰眉羞美靨。", "徑當去劍釋皮冠，腥血淋漓休使喋。", "賢如孟光不與謀，搏獸於原毋乃輒。", "聞君三日靜思愆，謝過莫如吾計捷。", "熊膰兔首速分張，好客庶幾閭里俠。", "歸家一笑定卿卿，止獵之書猶滿篋。"]'),
('73666eb0-9d74-46c9-b004-57186d4b19f1','再次前韵戲志康','趙鼎臣','宋','宋诗','song-poetry','','[]','賈侯少日規原涉，酒徒劍客交相接。',192,'全唐诗/poet.song.74000.json','["賈侯少日規原涉，酒徒劍客交相接。", "官成忽綰縣令章，文墨能令豪士怯。", "滿庭牒訴若沈迷，過眼詩書聊領獵。", "發狂正爾不能堪，大叫赫然胥吏懾。", "西城曉出頗匆匆，日射圍場光有曄。", "鹿傷鶴膝畏鵰盤，兔中鶻拳愁犬躡。", "獲多意解始開顔，暗覺微渦生兩靨。", "逡巡下令釋前禽，尚恐流殷人競喋。", "不知誰忽遣君知，佐饔而嘗心頗輒。", "新詩不減子虛篇，喜意似書城濮捷。", "更因乞肉苦譏嘲，句險詞夸終類俠。", "莫瞋令尹少須之，報聘已裝珠一篋。"]'),
('055dfa02-a506-4819-b0e9-4551eea9d633','余數與同舍唱和而何亨老獨否耿伯順以詩挑之因次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','巧匠未嘗夸所能，解衣槃薄初不驚。',128,'全唐诗/poet.song.74000.json','["巧匠未嘗夸所能，解衣槃薄初不驚。", "紛紛衆史爭舐筆，我獨以此全其名。", "坎其擊鼓瓦釜鬧，黄鐘大呂元希聲。", "揚雄有口吃不語，長安小兒心欲輕。", "一朝胸中吐白鳳，至今千載猶儀刑。", "頗疑將軍固多許，銜枚十萬藏奇兵。", "可憐吾黨有壯士，疾鬭不暇金鼓鳴。", "寄聲大耿莫倉猝，火急防渠夜斫營。"]'),
('4ac767c2-4701-4123-bb52-8405ac3b712b','次韵志康贈武得之得之余同年也','趙鼎臣','宋','宋诗','song-poetry','','[]','昔年曾伴南鵬擊，借我扶摇多少力。',80,'全唐诗/poet.song.74000.json','["昔年曾伴南鵬擊，借我扶摇多少力。", "君雖進寸我退尺，安得揚揚好顔色。", "忽然相逢不相識，怪我摧頹凋羽翮。", "念君家亦仍四壁，誰信懷中有垂棘。", "天寒雪凍行不息，相屬一杯空感激。"]'),
('5f77be1d-533b-4ced-8149-96782a59f4b1','梅花下置酒送潘廷立學正赴官京師因寄博士王堯明監簿劉仲忱','趙鼎臣','宋','宋诗','song-poetry','','[]','卧龍山下梅花發，舉杯半夜邀明月。',176,'全唐诗/poet.song.74000.json','["卧龍山下梅花發，舉杯半夜邀明月。", "自從却棹酒船回，一十五年如電掣。", "相逢忽在百花洲，玉骨冰姿愈奇絕。", "粲然顧我低欲笑，斂袵對之那忍折。", "應憐我老遽如許，鬢髮摧禿牙齒缺。", "對花不飲可奈何，急喚潘郎相煖熱。", "潘郎趣召許朝天，昨日見之今日別。", "莫嫌韓愈困虀鹽，會有王良收汗血。", "同僚滿屋多豪傑，倉卒立談難盡說。", "請於主簿覓于思，博士龍頭如玉雪。", "故人儻問我何如，正被梅花惱不徹。"]'),
('f3be887a-0e29-4e4a-8293-6b70f3ff8b5c','均文屢約相過近得書輒遷延偶讀予梅花詩次韵以趣北轅之約','趙鼎臣','宋','宋诗','song-poetry','','[]','江南仲御才英發，身佩瓊琚冠寶月。',176,'全唐诗/poet.song.74000.json','["江南仲御才英發，身佩瓊琚冠寶月。", "驊騮未肯就韁銜，乍蹋天街頻齧掣。", "忽然醉裏謫三湘，頓覺新詩愈超絕。", "人疑夫子不堪憂，豪氣壯心當少折。", "不知世故轉磨礲，凜凜太阿初不缺。", "歸逢北客笑無言，但道湖南苦秋熱。", "許來過我已三書，欲對清樽話離別。", "可憐楊葉漫飛煙，坐嘆榴花空點血。", "平生一諾季將軍，邂逅相逢應有說。", "頗聞列屋盡蛾眉，自教繞梁歌郢雪。", "君能輒暇暫來無，莫待新聲都按徹。"]'),
('eb95e0ee-2de1-4788-8d3f-bf7e7f390352','蔡興兵曹謝曾秀才見和梅花詩復此韵爲謝','趙鼎臣','宋','宋诗','song-poetry','','[]','詩如病疥歇復發，最忌春花與秋月。',176,'全唐诗/poet.song.74000.json','["詩如病疥歇復發，最忌春花與秋月。", "袖中縮手苦禁之，技癢不堪時一掣。", "彫肝琢腎神何苦，故令眼亂心愁絕。", "我生酒外百無能，病不持盃被磨折。", "暗香浮動正黄昏，獨坐悲歌唾壺缺。", "粗官豈合賦梅花，冷撰不慚中允熱。", "更煩屬和騁妍詞，句怯雖殊才調別。", "見輪學斲三十年，十指淋漓漫流血。", "忽逢匠扁過吾前，心悟微言口難說。", "冥搜角逐遂經旬，不覺紛紛墮香雪。", "尚堪火急醉其旁，卜夜直須令曉徹。"]'),
('89f3f5e0-7ef7-447b-a0e9-2ebd8779a609','讀李生詩愛而有作','趙鼎臣','宋','宋诗','song-poetry','','[]','少年似是賈才子，作語便如歐少師。',64,'全唐诗/poet.song.74000.json','["少年似是賈才子，作語便如歐少師。", "後生可畏吾老矣，下筆有神君勉之。", "崩崖破壑水浩渺，壞銜掣轡駒權奇。", "徐徐勢定識歸處，要以古人爲矩規。"]'),
('19507fd9-bf8d-4e7a-a9aa-4ed3d9aceac6','次韵朱琳天球','趙鼎臣','宋','宋诗','song-poetry','','[]','問君著鞭胡不忙，天子正欲興明堂。',64,'全唐诗/poet.song.74000.json','["問君著鞭胡不忙，天子正欲興明堂。", "不應止作燕雀伍，何苦不追鵷鷺行。", "請纓未欲事南粵，獻賦且可夸長楊。", "奈何聽訟獨辛苦，日與鳬鶴分短長。"]'),
('7b090f50-c117-4e68-a7eb-9ab83b453792','戲楊丞許尉','趙鼎臣','宋','宋诗','song-poetry','','[]','楊侯作書倚庭柱，不覺震雷掀屋去。',64,'全唐诗/poet.song.74000.json','["楊侯作書倚庭柱，不覺震雷掀屋去。", "許侯一盞便醺酣，遮莫王公也箕踞。", "兩君落魄不堪聞，愁殺當年鄭廣文。", "看却聾丞并酒尉，何曾敢說故將軍。"]'),
('04cafbcb-84b7-45f1-99e2-a169f192db0b','河間令尹','趙鼎臣','宋','宋诗','song-poetry','','[]','東家載豆如山嶽，西舍割禾無處著。',160,'全唐诗/poet.song.74000.json','["東家載豆如山嶽，西舍割禾無處著。", "父老歡呼南陌頭，打鼓吹簫相燕樂。", "今年不復似常年，斗米都無百十錢。", "新來長官政及我，夜無吠犬人得眠。", "公家力役會不免，常苦里胥相擾亂。", "里胥不出今幾時，我自輸官不須歎。", "秋風嫋嫋樂無涯，棗有實兮菊有花。", "聞道長官作生日，相呼父老來排衙。", "排衙奉上一盃酒，再拜長官千萬壽。", "三年替去不須臾，聊與斯民爲父母。"]'),
('bc382a84-47ea-496a-96fe-cc14611734c4','永錫生日以詩壽之','趙鼎臣','宋','宋诗','song-poetry','','[]','酌君以御府黄封之酒，泛君以江南白玉之巵。',168,'全唐诗/poet.song.74000.json','["酌君以御府黄封之酒，泛君以江南白玉之巵。", "祝君以歲寒後凋之壽，頌君以鮐背難老之詞。", "十年聞名不相識，一日傾蓋無復疑。", "文如錦繡可貴重，行似金玉無瑕疵。", "詔書求賢意不淺，嚴徐賈馬爭推薦。", "大蟲老鼠本殊科，李耳韓非偶同傳。", "看君此舉不匆匆，白日青霄意氣中。", "上方未賜尚書履，烏府先騎御史驄。", "我當報罷歸可必，却向軍中弄刀筆。", "今朝判得一醉無，請辦黄封作生日。"]'),
('8859e39d-fa2a-4040-88f4-90bb7ca46ad9','昔官會稽故侍講呂公原明丈請以其孫揆中者娶余之長女既受幣矣無何揆中與余女未成婚而俱卒濟陰簿本中則揆中之弟也近於同舍林德祖處見其所與石子植唱和詩子植又余太學之舊僚也故次其韵因寄呂兼以簡石且請德祖同賦','趙鼎臣','宋','宋诗','song-poetry','','[]','我昔江湖百憂集，侍講寄書猶墨濕。',128,'全唐诗/poet.song.74000.json','["我昔江湖百憂集，侍講寄書猶墨濕。", "婚姻竟作覆手空，日月真如跳丸急。", "哀哉大耿已川逝，秀矣小馮今玉立。", "詞源江海浩奔茫，句法風騷森出入。", "石郎與我金石交，每懷見君嗟靡及。", "種桑自比侯千戶，力田不願爵一級。", "頗聞杖屨約招携，應許蓬茅助營葺。", "欲討明珠救子饑，老矣安能發鮫泣。"]'),
('1145b2b8-323b-4b32-87dc-1549e8fffe28','欒棄奇育皆賦集字韵詩再次其韵示之','趙鼎臣','宋','宋诗','song-poetry','','[]','我家不減烏衣集，何曾以沫空相濕。',128,'全唐诗/poet.song.74000.json','["我家不減烏衣集，何曾以沫空相濕。", "父兄共有清白傳，家世不於名利急。", "稍侵老景何足道，粗喜汝曹皆有立。", "天路崢嶸在一飛，承明翕習期三入。", "乘時便可功業建，發策豈爲科第及。", "連珠合璧競名聲，九棘三槐爭品級。", "金門他日看汝游，竹隠何年助吾葺。", "男兒志氣要軒昂，肯作楚囚相對泣。"]'),
('74e65472-9157-43a9-9503-b409ffd3e793','送外兄張會之','趙鼎臣','宋','宋诗','song-poetry','','[]','我見舅氏如母存，舅氏之子吾弟昆。',208,'全唐诗/poet.song.74000.json','["我見舅氏如母存，舅氏之子吾弟昆。", "昔年兒童今白髮，舊事豈復能追論。", "烏乎外家久零落，無復駟馬乘朱軒。", "諸甥獨我偶未死，投老得郡西南奔。", "故鄉隔遠親舊少，忽騎款段呼我門。", "相逢握手問存歿，流淚欲哭聲復吞。", "頗聞二頃皆負郭，力田自可供晨昏。", "兒婚女嫁都已了，翁嫗屢醉茅柴渾。", "人生如此萬事足，便可送老三家村。", "我行四方走萬里，十畝未有桑麻園。", "欲置一錐無著處，儒冠誤我知何言。", "買牛賣劍計已决，家有竹隠堪負暄。", "兄能遠來復過我，當釀白酒烹雞豚。"]'),
('b071775d-9af8-4b6d-8ce8-6efdf8271aec','送張才元大臨歸高陽兼寄楊霍','趙鼎臣','宋','宋诗','song-poetry','','[]','少年公子麒麟種，使者選之來入貢。',144,'全唐诗/poet.song.74000.json','["少年公子麒麟種，使者選之來入貢。", "文章到處是青錢，談笑有時飛白鳳。", "留連太學滯遠業，歎息南陵發歸夢。", "黄河一葦浩將往，太行諸山森欲動。", "上堂嘉慶拜庭闈，入戶壎篪迎伯仲。", "幕中濟濟盡應劉，筆下翩翩皆屈宋。", "四者能并蓋已難，一尊可飲何妨痛。", "老夫久客興愈闌，公子遠行情所重。", "爲見應劉借問看，惟有月明千里共。"]'),
('d1fca3d2-b5ee-40fc-840b-5d366fc07dc0','送許少尹','趙鼎臣','宋','宋诗','song-poetry','','[]','春風無情自作惡，桃花杏花總零落。',96,'全唐诗/poet.song.74000.json','["春風無情自作惡，桃花杏花總零落。", "欲往城西看海棠，黄塵障天無住著。", "城西有客不可留，我挽其衣一頷頭。", "夢魂夜夜繞吳越，便思飛到江南州。", "滿堂故人色欲動，競把酒杯相鄭重。", "請君一醉不須辭，尚有殘春堪斷送。"]'),
('0ca6b119-957e-4fa2-81af-1231e05c59e4','憶昔行送彭子發','趙鼎臣','宋','宋诗','song-poetry','','[]','憶昔黄粱炊未熟，太學七人同日逐。',160,'全唐诗/poet.song.74000.json','["憶昔黄粱炊未熟，太學七人同日逐。", "先生不免弟子嘲，胯下頗遭年少辱。", "古人高誼今則亡，惟有彭公色慨慷。", "皇華已建使者節，青眼尚看同舍郎。", "三年牢落江湖上，頼有故人相倚傍。", "我窮凡鬼輒累公，公復參差我何望。", "世間榮辱何紛紛，覆手爲雨翻手雲。", "請將得失問北叟，敢以喜慍觀子文。", "滿斟滑盞如船大，舉酒屬公公且坐。", "看公骨相合封侯，今日入朝明日賀。"]'),
('f3174935-8c2a-4bed-a92b-b0e067e533a9','送同年王粹公受代還朝','趙鼎臣','宋','宋诗','song-poetry','','[]','昔年講學城南館，君餘二十我方冠。',192,'全唐诗/poet.song.74000.json','["昔年講學城南館，君餘二十我方冠。", "讀書兀兀敝精神，刺口紛紛談治亂。", "集英賜第偶追隨，慈孝題名容齒間。", "欲將步武踵夔龍，肯以功名論管晏。", "一時意氣若風狂，二紀光陰如夢幻。", "青眼全稀苦賤貧，白頭太早傷憂患。", "塞上逢迎心骨驚，尊前太息容顔換。", "哀哉田叔墓已拱，老矣朱公人所慢。", "分甘位下莫相憐，贏得身强聊自諫。", "君去方趨魏闕朝，我歸乍解軍書絆。", "河南河北地比鄰，春後秋前花爛熳。", "興來命駕豈吾難，會訪藍橋容一盼。"]'),
('e023a36b-5789-4795-b2c1-7b9d22b6f829','送張彥政歸京師','趙鼎臣','宋','宋诗','song-poetry','','[]','官曹寂寞坐兀兀，囊無一錢貧到骨。',224,'全唐诗/poet.song.74000.json','["官曹寂寞坐兀兀，囊無一錢貧到骨。", "欲歸未得住也難，客子秋來頗蕭瑟。", "并州人情薄於紙，覆雨翻雲而已矣。", "我頑不顧柰我何，得酒陶然且歡喜。", "府中別駕名公孫，往時閥閱推其門。", "皎如雙璧照閭里，至今文彩風流存。", "諸郎往往皆汗血，超然別駕尤奇絕。", "滿前豪傑多少人，獨向我曹相暖熱。", "幕府轅門一事無，五白爭梟半夜呼。", "但知得醉乃已耳，頗復有客如此乎。", "俗多我責君不然，君今去我真可憐。", "微官縛人不可脫，五斗看來成幾錢。", "君還朝廷用决矣，錯節盤根談笑裏。", "當權得意莫相忘，要須容此狂狷士。"]'),
('cbbbf1d9-ddec-469f-94e1-6e97a5b8fe6c','送趙延之億送伴高麗人歸國','趙鼎臣','宋','宋诗','song-poetry','','[]','九州遺迹皆禹功，高麗之通自元豐。',208,'全唐诗/poet.song.74000.json','["九州遺迹皆禹功，高麗之通自元豐。", "元豐聖人湯勇智，遠交欲斷匈奴臂。", "越裳九譯何自來，軺車不動麗人至。", "至今航海輸國珍，稽首朝正禮甚馴。", "吾皇寤寐率昭考，寵以大國升爲賓。", "海上凌秋潮信熟，去憑賈客船如屋。", "詔書揀選尚書郎，持節送之恩意縟。", "東夷北敵世爲鄰，久苦誅求夷甚貧。", "願歸筦鑰事天子，厭以形勢初無因。", "頗聞天驕國方擾，種落攻之天所討。", "附書憑子問三韓，畏頭畏尾何時了。", "天兵弔伐那可期，幽燕本自吾遺黎。", "請將鴨綠釀爲酒，來犒王師古北口。"]'),
('139ce779-1715-41bf-ba92-3037c03bb10b','送宋宏甫出守邠州','趙鼎臣','宋','宋诗','song-poetry','','[]','前年謬入文昌裏，堆案簿書如黑蟻。',192,'全唐诗/poet.song.74000.json','["前年謬入文昌裏，堆案簿書如黑蟻。", "左鳬右鶩去復來，大叫發狂那得止。", "開眼忽見同舍郎，英氣律兀髯而長。", "時於談間出妙語，似濯大暑遭風凉。", "自夸才高足餘刃，屢以豪篇相折困。", "我衰嚄唶安可當，晉甲未興齊已遯。", "今年別我西入關，意氣崢嶸喜動顔。", "秦山渭水笑談裏，劍閣峨嵋指顧間。", "古公去後風俗好，南畝勸耕農事早。", "一篇七月是圖經，不待下車心已了。", "髯卿故自讀書人，想有仁風慰彼民。", "班取新詩一千首，閉閣莫開長飲酒。"]'),
('5ed104ac-ec7e-4ff3-bafa-9305c5055310','得符先生作焚香寮東郡趙鼎臣賦詩以寄之','趙鼎臣','宋','宋诗','song-poetry','','[]','編蒲爲簾竹爲牀，先生一室如僧房。',96,'全唐诗/poet.song.74000.json','["編蒲爲簾竹爲牀，先生一室如僧房。", "乞米未來朝食粥，閉門不出坐焚香。", "銅爐霏霏擢煙縷，長伴詩翁作詩苦。", "郁然百和入肝脾，散落詩中出奇語。", "昔年我亦預言詩，裹糧問道今其時。", "肯將司法盡傳我，願與先生管香火。"]'),
('7ad472dc-2e22-44a9-9d8e-bc3b74b0fa78','寄題遐觀閣','趙鼎臣','宋','宋诗','song-poetry','','[]','子長南遊探禹穴，自誇歷覽多所列。',164,'全唐诗/poet.song.74000.json','["子長南遊探禹穴，自誇歷覽多所列。", "歸來落筆方著書，意與素王爭巧拙。", "謫仙早亦勤四方，沉浮江海遨齊梁。", "腹中領略幾萬里，文焰萬丈如許長。", "取之欲富觀欲博，貪多豈不如谿壑。", "直將眼力徧八方，達者應悲用心錯。", "不如五柳宅邊一老人，家貧無錢常閉門。", "時時矯首聊寓目，但見倦飛之鳥無心雲。", "老人觀之釋然悟，歸去來兮從此賦。", "勉旃爲謝倚欄人，著眼應須在渠處。"]'),
('856a4ed2-c584-4085-bb5c-7ae480b361b4','屬疾在告郡中諸公相繼服藥戲作病中九客歌','趙鼎臣','宋','宋诗','song-poetry','','[]','將軍膽氣凌秋天，百札曾將一箭穿。',224,'全唐诗/poet.song.74000.json','["將軍膽氣凌秋天，百札曾將一箭穿。", "倒牀忽作兒女眼，悲啼出淚如湧泉。", "會稽令尹形悍堅，新買蛾眉費萬錢。", "未容纖腰小回旋，徑煩藥餌親調煎。", "山陰大夫祖文淵，彎弓射賊口垂涎。", "壯士亦苦頭風偏，河潤九里風化傳。", "坐令丞簿相牽聯，請醫買藥爭後先。", "剡中有宰正鳴絃，携琴忽泛子猷船。", "入城巵酒不下咽，但飲柴胡如吸川。", "沃洲公子黠可憐，斬關夜遁呼不前。", "道中揮斷九鐵鞭，抱病誰復能輕便。", "鑄錢短簿非凜然，捧心欲效西子妍。", "青衫從事世所捐，亦遭病鬼相傍緣。", "戲成嘲語如怪顛，一讀坐使沉痾痊。"]'),
('c9b0a46f-e9c9-43de-90e2-2781e0f799d8','次韵洪琳父','趙鼎臣','宋','宋诗','song-poetry','','[]','平生見酒喜欲舞，不惜淋漓身上衣。',160,'全唐诗/poet.song.74000.json','["平生見酒喜欲舞，不惜淋漓身上衣。", "尊中聖賢盡莫逆，坐上賓客皆能詩。", "陶潛欲眠無我責，灌夫駡坐不汝疵。", "世間樂事凡四者，他人多耦我獨奇。", "今年病眠不敢飲，坐負美景辜良時。", "中秋明月漫皎皎，九日黄菊空離離。", "洪崖先生夙所慕，文雅藴藉今阮嵇。", "故持濁醪作勝供，往助脫粟陪羹藜。", "先生學道早有得，一車僅可如雞栖。", "相投木瓜意不淺，願得瓊琚以報之。"]'),
('69f5e7fd-1010-4ec7-bd74-6f07e1fb2c34','余嘗假酒於楊時可既而償之時可不受因以詩見餉次其韵','趙鼎臣','宋','宋诗','song-poetry','','[]','君家子雲老無酒，好事時煩親與舊。',64,'全唐诗/poet.song.74000.json','["君家子雲老無酒，好事時煩親與舊。", "車邊大腹載鴟夷，從事督郵無不受。", "諸孫今復可憐人，官冷何嘗堪炙手。", "家雖有酒不自持，橫來澆我談天口。"]'),
('bd2d973a-8256-4a86-a7f2-0956c1245e28','猶子奕來乞酒戲以詩餉之','趙鼎臣','宋','宋诗','song-poetry','','[]','滏陽從事如瓠壺，雖如瓠壺中不粗。',216,'全唐诗/poet.song.74000.json','["滏陽從事如瓠壺，雖如瓠壺中不粗。", "十圍腰腹八尺軀，出行不敢用肩輿。", "馬壯如牛形虎如，載之喘汗蹶不趨。", "倒牀甘寢鼻輒呼，隠如雷霆驚里閭。", "覺來長嘯忽軒渠，口吻咳唾出明珠。", "詆嘲風月戲鳥魚，攟摭草木窮根鬚。", "大聲鏗鏘金石俱，小聲要眇韵笙竽。", "泠泠清風濯暑餘，玉壺之冰列坐隅。", "夷甫衛玠談玄虛，蒙莊執策算有無。", "乃知公孫不碩膚，炯如列仙形甚臞。", "瑶泉之酒出中厨，時節貢獻帝所須，頗亦霑丐及吾徒。", "知汝燥吻思江湖，作書亟遣長鬚奴。", "焦山未沃東海枯，笑我一勺安可濡。"]'),
('79a30b68-2cae-42e2-abc8-294582e37358','伯順以歙硯餉我因用前韵謝之并簡亨老以助致師之請','趙鼎臣','宋','宋诗','song-poetry','','[]','挾山超海吾豈能，章服裹之麋鹿驚。',128,'全唐诗/poet.song.74000.json','["挾山超海吾豈能，章服裹之麋鹿驚。", "平生忍饑耕破硯，字畫僅能通姓名。", "自傳同舍有和璧，未敢攫取先以聲。", "耿侯聞之顧且笑，棄擲不啻鴻毛輕。", "我窮正坐毛穎誤，戀著翰墨天所刑。", "少不如人今老矣，筆陣欲合陰借兵。", "何郎持重欲困我，堅壁不聞刁斗鳴。", "明朝一陣氣已了，大將旗鼓居吾營。"]'),
('c15a5936-adcf-44f7-8d49-4bbdc5850360','次韵子磐悼畜馬死','趙鼎臣','宋','宋诗','song-poetry','','[]','吾聞古者八駿圖，白義騄耳皆龍駒。',240,'全唐诗/poet.song.74000.json','["吾聞古者八駿圖，白義騄耳皆龍駒。", "獨嘶長風志萬里，意態自與凡馬殊。", "常時陸陸未足道，一日致遠君應須。", "朝秣幽燕暮吳粵，顧視款段猶泥塗。", "王良不生造父死，校計豈復分毫銖。", "憶君初應將軍召，隨身惟以一馬俱。", "官曹卑微騎從少，豈有負弩供前驅。", "忽然據鞍欲有適，老兵一諾費百呼。", "空槽無芻但與飲，坐令槁死城南隅。", "天嫌此馬非俊物，如君豈合冉冉趨。", "才高不肯露頭角，有計甘學水中鳬。", "故令駑蹇自斃踣，欲君感慨求夷途。", "當捐千金市絕足，勿仗短策驅庸奴。", "人生但可印如斗，世上豈患騅無烏。", "馬骨朽時君貴矣，頗應憶著敝帷無。"]'),
('5b2bdb3c-3ef6-4f60-ba4a-70919616c568','驛中燕北使戲成','趙鼎臣','宋','宋诗','song-poetry','','[]','夜長更長睡復覺，欲雪不雪寒且風。',64,'全唐诗/poet.song.74000.json','["夜長更長睡復覺，欲雪不雪寒且風。", "人如胡越不覺異，酒味聖賢聊復中。", "客來不語雖禮簡，賓去獻弓而愛同。", "書生多口慎勿出，累聖消兵在此中。"]'),
('337d8a9b-9ff7-45b6-9a39-f418bb1d3644','寒日前二日直宿省中','趙鼎臣','宋','宋诗','song-poetry','','[]','古屋寒無禁，幽眠夢不成。',48,'全唐诗/poet.song.74000.json','["古屋寒無禁，幽眠夢不成。", "鼠留窺硯迹，風度響窗聲。", "人語天將曉，春陰日未明。", "起來搔短髮，端自有餘清。"]'),
('b1601534-19aa-41e8-89d6-aea3ae69751a','雨中直宿','趙鼎臣','宋','宋诗','song-poetry','','[]','白日文書滿，清秋寓直頻。',48,'全唐诗/poet.song.74000.json','["白日文書滿，清秋寓直頻。", "雨愁官路滑，風喜夜凉新。", "頭裏千莖雪，胸中萬斛塵。", "不知窮列宿，若箇是吾身。"]'),
('30e4f480-8975-40e5-bcf9-8095374377cb','伏日還府題王村鋪','趙鼎臣','宋','宋诗','song-poetry','','[]','火候猶騎伏，金行已立秋。',48,'全唐诗/poet.song.74000.json','["火候猶騎伏，金行已立秋。", "凉雖來緩緩，熱好罷休休。", "歲月隨鞭箠，塵埃老置郵。", "年年禾黍熟，吾道得無憂。"]'),
('171e3cff-5849-45cd-af26-0fb388a8c68c','六月十二日被檄詣邊道中即事','趙鼎臣','宋','宋诗','song-poetry','','[]','驅馬日尚早，解鞍天向晨。',48,'全唐诗/poet.song.74000.json','["驅馬日尚早，解鞍天向晨。", "風雖排酷吏，雨復滯行人。", "保障連營遠，陂塘發興新。", "荷花嬌欲語，愁絕故傷神。"]'),
('4c6cb604-baa7-4e00-af59-49a66f22f334','晉陽道中','趙鼎臣','宋','宋诗','song-poetry','','[]','路入羊腸裏，師行鼠穴中。',48,'全唐诗/poet.song.74000.json','["路入羊腸裏，師行鼠穴中。", "山田如越俗，板屋類秦風。", "形勢無加損，汙隆有異同。", "百年開壽域，興國太平功。"]'),
('181839ee-bae3-4ce9-b5c6-6620baa560f0','嵐谷道中','趙鼎臣','宋','宋诗','song-poetry','','[]','汗漫穿巖谷，悠悠不計程。',48,'全唐诗/poet.song.74000.json','["汗漫穿巖谷，悠悠不計程。", "林鳩呼婦宿，驛馬带駒行。", "葉落知霜早，禾登喜歲成。", "潺湲溪水急，未暇濯吾纓。"]'),
('70d1fd89-5c73-452a-be9d-b2f9631d5c08','過武强渡','趙鼎臣','宋','宋诗','song-poetry','','[]','千里跨羸馬，一舟浮大河。',48,'全唐诗/poet.song.74000.json','["千里跨羸馬，一舟浮大河。", "他鄉故舊少，長路往來多。", "心欲求田耳，身如作吏何。", "荒凉三徑晚，歸計日蹉跎。"]'),
('138a9183-ea2d-44e0-b12b-963f6b6ad915','過銅雀臺弔魏武','趙鼎臣','宋','宋诗','song-poetry','','[]','慷慨勤王始，艱難創業初。',48,'全唐诗/poet.song.74000.json','["慷慨勤王始，艱難創業初。", "英辭傳樂府，妙略布新書。", "逐鹿功雖在，藏舟計已疏。", "一朝空繐帳，愛子竟何如。"]'),
('086b888f-a120-4b1c-8086-57af00b07192','八月十一日山中早發薄寒凝冰馬上重裘尚未能以禦寒也時將中秋感舊而作','趙鼎臣','宋','宋诗','song-poetry','','[]','蕭索嵐州路，天寒已著人。',48,'全唐诗/poet.song.74000.json','["蕭索嵐州路，天寒已著人。", "可憐挾纊日，不待飲冰辰。", "凉夜更籌永，清秋月色新。", "去無河朔飲，絺綌故相親。"]'),
('d0014b25-0756-4437-a3ec-6194cb3ab49d','任邱道中值雪贈權邑宰曹弋取道曹河間同僚也  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','宿霧寒猶重，濃陰曉未分。',48,'全唐诗/poet.song.74000.json','["宿霧寒猶重，濃陰曉未分。", "山川連野暗，雞犬隔村聞。", "浩蕩天將雪，朦朧酒半醺。", "向來臨易水，長嘯欲移文。"]'),
('d91110e7-7858-4a2d-84b7-928a697107bb','任邱道中值雪贈權邑宰曹弋取道曹河間同僚也  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','俎豆嗟何有，櫜鞬病未能。',48,'全唐诗/poet.song.74000.json','["俎豆嗟何有，櫜鞬病未能。", "府中嘲短簿，門下養聾丞。", "問路朝馳傳，逢人夕飲冰。", "全家今飽滿，此祿懼難勝。"]'),
('ef9c8e87-65b1-437b-9b6a-196be711fa0f','騎立山禱雨詩二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','絕壁臨無地，飛泉落半天。',48,'全唐诗/poet.song.74000.json','["絕壁臨無地，飛泉落半天。", "潭中看止水，澗下響驚川。", "江漢威南及，嵩邙勢北連。", "尋山應最易，騎立衆峰前。"]'),
('1199e056-6fdd-4aaf-877e-3fe71bcfd599','騎立山禱雨詩二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','乞雨甘重繭，瞻天劇戴盆。',48,'全唐诗/poet.song.74000.json','["乞雨甘重繭，瞻天劇戴盆。", "無才修政事，有靦傍祠門。", "馬足盤山肋，泉聲漱石根。", "雲霓如響答，蘋藻願星奔。"]'),
('3d1797f7-6183-4c74-9190-8a21fc6fcdc6','謝諸公惠喜雨之什','趙鼎臣','宋','宋诗','song-poetry','','[]','薄宦慙亡補，高秋恨不歸。',48,'全唐诗/poet.song.74000.json','["薄宦慙亡補，高秋恨不歸。", "况逢仍歲旱，猶著故時衣。", "禱雨精誠竭，憂民寢食非。", "自惟存畎畝，何以辱珠璣。"]'),
('cfdb1d0f-c7d0-41f3-bf2b-bff102291352','喜雨','趙鼎臣','宋','宋诗','song-poetry','','[]','蹔舉催科手，來吟喜雨詩。',48,'全唐诗/poet.song.74000.json','["蹔舉催科手，來吟喜雨詩。", "不徒人物惠，且免吏民嗤。", "三日霖隨應，千箱樂在茲。", "爲言農事好，卒歲保嘻嘻。"]'),
('0128f610-59de-4df9-a38e-fe1f4c1fd9cc','四月二十七日雨後詣府學道過辟雍不暇謁權朝美歸以詩寄之','趙鼎臣','宋','宋诗','song-poetry','','[]','三日霖雨足，四郊牟麥稠。',48,'全唐诗/poet.song.74000.json','["三日霖雨足，四郊牟麥稠。", "日長渾似夏，風冷却疑秋。", "璧水勞心曲，車輪阻道周。", "桃花如爛熳，他日定來游。"]'),
('99b05502-c39d-45cf-850b-9411770a71b7','和欽止桐廬中道見寄二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','邂逅來隨牒，因循未拂衣。',48,'全唐诗/poet.song.74000.json','["邂逅來隨牒，因循未拂衣。", "江鄉知舊少，京國信音稀。", "老廢書千卷，愁寬带十圍。", "故人鴻鵠舉，燕雀自卑飛。"]'),
('a55caa56-8436-4935-874a-533843e1e358','和欽止桐廬中道見寄二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','昔忝同僚分，深慚國士知。',48,'全唐诗/poet.song.74000.json','["昔忝同僚分，深慚國士知。", "髮衰將得白，衣素已成緇。", "富貴君餘事，功名彼一時。", "臘梅如可寄，爲折最南枝。"]'),
('49bff386-af40-432d-b2a8-0b082bbf3616','次韵翟經國見寄','趙鼎臣','宋','宋诗','song-poetry','','[]','故國幾喬木，長歧數短亭。',48,'全唐诗/poet.song.74000.json','["故國幾喬木，長歧數短亭。", "日趨天闕絳，坐失鬢絲青。", "舊著歸田賦，新傳釀酒經。", "卜鄰知有日，爛醉不須醒。"]'),
('631fe447-b6f6-4b6d-b5f1-e4c3ee88691e','喜聞方時敏來','趙鼎臣','宋','宋诗','song-poetry','','[]','浙江爲客久，汴岸艤舟新。',48,'全唐诗/poet.song.74000.json','["浙江爲客久，汴岸艤舟新。", "未暇趨東閣，先來覓故人。", "棋應緣老退，詩不爲家貧。", "土物惟襄錦，堪爲照乘珍。"]'),
('24199ce9-dcfb-4557-ae4d-07b1def188bd','寄山陰隠者','趙鼎臣','宋','宋诗','song-poetry','','[]','聞道山陰老，春來樂有餘。',48,'全唐诗/poet.song.74000.json','["聞道山陰老，春來樂有餘。", "饑餐一盤飯，閑讀兩行書。", "竹裏親沽酒，江邊自買魚。", "何曾入城市，人事轉生疏。"]'),
('418a51d5-5e40-4fe7-91a8-aeee9b767eda','翟經國築室於鄉里人誇傳以爲盛其西吾葦溪也以詩戲之','趙鼎臣','宋','宋诗','song-poetry','','[]','故人高隠處，近在郭門西。',48,'全唐诗/poet.song.74000.json','["故人高隠處，近在郭門西。", "數仞簷楹敞，滿城門戶低。", "便當容駟馬，何止卜幽棲。", "更請開三徑，時來過葦溪。"]'),
('5050e661-becf-4b96-b340-44b3f48932cb','十二月二十一日雪取道置酒於清白堂林正仲有詩次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','花飛何事急，紈細不勝裁。',48,'全唐诗/poet.song.74000.json','["花飛何事急，紈細不勝裁。", "睡起明書幌，粧成濕鏡臺。", "多情調玉燭，作意恥金罍。", "授簡何容易，相如欲到來。"]'),
('b84e2cc3-4c41-44f5-a89b-943d58c64edc','泛舟席上次韵祖武聞笛','趙鼎臣','宋','宋诗','song-poetry','','[]','虎檻留春色，龍吟入酒杯。',48,'全唐诗/poet.song.74000.json','["虎檻留春色，龍吟入酒杯。", "響從天外去，妙向曲中來。", "但可金罇滿，何勞暮鼓催。", "獨憐羈旅客，愁絕正徘徊。"]'),
('bd947e19-7962-40ec-b5b8-88b5851a21d1','嘲詠詩','趙鼎臣','宋','宋诗','song-poetry','','[]','堯俗雖勤儉，并兒可嘆嗟。',48,'全唐诗/poet.song.74000.json','["堯俗雖勤儉，并兒可嘆嗟。", "井牽長頸盎，山駕破轅車。", "八月霜如霰，三春雹似瓜。", "頭蓬非願女，膏沐欠油麻。"]'),
('e8d5bdcc-0a85-4054-9933-bad5d14c8f36','披風','趙鼎臣','宋','宋诗','song-poetry','','[]','脩竹不受暑，暗驚疑故人。',48,'全唐诗/poet.song.74000.json','["脩竹不受暑，暗驚疑故人。", "暫來聊解慍，徑去不驚塵。", "汗濕衣裳雨，書翻几案鱗。", "快哉那獨敢，贈爾耦耕民。"]'),
('e3b8f43b-f61f-492b-9800-78d3935b2cde','晝眠','趙鼎臣','宋','宋诗','song-poetry','','[]','枕瓷歌婭姹，屏紙漲漣漪。',48,'全唐诗/poet.song.74000.json','["枕瓷歌婭姹，屏紙漲漣漪。", "左角蝸休鬭，南柯蟻正爲。", "靜喧閑處失，憂喜夢中移。", "吐握真賢相，相邀不計時。"]'),
('7343c0c9-871a-480d-8927-fc7adb1077eb','波流一首','趙鼎臣','宋','宋诗','song-poetry','','[]','波流非自性，綠竹蓋其姿。',48,'全唐诗/poet.song.74000.json','["波流非自性，綠竹蓋其姿。", "坐得濯纓理，還思垂釣時。", "幾人能樂水，此處可無詩。", "寄語塵埃客，勤來一洒之。"]'),
('f5d127f0-4f75-414b-95f7-8d42a09cadae','買花詩','趙鼎臣','宋','宋诗','song-poetry','','[]','老覺歡娛少，愁驚歲月頻。',48,'全唐诗/poet.song.74000.json','["老覺歡娛少，愁驚歲月頻。", "能消幾日醉，又過一年春。", "陌上枝枝好，釵頭種種新。", "買歸持博笑，貢自可憐人。"]'),
('197febae-7e36-492e-b75a-55ee86fdec97','竹','趙鼎臣','宋','宋诗','song-poetry','','[]','雨洗修篁浄，風摇翠影森。',36,'全唐诗/poet.song.74000.json','["雨洗修篁浄，風摇翠影森。", "蒼官投分久，丹穴寄懷深。", "窈窕蕙蘭質，輕狂桃李心。"]'),
('15938553-a018-490e-a3f0-352cf90d6708','無題','趙鼎臣','宋','宋诗','song-poetry','','[]','韵勝應難畫，肌香不受熏。',48,'全唐诗/poet.song.74000.json','["韵勝應難畫，肌香不受熏。", "拂眉煙度柳，梳鬢月侵雲。", "歌罷猶依扇，閑來懶繫裙。", "最憐能賦客，渾似卓文君。"]'),
('0927c558-479a-47e6-8fc2-fc42b479fd47','故大司成葛亞卿輓詩  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','行義知名早，雲霄得路遲。',48,'全唐诗/poet.song.74000.json','["行義知名早，雲霄得路遲。", "喜聞儒者用，忽歎哲人萎。", "故事留青鏁，平生有素絲。", "馬鳴猶躑躅，似記入朝時。"]'),
('74271d77-177a-4430-8ae7-338865884ea2','故大司成葛亞卿輓詩  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','璧水除官日，漳濱卧疾年。',48,'全唐诗/poet.song.74000.json','["璧水除官日，漳濱卧疾年。", "賀書猶未報，弔客已相先。", "夢幻真空矣，衣冠尚儼然。", "平生詩滿篋，當自有人傳。"]'),
('ddd6623e-708b-4ee0-9c8c-a89ef927060b','輓李待制浦五首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','鄉黨推耆舊，朝廷重老成。',48,'全唐诗/poet.song.74000.json','["鄉黨推耆舊，朝廷重老成。", "閨門無政事，孝悌有平生。", "萬卷常充宇，千金不滿籯。", "種成蘭玉後，華髮看昇平。"]'),
('099af733-5f65-495a-b047-9ebb42be5a3e','輓李待制浦五首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','晚持安世橐，早掛隠居冠。',48,'全唐诗/poet.song.74000.json','["晚持安世橐，早掛隠居冠。", "子貴年方壯，家嚴色更難。", "古今成俯仰，歌哭異悲歡。", "淚滴新阡上，風吹不肯乾。"]'),
('2a0e0261-a9e3-4d98-9979-1410464ca670','輓李待制浦五首  其三','趙鼎臣','宋','宋诗','song-poetry','','[]','就養今西府，趨庭國柄臣。',48,'全唐诗/poet.song.74000.json','["就養今西府，趨庭國柄臣。", "上思耆艾久，詔問起居頻。", "贈典河圖貴，佳城馬鬣新。", "丹青雖可畫，那復見斯人。"]'),
('4b55e64d-b2cc-4415-b54e-168e2193fe3a','輓李待制浦五首  其四','趙鼎臣','宋','宋诗','song-poetry','','[]','人物推河內，英靈稟太行。',48,'全唐诗/poet.song.74000.json','["人物推河內，英靈稟太行。", "先生雖隠晦，嗣子遂騰驤。", "堯舜親延接，夔龍日贊襄。", "于門高未了，不惜更軒昂。"]'),
('9d5b5475-7d8f-48aa-9594-a4d92ce3411d','輓李待制浦五首  其五','趙鼎臣','宋','宋诗','song-poetry','','[]','往昔陪尊俎，從容接話言。',48,'全唐诗/poet.song.74000.json','["往昔陪尊俎，從容接話言。", "骨雖如鶴瘦，語尚作春溫。", "一夢人琴失，流年日月奔。", "空餘華屋處，愁絕向誰論。"]'),
('6bc1bf36-8cde-442e-a42b-589c6e6065dd','輓傅奉議三首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','行義推鄉里，才華動搢紳。',48,'全唐诗/poet.song.74000.json','["行義推鄉里，才華動搢紳。", "六經常自醉，一室故安貧。", "未覺蒲輪晚，俄悲薤露新。", "他年儒學傳，莫謂史無人。"]'),
('6787d4b3-412c-4fac-812e-05cb680e7be9','輓傅奉議三首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','往日調商鼎，當年築漢壇。',48,'全唐诗/poet.song.74000.json','["往日調商鼎，當年築漢壇。", "從容作霖雨，談笑斬樓蘭。", "每恐風流盡，空餘琬琰刊。", "承家今已矣，清淚一汍瀾。"]'),
('86c3ca93-399c-4d84-a25d-2d5028e95415','輓傅奉議三首  其三','趙鼎臣','宋','宋诗','song-poetry','','[]','爲儒嗟不達，射策竟知名。',48,'全唐诗/poet.song.74000.json','["爲儒嗟不達，射策竟知名。", "爵命加黄壤，詩書到後生。", "高年鳩杖貴，故國錦衣榮。", "他日蘭亭會，何由見老成。"]'),
('5d89bd8e-bda7-47cf-adc7-e7c984f79ef0','輓故致政大夫詩  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','乍捧毛生檄，初登賈傅年。',48,'全唐诗/poet.song.74000.json','["乍捧毛生檄，初登賈傅年。", "低回成鶴髮，勉强用蒲鞭。", "遺愛西州說，清風古國傳。", "欲知陰德處，廷尉有青氈。"]'),
('a59b0553-132d-4d72-9856-abe2f3e17ba9','輓故致政大夫詩  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','系忝宗盟重，交推父黨尊。',48,'全唐诗/poet.song.74000.json','["系忝宗盟重，交推父黨尊。", "凄凉思往日，邂逅識朱轓。", "華屋耆年逝，衡門稚子存。", "大岯山下路，愁句向誰論。"]'),
('e6a58a64-7983-49fe-907d-794620eb1b3e','彭樂道輓詩三首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','絳帳名雖早，青衫位不登。',48,'全唐诗/poet.song.74000.json','["絳帳名雖早，青衫位不登。", "對囚常涕泣，奏當極哀矜。", "養氣勞存想，看書廢寢興。", "短檠留案上，不復夜挑燈。"]'),
('57b8ed45-b2b0-45d4-b1c3-544548c86a65','彭樂道輓詩三首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','法吏真雞割，儒衣歎陸沉。',48,'全唐诗/poet.song.74000.json','["法吏真雞割，儒衣歎陸沉。", "官曹曾接武，談麈獨傾心。", "笑我趨時懶，知渠味道深。", "微言今已矣，慷慨獨沾襟。"]'),
('a7d53cfe-d735-4819-b96a-7619f71a6350','彭樂道輓詩三首  其三','趙鼎臣','宋','宋诗','song-poetry','','[]','身老羞干祿，家貧喜著書。',48,'全唐诗/poet.song.74000.json','["身老羞干祿，家貧喜著書。", "妙雖窮比興，粗亦到蟲魚。", "潘令官何拙，虞卿意不疏。", "傳詩今有子，應不廢菑畬。"]'),
('455340db-ba00-49c0-a95e-f224c8549e2c','劉孝叔輓詩','趙鼎臣','宋','宋诗','song-poetry','','[]','登科方欲冠，謝病未當傳。',48,'全唐诗/poet.song.74000.json','["登科方欲冠，謝病未當傳。", "歡喜榮親日，康强任子年。", "入川將老矣，返魯遂終焉。", "他日南城路，回車一愴然。"]'),
('00942ad8-724b-4b25-93b7-28e564e0e4d3','唐康功輓詩二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','命也人難料，天乎子可憐。',48,'全唐诗/poet.song.74000.json','["命也人難料，天乎子可憐。", "愁看一片玉，埋向九重泉。", "已覺荆枝悴，空餘綵服鮮。", "老親今八十，行路亦悽然。"]'),
('76236743-f286-4cab-ad6b-287a1e041f16','唐康功輓詩二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','意氣聞他日，聲名蓋此邦。',48,'全唐诗/poet.song.74000.json','["意氣聞他日，聲名蓋此邦。", "膽令姦吏破，心使壯夫降。", "頓失歆龍一，仍存賈虎雙。", "風流嗟已矣，洒淚向秋江。"]'),
('0a31bd49-a1c9-4fb8-a34f-366dc80c21bc','故太原郡太夫人李氏輓歌詩二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','德配平原盛，家傳相國親。',48,'全唐诗/poet.song.74000.json','["德配平原盛，家傳相國親。", "桂抽三筍茂，玉種兩株成。", "化劍中秋冷，藏舟半夜驚。", "凱風從此去，忍聽自南聲。"]'),
('95c8b680-5518-4477-ac35-a8cbdf10f721','故太原郡太夫人李氏輓歌詩二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','大郡開湯沐，高堂問凊溫。',48,'全唐诗/poet.song.74000.json','["大郡開湯沐，高堂問凊溫。", "腰金仍及婿，持橐更連孫。", "養極千鍾富，身兼五福尊。", "從今雋京兆，誰爲賞平反。"]'),
('11b638ec-7b72-4b5b-bf84-808f8f2911a2','故安定郡太夫人郭氏輓詩二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','象服承恩日，金牋告第初。',48,'全唐诗/poet.song.74000.json','["象服承恩日，金牋告第初。", "御前頒詔旨，天上寫除書。", "流水三春逝，黄粱一夢虛。", "七絃雖自足，亡已復何如。"]'),
('aec2a69f-fc6a-403a-b9a3-b6dba4be9ea2','故安定郡太夫人郭氏輓詩二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','卜葬開新兆，從姑返舊塋。',48,'全唐诗/poet.song.74000.json','["卜葬開新兆，從姑返舊塋。", "二卿銜恤意，八座悼亡情。", "蘋藻全拋却，松楸已種成。", "魚軒相逐去，非復是平生。"]'),
('ac3c9f2c-7afd-4d5e-8545-44946dcf91e8','夜直宿有懷','趙鼎臣','宋','宋诗','song-poetry','','[]','坐愛王孫不嗣音，東家芳草怨何深。',64,'全唐诗/poet.song.74000.json','["坐愛王孫不嗣音，東家芳草怨何深。", "柳芽得雨皆青茁，花葉隨風故陸沉。", "未可便成春去恨，猶堪自强老來心。", "直須淡墨題名了，一醉相期到上林。"]'),
('75095b15-bcd6-49c7-bbeb-afb172fc4856','二月八日以藉田職事雪中至郊外歸過美之題于屋壁','趙鼎臣','宋','宋诗','song-poetry','','[]','簿領勞人不少休，暫因王事得抽頭。',64,'全唐诗/poet.song.74000.json','["簿領勞人不少休，暫因王事得抽頭。", "不辭出郭辛勤去，聊作尋春爛漫遊。", "酒興欲狂無客喚，雪花方急被風收。", "鑾輿不日臨千畝，鬰鬰天田瑞氣浮。"]'),
('27e75bc7-b9ae-4d37-a295-cfa55400c2b2','社日過美之兄','趙鼎臣','宋','宋诗','song-poetry','','[]','鳴鳩喚婦喜新晴，舊燕尋巢乍入城。',64,'全唐诗/poet.song.74000.json','["鳴鳩喚婦喜新晴，舊燕尋巢乍入城。", "雷送雨聲逢甲子，寒留春色到清明。", "賞心未向桃蹊發，飽意先從麥隴生。", "覓句盡於南畝得，粗官真自少風情。"]'),
('d73c5da3-6ee1-4a43-9877-ebddc3ba47a9','寒食前一日率趙伯山李漢老楊時可秦夷行劉仲忱游西池泛舟置酒分韵賦詩以每日江頭盡醉歸爲韵余得江字因即賦所見','趙鼎臣','宋','宋诗','song-poetry','','[]','老欲爭春未肯降，强陪諸彥倒空缸。',64,'全唐诗/poet.song.74000.json','["老欲爭春未肯降，强陪諸彥倒空缸。", "上林春景宜寒食，水殿樓臺勝曲江。", "花裏人家酤酒斗，葦間釣艇買魚雙。", "眼穿不見春風面，翠袖依微半隠窗。"]'),
('dcfd86d1-2cd8-4222-a382-7a63820a03ef','寒食道中病目','趙鼎臣','宋','宋诗','song-poetry','','[]','今年已作暗寒食，此日正如盲老翁。',64,'全唐诗/poet.song.74000.json','["今年已作暗寒食，此日正如盲老翁。", "病眼昏昏迷白黑，幻花隠隠出青紅。", "人歌人哭千家裏，春雨春晴一夢中。", "會放目光牛背上，轉頭何事不成空。"]'),
('2fcd254a-a3de-47dc-9dfc-f7c7205a1339','暮春東陽道中寄鄉里弟兄','趙鼎臣','宋','宋诗','song-poetry','','[]','天末題詩望故鄉，碧雲煙樹兩茫茫。',64,'全唐诗/poet.song.74000.json','["天末題詩望故鄉，碧雲煙樹兩茫茫。", "青山九折屢回首，杜宇一聲還斷腸。", "別後已成千萬恨，書來不寄兩三行。", "江南春盡頻相憶，爲有楊梅欲共嘗。"]'),
('98749293-81b3-4cd4-a0a0-f2446f452485','仲秋席上呈張幾仲','趙鼎臣','宋','宋诗','song-poetry','','[]','父老歡呼夾道周，將軍喜色在眉頭。',64,'全唐诗/poet.song.74000.json','["父老歡呼夾道周，將軍喜色在眉頭。", "臨邊已見三開府，翫月何妨七倚樓。", "盛事珠璣交履舄，豐年酒肉到耡耰。", "請公徑作通宵飲，今夜何須秉燭遊。"]'),
('2fab3fed-9b7a-449d-8875-f812c29f710c','九日張師席上次韵志康','趙鼎臣','宋','宋诗','song-poetry','','[]','重陽何處可銜盃，瀛海新成百尺臺。',64,'全唐诗/poet.song.74000.json','["重陽何處可銜盃，瀛海新成百尺臺。", "白雁迎霜前日到，黄花冒雨一時開。", "籬邊歲歲民同樂，塞外年年上倚才。", "况有登高能賦客，孫郎聲價擅天台。"]'),
('c584a5a3-4308-4e0c-be4e-655ea4c689f5','次韵張衡父冬夕書事','趙鼎臣','宋','宋诗','song-poetry','','[]','橫笛休吹且當撾，幽人夢短不禁茶。',64,'全唐诗/poet.song.74000.json','["橫笛休吹且當撾，幽人夢短不禁茶。", "風琴不鼓自成曲，雪蘂無香猶是花。", "瑚璉少時輕子貢，鷦鷯此日慕張華。", "勞生正是南飛雁，秋去春來詎有涯。"]'),
('2b3dea74-4ae3-4199-94c6-b879e0438b7e','二十二日泛舟曹娥江至蔡家山以晚潮將至趨陸至白宋堰遂復登舟','趙鼎臣','宋','宋诗','song-poetry','','[]','區區州縣信徒勞，今日天涯倍寂寥。',64,'全唐诗/poet.song.74000.json','["區區州縣信徒勞，今日天涯倍寂寥。", "流水有溪皆赴海，泛舟無處不乘潮。", "登臨初識山川險，來往空悲歲月消。", "但可此身長得飽，不妨斗米折吾腰。"]'),
('5bc4486f-9fd2-4ccd-b38a-9a77ec324897','九月一日舟次雍邱次翟靜叔韵','趙鼎臣','宋','宋诗','song-poetry','','[]','砌下蛩聲日夜催，秋之爲氣信悲哉。',64,'全唐诗/poet.song.74000.json','["砌下蛩聲日夜催，秋之爲氣信悲哉。", "西風不送愁歸去，白髮能將老到來。", "涸轍久知吾有命，壯圖今見子方開。", "相寬更辱新詩句，川上難忘逝者哀。"]'),
('6d67fe61-0d6a-4a75-925e-c55d3b8bac0b','次岢嵐軍寄保德倅同年王粹公','趙鼎臣','宋','宋诗','song-poetry','','[]','一舍相望馬不前，秋風搔首故依然。',64,'全唐诗/poet.song.74000.json','["一舍相望馬不前，秋風搔首故依然。", "江湖流落三千里，筆硯追隨二十年。", "歎我塵埃凋髮齒，知君卜築近林泉。", "生涯粗足能歸否，老大何妨不著鞭。"]'),
('fb69aa45-3451-498b-aa61-632485e6ce2e','是日晚次晉祠日已暮矣有客呼門甚急問之則陽曲尉高履伯祥也不鄙謂余置酒敘別感其志意以詩贈之高嘗客河間河間帥南陽公以一飯禮焉高每語余未始不感激也故見于卒章','趙鼎臣','宋','宋诗','song-poetry','','[]','匹馬青衫忽叩門，山前燈火已黄昏。',64,'全唐诗/poet.song.74000.json','["匹馬青衫忽叩門，山前燈火已黄昏。", "蒼顔白髮身雖老，白酒黄鷄意尚存。", "醉裏未嘗呵李廣，遠來獨肯送陳蕃。", "要敦薄俗惟君可，感激猶懷一飯恩。"]'),
('25bbf820-b5a4-4430-9721-dc37a574b7eb','塞下','趙鼎臣','宋','宋诗','song-poetry','','[]','相逢奔走兩河壖，來往空驚月再圓。',64,'全唐诗/poet.song.74000.json','["相逢奔走兩河壖，來往空驚月再圓。", "王事敢辭同契闊，客遊還喜共周旋。", "暮行野岸泥三尺，夜宿人家屋一椽。", "歸看彭郎應大笑，東軒何事不留連。"]'),
('3eebee11-54a3-47b6-9af1-5171871b2b36','任邱道中值雪贈權邑宰曹弋取道曹河間同僚也  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','驊騮終日在道路，鸚鵡一生遭網羅。',64,'全唐诗/poet.song.74000.json','["驊騮終日在道路，鸚鵡一生遭網羅。", "諸公但欲選才耳，明府其如多事何。", "釜中烹魚莫倉卒，車下叩角徒悲歌。", "寄書請問皇華使，今日誰堪政事科。"]'),
('758f8624-979c-4be0-a15c-e1b05281bad4','任邱道中值雪贈權邑宰曹弋取道曹河間同僚也  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','塞南塞北平如掌，冬後冬前暖似春。',64,'全唐诗/poet.song.74000.json','["塞南塞北平如掌，冬後冬前暖似春。", "鷄唱曉聲頻送客，雪藏歸路苦留人。", "論交自覺于詩薄，投分誰知與酒親。", "恐被應劉來覓句，故看子建乞諸鄰。"]'),
('d0d468f2-a1a4-4d37-be0c-ace117c35279','上恭祀圜丘天宇晴霽既慶成數日乃得小雪御製喜雪詩示羣臣代人次韵擬和','趙鼎臣','宋','宋诗','song-poetry','','[]','都人夾道袂成陰，護駕爭看萬羽林。',64,'全唐诗/poet.song.74000.json','["都人夾道袂成陰，護駕爭看萬羽林。", "放仗端門歸內早，飛花梁苑慰民深。", "雨暘時若皆天意，夙夜惟寅本帝心。", "赤子但聞歌擊壤，未知何以報君臨。"]'),
('f2a54c48-768b-40c2-b88a-d3bb1494c354','代擬和御製喜雪詩','趙鼎臣','宋','宋诗','song-poetry','','[]','朝罷正元改歲華，都城飛雪夜如沙。',64,'全唐诗/poet.song.74000.json','["朝罷正元改歲華，都城飛雪夜如沙。", "似知天上焦勞意，來作人間散漫花。", "和氣與春生畎畝，恩波隨地徹荒遐。", "君王只爲豐年喜，二月何妨見草芽。"]'),
('a2600192-5129-4a3a-9abf-982774c2525b','喜雪上王尹','趙鼎臣','宋','宋诗','song-poetry','','[]','一封細札下明光，幕府匆匆夜促裝。',64,'全唐诗/poet.song.74000.json','["一封細札下明光，幕府匆匆夜促裝。", "天子賜書追賈馬，師臣草制拜龔黄。", "東都已散隨車雪，西雒初留聽訟棠。", "三日造朝真未速，方須杞梓構明堂。"]'),
('6d4ae44b-6b44-4a15-9b95-22079146cd5b','客舍喜雪呈邵稽仲','趙鼎臣','宋','宋诗','song-poetry','','[]','和氣先來慰旅人，中宵溫暖便知春。',64,'全唐诗/poet.song.74000.json','["和氣先來慰旅人，中宵溫暖便知春。", "但疑造化回天地，豈料風雲動鬼神。", "洗濯萌芽歸草木，掃除瘴癘入埃塵。", "隔牆似聽閭閻說，邵父朝來喜色新。"]'),
('92bbab37-ff37-4e26-aa54-dca3c1c2853b','再和二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','天上紛紛地上勻，攙先來作塞垣春。',64,'全唐诗/poet.song.74000.json','["天上紛紛地上勻，攙先來作塞垣春。", "不憂病客衣無褐，要助詩翁筆有神。", "且可留連遮瓦礫，莫教容易雜泥塵。", "悔將布鼓雷門過，謝罪從今欲自新。"]'),
('519fe1e7-b630-4ff1-8da9-70f826abaef9','再和二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','冬來玉燭更調勻，傍歲先教雪報春。',64,'全唐诗/poet.song.74000.json','["冬來玉燭更調勻，傍歲先教雪報春。", "色借樓臺呈氣象，力欺狐兔失精神。", "故應桃李知陰德，聊許冰霜作後塵。", "不用漁蓑苦圖畫，使君詩句自清新。"]'),
('c59f5253-19a3-422d-b832-9f02c315fb01','次韵邵稽仲喜雪詩','趙鼎臣','宋','宋诗','song-poetry','','[]','真是銀河落半空，天公捨施作年豐。',64,'全唐诗/poet.song.74000.json','["真是銀河落半空，天公捨施作年豐。", "巧心未到芳菲處，飽意先歸稼穡中。", "積素乍憑風凜凜，流膏應待日融融。", "更須今夜邀明月，要看清光幾許同。"]'),
('ed903766-817d-4317-8788-24b62ead3aef','去冬張若水伯奮以雪詩示余懶不暇和張屢趣之因謾謂張候有雪當奉和二月五日平旦雪數寸遽作此詩','趙鼎臣','宋','宋诗','song-poetry','','[]','春分猶著御冬衣，寒色憑陵暖自遲。',64,'全唐诗/poet.song.74000.json','["春分猶著御冬衣，寒色憑陵暖自遲。", "入眼未教花惱客，斷腸先被雪催詩。", "酒中有聖曾何敢，醉裏尋鄉自不辭。", "柳絮因風佳句在，報君已負一年期。"]'),
('1e23ac95-f7bc-4d76-ad24-e0e377b9b0f2','憫旱','趙鼎臣','宋','宋诗','song-poetry','','[]','陌上行人欲飲冰，常年四月未炎蒸。',64,'全唐诗/poet.song.74000.json','["陌上行人欲飲冰，常年四月未炎蒸。", "熱因常侍雖無據，塵類元規自可憎。", "南畝望雲心激烈，老巫當午氣憑陵。", "故應此旱由風伯，訟汝于天豈不能。"]'),
('9521c148-53fc-49ce-836d-324020f5dfab','耿伯順用趨字韵作苦雨詩次韵答之','趙鼎臣','宋','宋诗','song-poetry','','[]','天公作雨萬龍趨，倒捲黄河不用符。',64,'全唐诗/poet.song.74000.json','["天公作雨萬龍趨，倒捲黄河不用符。", "鶴集東山興婦嘆，水添北海助鵬圖。", "轉緣泥淖嗟疲懦，賡和篇章愧淺膚。", "夜報燈花雙蘂好，忽驚簷溜曉來無。"]'),
('68a142fa-622d-4324-b36d-2bf38c3fa23b','送韓存思誠出守永嘉并寄同年周恭叔','趙鼎臣','宋','宋诗','song-poetry','','[]','雁蕩山前萬壑趨，故人新剖左魚符。',64,'全唐诗/poet.song.74000.json','["雁蕩山前萬壑趨，故人新剖左魚符。", "眼中風物皆詩句，到處溪山是畫圖。", "柑子剩量金尺寸，荔支遠致玉肌膚。", "謝公巖畔因行樂，借問周郎好在無。"]'),
('bf9f29c8-3ac3-482e-b9aa-6ebdb8b1d08b','耿伯順見和趨字韵詩次韵謝之','趙鼎臣','宋','宋诗','song-poetry','','[]','白頭冉冉省中趨，欲乞君王竹使符。',64,'全唐诗/poet.song.74000.json','["白頭冉冉省中趨，欲乞君王竹使符。", "漸覺求田真上策，絕知躍馬太狂圖。", "不妨書籍時遮眼，已免蚊虻夜噆膚。", "老矣尚思交勝友，平生此意未全無。"]'),
('bd05d1d5-bfc9-4138-96f0-c0625d644e8a','何得之見和次韵謝之','趙鼎臣','宋','宋诗','song-poetry','','[]','天府春來接步趨，立談意氣偶相符。',64,'全唐诗/poet.song.74000.json','["天府春來接步趨，立談意氣偶相符。", "詩名高似三都賦，句法嚴於八陣圖。", "數仞未容窺閫奧，一斑猶喜見皮膚。", "不嫌俗客塵埃甚，時許篇章到我無。"]'),
('540a3690-4162-4546-b369-616947e370ea','韓循之治守安陽以病求代詔以其子衛尉少卿肖胄似夫爲安陽守以詩送之','趙鼎臣','宋','宋诗','song-poetry','','[]','入戲萊衣問起居，出班條教吏民趨。',64,'全唐诗/poet.song.74000.json','["入戲萊衣問起居，出班條教吏民趨。", "韋平繼世調金鼎，父子同時合虎符。", "一姓連書三守貴，兩轓今見四輪朱。", "須將盛事煩耆舊，晝錦堂中作畫圖。"]'),
('a88d89c7-faa8-4d47-8e1a-b0c605198488','送趙勝非出守濰州','趙鼎臣','宋','宋诗','song-poetry','','[]','五十專城鬢尚青，左符分得意縱橫。',64,'全唐诗/poet.song.74000.json','["五十專城鬢尚青，左符分得意縱橫。", "吏民猶記孔北海，宗室誰如劉更生。", "秋到郡樓和月上，花開後院带春行。", "何時我亦驅千騎，得傍三齊作附城。"]'),
('53aaa458-6f98-4de2-bb92-3adf9332a96c','送何亨老以直秘閣出守毗陵','趙鼎臣','宋','宋诗','song-poetry','','[]','爲郎歲久坐無氈，夢想扁舟眼欲穿。',64,'全唐诗/poet.song.74000.json','["爲郎歲久坐無氈，夢想扁舟眼欲穿。", "得郡更兼天祿閣，逢人先說惠山泉。", "欲知炙味余雖勇，爭下鞭梢子獨先。", "別後若爲相憶處，大江南畔月嬋娟。"]'),
('71e437c9-79b6-4ed4-a36b-afba6f147720','送李元量知池州','趙鼎臣','宋','宋诗','song-poetry','','[]','傳聞喜色動周邦，日日江邊望節幢。',64,'全唐诗/poet.song.74000.json','["傳聞喜色動周邦，日日江邊望節幢。", "天下文章曾第一，關西材氣本無雙。", "好栽紅藥歸持橐，却駕朱幡遠渡江。", "千里不須勞筆力，從來九鼎尚能扛。"]'),
('e52bb10d-9dd9-4644-af6c-9eb6c0521786','送柳叔達侍知福州','趙鼎臣','宋','宋诗','song-poetry','','[]','山到甌閩特地奇，滿城樓觀碧參差。',64,'全唐诗/poet.song.74000.json','["山到甌閩特地奇，滿城樓觀碧參差。", "勝游入眼如甘蔗，喜色逢人說荔枝。", "痛飲莫辜千日酒，劇談聊付一枰棋。", "侍郎豈弟如慈父，想見邦人不忍欺。"]'),
('19fbc190-bf0a-4ea4-bd54-5bb5787d3a30','送同舍朱君彥明奉使東南措置銅事','趙鼎臣','宋','宋诗','song-poetry','','[]','天邊使節動星辰，銜命歸家得意新。',64,'全唐诗/poet.song.74000.json','["天邊使節動星辰，銜命歸家得意新。", "負弩不須煩縣令，揮金聊復燕鄉人。", "錦衣行處江天曉，華表歸時社樹春。", "暫試銅山陶鑄手，速應西上莫逡巡。"]'),
('e01e7682-b69a-43a2-855c-695a1491f999','送王取道二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','仁如堯舜聖天子，孝似騫參賢使君。',64,'全唐诗/poet.song.74000.json','["仁如堯舜聖天子，孝似騫參賢使君。", "拜章北闕墨尚濕，刻印東州符已分。", "從今懽笑對黄髮，不復咨嗟看白雲。", "知公閉閣坐自了，比屋孝弟皆欣欣。"]'),
('d2ff2f90-813d-49f1-a2d4-5e9499285ece','送王取道二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','凜然孝子與忠臣，恩義雙全在一身。',64,'全唐诗/poet.song.74000.json','["凜然孝子與忠臣，恩義雙全在一身。", "來作會稽千里雨，去爲東武萬家春。", "定將清浄安齊俗，空有謳歌戴越民。", "想過故鄉須少駐，曉行方見錦衣新。"]'),
('c39af760-62da-4f23-967b-cbdc99be0169','送蘇師德主簿領赴官和州','趙鼎臣','宋','宋诗','song-poetry','','[]','眼看汗血已成駒，忽泛扁舟興不疏。',64,'全唐诗/poet.song.74000.json','["眼看汗血已成駒，忽泛扁舟興不疏。", "官小自應親簿領，政成當遣樂樵漁。", "舉行詩禮爲家法，收拾江山作俸餘。", "蘋滿汀洲相憶處，秋風寄取一行書。"]'),
('0bf3eb46-f95d-4d8f-87a0-87c57cf6cbde','美之得免西行喜甚以韵見報因賀之美之嘗許候得報即置酒故見於卒章','趙鼎臣','宋','宋诗','song-poetry','','[]','喜報征車已罷休，解鞍聊足放眉頭。',64,'全唐诗/poet.song.74000.json','["喜報征車已罷休，解鞍聊足放眉頭。", "異時安石難高卧，此日相如固倦游。", "花恨春遲方半吐，雲欺風弱未全收。", "正須麴糵相料理，萬斛舟中試拍浮。"]'),
('9be9d8d8-fe81-4677-a0b1-bfa3f4c3549a','次韵仲兄美之喜歸二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','好在青山隠翠眉，遥知不負芰荷衣。',64,'全唐诗/poet.song.74000.json','["好在青山隠翠眉，遥知不負芰荷衣。", "越吟凄斷終懷本，宋鷁徘徊故倦飛。", "世路百憂無似客，人情萬事莫如歸。", "况逢鄴下多才子，剩判流霞醉落暉。"]'),
('d277c78c-ae8a-4216-b9fd-debb3ae96cbe','次韵仲兄美之喜歸二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','纖纖楊葉舞脩眉，珍重煙光惹客衣。',64,'全唐诗/poet.song.74000.json','["纖纖楊葉舞脩眉，珍重煙光惹客衣。", "碧杏梢頭鶑百囀，黄茅簷外燕雙飛。", "自諳漁父醒猶醉，莫怨劉郎去又歸。", "今日正南驅馬首，未饒陰藿向陽暉。"]'),
('31fd4764-9e32-4909-a5e6-4c37e83120ee','張子儀以省員罷官若不釋然者以詩勉之','趙鼎臣','宋','宋诗','song-poetry','','[]','折腰斗米笑徒勞，薄宦何能損一毛。',64,'全唐诗/poet.song.74000.json','["折腰斗米笑徒勞，薄宦何能損一毛。", "他日未應忘令尹，今年還是省東曹。", "溟鵾得水鱗終變，韝鶚逢秋勢必高。", "隋岸春深好楊柳，莫將歸思滯江皋。"]'),
('1f5e9f8d-0c15-4d3d-8e6f-83d5bc3376d1','次韵前南陽太守王傳翁','趙鼎臣','宋','宋诗','song-poetry','','[]','當年五馬富才華，百斛珠璣在咄嗟。',64,'全唐诗/poet.song.74000.json','["當年五馬富才華，百斛珠璣在咄嗟。", "陌上行春迎曉日，樓頭待月送餘霞。", "屢聞田父歌遺愛，時有游人指漸嘉。", "笑殺即今癡太守，二毛憔悴眼昏花。"]'),
('9df43b04-fb9a-4586-9d8f-1815eb63cecf','寄武景才','趙鼎臣','宋','宋诗','song-poetry','','[]','清漳北去水滔滔，一舍相望倍鬰陶。',64,'全唐诗/poet.song.74000.json','["清漳北去水滔滔，一舍相望倍鬰陶。", "腐肉豈宜攖利劍，小鷄聊用試牛刀。", "馮驩久客彈長鋏，揚子多愁賦廣騷。", "無限秋風助佳興，故人不見我心勞。"]'),
('56b6f03d-b046-4755-a7a7-dd82fd22b37b','鄉人胡舜舉見和再次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','咳唾珠璣出緒餘，舊傳詞賦壓三都。',64,'全唐诗/poet.song.74000.json','["咳唾珠璣出緒餘，舊傳詞賦壓三都。", "先生年輩如今少，鄉里人情似舊無。", "睡思不禁詩作惱，衰顔正頼酒塗糊。", "他年雞黍陪鄉社，愧我空空一鄙夫。"]'),
('f41454c7-a591-4146-8823-d64b42bce628','次韵翟二淳老見寄','趙鼎臣','宋','宋诗','song-poetry','','[]','十年不到魯東門，歸夢長隨酒半醺。',64,'全唐诗/poet.song.74000.json','["十年不到魯東門，歸夢長隨酒半醺。", "後進頗能欺俗吏，故交獨肯寄高文。", "老貪北闕千鍾米，興在西山一段雲。", "欲乞此身南畝去，移書先報葦溪聞。"]'),
('9c930faf-dc24-4c01-ba6d-c6e18f91550a','次韵翟淳老','趙鼎臣','宋','宋诗','song-poetry','','[]','白髮爲郎亦偶然，戴盆何敢望青天。',64,'全唐诗/poet.song.74000.json','["白髮爲郎亦偶然，戴盆何敢望青天。", "簿書不足妨談麈，稍入聊能續爨煙。", "竹隠逢秋應怨鶴，葦溪過雨欲生蓮。", "一籌太息輸吾子，老圃堂成在我先。"]'),
('082dc8c9-4cc7-480a-87f9-10daaa68aa60','次韵夏倪均父見和轅字韵詩六首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','浩然骨冷但孤墳，疏雨梧桐句法存。',64,'全唐诗/poet.song.74000.json','["浩然骨冷但孤墳，疏雨梧桐句法存。", "忽見新詩來故里，錯疑夫子是諸孫。", "江頭春暖堪乘興，洲上花開不掩門。", "日日城南望消息，僕夫爲我取征轅。"]'),
('0594933d-ff6f-4eac-b1b0-3e4eb034e4f8','次韵夏倪均父見和轅字韵詩六首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','南都詞賦舊傳聞，但有風流梗槩存。',64,'全唐诗/poet.song.74000.json','["南都詞賦舊傳聞，但有風流梗槩存。", "花徑逢春張錦繡，竹林過雨長兒孫。", "跨城樓觀雲連夜，隔岸人家水映門。", "正要子詩彈壓在，不應無事滯輪轅。"]'),
('e2274435-e64b-4db6-ae12-caec380055ad','次韵夏倪均父見和轅字韵詩六首  其三','趙鼎臣','宋','宋诗','song-poetry','','[]','織女機頭五色紋，裁成錦段遠相存。',64,'全唐诗/poet.song.74000.json','["織女機頭五色紋，裁成錦段遠相存。", "篇篇境界如甘蔗，一一詞章是外孫。", "載酒有人曾問字，談詩無客敢登門。", "可憐衰病南陽守，强駕疲牛逐後轅。"]'),
('6b8c0aa5-57ff-4f15-b39c-4d94fca48831','次韵夏倪均父見和轅字韵詩六首  其四','趙鼎臣','宋','宋诗','song-poetry','','[]','眼看花枝作霧昏，年來無復壯心存。',64,'全唐诗/poet.song.74000.json','["眼看花枝作霧昏，年來無復壯心存。", "酒盃屢諫愁聽婦，丁口新添喜到孫。", "攬鏡自憐霜鬢叟，閉關誰顧雀羅門。", "乘車强欲班春去，野老携壺許傍轅。"]'),
('939ba298-7631-49fd-9985-1ca83716723e','次韵夏倪均父見和轅字韵詩六首  其五','趙鼎臣','宋','宋诗','song-poetry','','[]','西郊不雨屢占雲，撫字區區志頗存。',64,'全唐诗/poet.song.74000.json','["西郊不雨屢占雲，撫字區區志頗存。", "未暇溉田如召父，翻愁告糴遣臧孫。", "願聞滂沛流鴛瓦，相見歡呼動蓽門。", "乞與高文訟風伯，卧龍何事敢停轅。"]'),
('44c7bcba-1110-46db-bd55-0c4fd52aac7b','次韵夏倪均父見和轅字韵詩六首  其六','趙鼎臣','宋','宋诗','song-poetry','','[]','何郎宿草已生墳，常老題詩翰墨存。',64,'全唐诗/poet.song.74000.json','["何郎宿草已生墳，常老題詩翰墨存。", "陶令一生惟愛酒，孟郊千古遂無孫。", "探花梁苑春騎馬，踏雪繁臺夜叩門。", "欲覓舊游何處在，故人不見漫回轅。"]'),
('e8b4747f-9773-4868-9c46-42d9448c6e8f','贈王正叔','趙鼎臣','宋','宋诗','song-poetry','','[]','百年圖史富縱橫，痛飲狂歌過一生。',64,'全唐诗/poet.song.74000.json','["百年圖史富縱橫，痛飲狂歌過一生。", "稷下先生初應詔，關西夫子舊知名。", "乘槎不覺侵霄漢，枕石終思返釣耕。", "好遣家童報消息，曉猿無事莫相驚。"]'),
('674a9421-cc6e-402f-a50d-2d681b6ae127','少夷見和戲以其韵贈之','趙鼎臣','宋','宋诗','song-poetry','','[]','南郭先生心似灰，一官偶向此間來。',64,'全唐诗/poet.song.74000.json','["南郭先生心似灰，一官偶向此間來。", "詩才舉世當歸遜，德行何人敢望回。", "三徑就荒知有命，十年不調惜無媒。", "更添貧病相料理，頗遣黄花近酒盃。"]'),
('9db614b1-4b9d-4239-b2dc-d79cce36d447','次韵趙伯山見贈','趙鼎臣','宋','宋诗','song-poetry','','[]','十年眉宇記清揚，班列爭看玉照行。',64,'全唐诗/poet.song.74000.json','["十年眉宇記清揚，班列爭看玉照行。", "奏雅不應參鄭衛，論交何必減潘楊。", "老妻釀酒新知法，稚子扶犁漸肯堂。", "心計此身歸已足，不須辛苦問耕桑。"]'),
('38605003-e420-4011-8310-d50573fafb9c','寄楊時可許少尹時有從兄之喪','趙鼎臣','宋','宋诗','song-poetry','','[]','憂患相隨不少寬，出門贏得淚汍瀾。',64,'全唐诗/poet.song.74000.json','["憂患相隨不少寬，出門贏得淚汍瀾。", "豈知桃李爭春色，但覺塵埃逐馬鞍。", "客裏自應書問少，老來尤念別離難。", "故人曾解相思否，乞取相思過眼看。"]'),
('9514ccb0-f616-4f8d-9a7d-54a0dfebc2d5','余去冬赴南陽過尉氏以不獲見孫少魏爲恨近於同僚處見孫詩次韵寄之','趙鼎臣','宋','宋诗','song-poetry','','[]','髮如黑漆未成翁，野鶴孤高不受籠。',64,'全唐诗/poet.song.74000.json','["髮如黑漆未成翁，野鶴孤高不受籠。", "踠足自疑天宇隘，舉鞭可但冀羣空。", "閑吟秀句邀詩客，自協新聲按舞童。", "已卜異時干典謁，莫嫌俗士不教通。"]'),
('9e490baf-9446-4eb2-b3c8-c05125518442','寄外兄張會之','趙鼎臣','宋','宋诗','song-poetry','','[]','與兄憔悴各他鄉，細數平生可斷腸。',64,'全唐诗/poet.song.74000.json','["與兄憔悴各他鄉，細數平生可斷腸。", "少日父兄俱過隙，老來兒女忽成行。", "夢游湖北心常折，身在周南鬢已蒼。", "莫向秋風原上望，脊令飛墮轉悲凉。"]'),
('2263c365-e041-4918-b819-36cad6b28dba','贈如璧長老二首  其一','趙鼎臣','宋','宋诗','song-poetry','','[]','少游太學饒夫子，老倚清松璧上人。',64,'全唐诗/poet.song.74000.json','["少游太學饒夫子，老倚清松璧上人。", "好與惠休爲後嗣，直疑賈島是前身。", "浮萍暫聚曾交臂，獨鶴孤飛遂絕塵。", "肯念故人今白髮，與雲出岫莫辭頻。"]'),
('128f993a-e934-4fc5-bbce-503ea43227ef','贈如璧長老二首  其二','趙鼎臣','宋','宋诗','song-poetry','','[]','自爲雲山作主人，更邀麋鹿作比鄰。',64,'全唐诗/poet.song.74000.json','["自爲雲山作主人，更邀麋鹿作比鄰。", "一齋一粥今禪伯，無姓無名古逸民。", "盡了委緣心似水，未捐習氣筆如神。", "丐師石上菖蒲節，要度人間八十春。"]'),
('2963e797-1b97-41a1-82df-b5901168632d','元祐中先人將漕淮南與長樂林旦次中爲僚其子碩儒膚與余游相好也後三十五年復相見於京師道舊涕淚已而復遣其愛子薿見過仍辱贈詩敘疇昔之好次其韵答之','趙鼎臣','宋','宋诗','song-poetry','','[]','往歲丁年戲綵同，別來幾度茁葭蓬。',64,'全唐诗/poet.song.74000.json','["往歲丁年戲綵同，別來幾度茁葭蓬。", "貧無負郭嗟吾拙，老有名駒慰子窮。", "雲斷太行雙拱木，鶴歸華表兩悲翁。", "更憐頭裏千莖雪，縱得春風不解融。"]'),
('20e582ca-4aa7-4e1e-9bd1-0a55137659a5','韓次律在許下與葉少藴唱和他日以寄余因次韵和之并以寄葉','趙鼎臣','宋','宋诗','song-poetry','','[]','尺書不獻罪何逃，每讀新詩勝讀騷。',64,'全唐诗/poet.song.74000.json','["尺書不獻罪何逃，每讀新詩勝讀騷。", "千里寄懷惟短夢，十年飲德似醇醪。", "次公治郡聲方藉，陶令拋官趣獨高。", "俗吏無緣參步武，白頭終日漫塵勞。"]'),
('cdfe89c5-b613-49ec-b012-aea5dc662c46','暇日過西曹謁何安中得之李倞沖季咸許出近詩而未也戲以詩索','趙鼎臣','宋','宋诗','song-poetry','','[]','眼看簿領眩生花，共指牆陰待日斜。',64,'全唐诗/poet.song.74000.json','["眼看簿領眩生花，共指牆陰待日斜。", "水部詩名今獨步，河梁句法舊傳家。", "未容碧海歸深闊，應許陽春辦咄嗟。", "莫爲瓊瑶生校計，古人初不廢投瓜。"]'),
('ce039fac-8093-4211-a6e0-c8b9323dfd12','司令謝兢元賜以詩見索近文且敘世舊次韵謝之','趙鼎臣','宋','宋诗','song-poetry','','[]','少年識字是天刑，妄意扶摇起北溟。',64,'全唐诗/poet.song.74000.json','["少年識字是天刑，妄意扶摇起北溟。", "我似羸羊安可駕，子如快劍不須硎。", "汗傳驥種方新赤，氈付衡門只舊青。", "滿紙惡詩將底用，爲糊新樣小圍屏。"]'),
('68b22ff6-5da1-4cd7-973f-6bd111e8a103','次韵朱琳天球','趙鼎臣','宋','宋诗','song-poetry','','[]','河鼓仙人喜欲狂，雲軿稍渡漢中央。',64,'全唐诗/poet.song.74000.json','["河鼓仙人喜欲狂，雲軿稍渡漢中央。", "應嗟此夜成弦筈，又待明年換雪霜。", "乞巧本非吾輩事，追歡已屬少年場。", "可憐愁殺朱夫子，竟夕哦詩仰屋梁。"]'),
('b66af153-25d5-40e8-9847-af8b8754abf7','春日燕百花堂有懷前太守許子大以詩戲之','趙鼎臣','宋','宋诗','song-poetry','','[]','風流誰似許南陽，人到于今尚不忘。',64,'全唐诗/poet.song.74000.json','["風流誰似許南陽，人到于今尚不忘。", "筆下涌成三峽水，胸中蓋就百花堂。", "召公棠蔭家家滿，潘令桃蹊處處芳。", "借問蔡州何所似，瓠壺形勢若爲長。"]'),
('d7c257e0-87bb-4854-8915-0d6507e12414','頃官會稽與江彥文趙勝非爲僚蓋二十餘年于今矣前日相會于庭中道舊樂勝非許以家釀餉我久而不至嘗請爲後堂之客屢矣輒復未果意者殆余請之未堅也因以詩戲之并約彥文同賦','趙鼎臣','宋','宋诗','song-poetry','','[]','天上王孫馳譽早，江南官舍結交深。',64,'全唐诗/poet.song.74000.json','["天上王孫馳譽早，江南官舍結交深。", "舉頭共惜湖山隔，屈指空驚歲月侵。", "青社欲頒從事酒，綈袍尤見故人心。", "絕聞列屋皆傾國，何日纖纖手自斟。"]'),
('5cde8274-f7e9-4b3b-a897-6ee598ddc037','既以詩乞酒於勝非而彥文云吾酒殆不減渠當以餉子九日遶菊獨對空樽而彥文使至因次前韵戲之','趙鼎臣','宋','宋诗','song-poetry','','[]','雨裏黄花愁正絕，籬邊白酒意殊深。',64,'全唐诗/poet.song.74000.json','["雨裏黄花愁正絕，籬邊白酒意殊深。", "曲拳自覺我無用，然諾誰知公不侵。", "便許餔糟真好事，獨令染指亦何心。", "小哉正恨鴟夷腹，傾倒聊堪一再斟。"]'),
('4dd2af8b-3747-4bbb-9444-993218c333b7','時可屢欲嘗白酒會有客饋余因分以餉之既而惠詩譏酒器之隘因復次深字韵爲答時可新買舞鬟甚麗而尚稚故云','趙鼎臣','宋','宋诗','song-poetry','','[]','解擯先生空儻䓪，草玄夫子獨精深。',64,'全唐诗/poet.song.74000.json','["解擯先生空儻䓪，草玄夫子獨精深。", "談詩亹亹心常折，使酒時時氣頗侵。", "欲炙已勤知子意，投醪雖儉蓋吾心。", "端知皓腕如綿弱，故遣涓涓只細斟。"]'),
('165cfb17-3f2c-452e-9b04-54bb5726afa3','朱貢父自尚書郎領憲河朔會高陽闕守因攝帥事以詩寄之且覓蟹螯','趙鼎臣','宋','宋诗','song-poetry','','[]','清渭三年伴濁涇，鴻毛一舉便冥冥。',64,'全唐诗/poet.song.74000.json','["清渭三年伴濁涇，鴻毛一舉便冥冥。", "帳前共聽將軍令，塞下爭看使者星。", "四坐應劉邀俊彥，兩行燕趙列娉婷。", "只知左手持螯美，不念貧交正獨醒。"]'),
('b2552b07-fb23-4a18-88dd-95ec62831347','史東美置酒見招偶以釋奠致齋不果往因爲詩戲之以請他日之約兼呈周與劉敏叔','趙鼎臣','宋','宋诗','song-poetry','','[]','登車未肯便埋輪，置酒邀賓一笑春。',64,'全唐诗/poet.song.74000.json','["登車未肯便埋輪，置酒邀賓一笑春。", "北海尊罍知意重，太常官職恨齋頻。", "愁霖已逐清歡失，勝槩空隨好夢新。", "喚取江潭憔悴客，莫教偏作獨醒人。"]'),
('dae14b5c-cc2a-43cf-9d99-402cb5e51da2','聞蘇叔黨至京客於高殿帥之館而未嘗相聞以詩戲之','趙鼎臣','宋','宋诗','song-poetry','','[]','小坡不見二年餘，聞到都城信有諸。',64,'全唐诗/poet.song.74000.json','["小坡不見二年餘，聞到都城信有諸。", "雪裏便回非興盡，魚中不寄是情疏。", "朱門但識將軍第，陋巷難逢長者車。", "別後欲知安否在，試憑青鳥問何如。"]'),
('3f28489e-5368-4318-b87b-e0cf65a0dc1f','走筆謝仲達餉新橘詩','趙鼎臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','薄暮傳呼使者忙，兒童顛倒著衣裳。',64,'全唐诗/poet.song.74000.json','["薄暮傳呼使者忙，兒童顛倒著衣裳。", "花開鐵樹何曾識，棗熟東家漫得嘗。", "厭客欲開丞相閣，絕交先寄洞庭香。", "直須載酒同君飲，免使繁枝怨曉霜。"]'),
('0fea1e33-75fa-4cc4-baee-b23cd587c8be','代擬和御製睿思殿賜宴賞金橘詩','趙鼎臣','宋','宋诗','song-poetry','','[]','帝燕蓬萊月最良，廣寒仙部出中房。',64,'全唐诗/poet.song.74000.json','["帝燕蓬萊月最良，廣寒仙部出中房。", "浥霜火齊纍纍熟，噀霧金苞冉冉香。", "地向江南移茂苑，人於天下醉清觴。", "願因嘉果論忠孝，報國丹心敢暫忘。"]'),
('9a4ebb19-2b91-4a20-ac84-84a0317657a8','東坡兄弟應制舉日各携硯一入對廷中而黄門之硯爲其甥文驥所寶好事者往往有詩文以請余故亦同賦','趙鼎臣','宋','宋诗','song-poetry','','[]','不見東坡老弟昆，文章浩蕩失淵源。',64,'全唐诗/poet.song.74000.json','["不見東坡老弟昆，文章浩蕩失淵源。", "眉山當日人何在，曲阜他年履尚存。", "試想研磨雖有處，欲尋斧鑿見無痕。", "計功何必慚周鼎，會使詞林百怪奔。"]'),
('8fa9e2a8-ce3d-40eb-b9a5-792d56b19364','馬宗玉教授自大名考進士歸以詩贈之','趙鼎臣','宋','宋诗','song-poetry','','[]','清世誰人怨考槃，喜聞明詔競彈冠。',64,'全唐诗/poet.song.74000.json','["清世誰人怨考槃，喜聞明詔競彈冠。", "文章得路呈身易，衡石當前下筆難。", "盡拔靈珠滄海暗，獨橫長劍曉天寒。", "知君故是掄才手，擬抱焦桐一問看。"]'),
('aab08470-af49-4128-8238-0ccea941be0d','辛丑二月二十四日以故事被檄詣貢院榜下訶止觀者五鼓至院前榜未出假寐門臺之上忽憶秦夷行在院中因作小詩戲之預約西池之游秦出當以呈也','趙鼎臣','宋','宋诗','song-poetry','','[]','不妨骯髒倚朱門，坐睡聊醒宿酒醺。',64,'全唐诗/poet.song.74000.json','["不妨骯髒倚朱門，坐睡聊醒宿酒醺。", "顧我尚猶堪禦侮，逢公那敢更論文。", "水添池面今三尺，花減春光已二分。", "頗許韓非同傳否，西城行樂念相聞。"]'),
('724e28a9-ddbb-4de4-818a-850ac430a329','榜出即事戲成','趙鼎臣','宋','宋诗','song-poetry','','[]','黄紙爭看淡墨書，人人自恐姓名無。',64,'全唐诗/poet.song.74000.json','["黄紙爭看淡墨書，人人自恐姓名無。", "用心正似爭蠻觸，出手何如得雉盧。", "路入廣寒人共羨，捷傳城濮氣爭呼。", "回思三十年前事，華髮蕭蕭一病夫。"]'),
('3d2f487f-e5ff-4918-aac6-3829300da2e8','奇將赴廷試用韵','趙鼎臣','宋','宋诗','song-poetry','','[]','憶昔先公一束書，起家儋石向來無。',64,'全唐诗/poet.song.74000.json','["憶昔先公一束書，起家儋石向來無。", "子孫但欲傳倉庫，婚嫁何曾議鄭盧。", "孝弟一門貧自樂，科名三世喜相呼。", "更須力獻平津策，奪取龍頭慰老夫。"]'),
('b5e279b3-6e66-4d8d-be56-00d10df80d69','育下第用前韵示之','趙鼎臣','宋','宋诗','song-poetry','','[]','人生當讀五車書，一第區區汝豈無。',64,'全唐诗/poet.song.74000.json','["人生當讀五車書，一第區區汝豈無。", "但可三冬長足史，何須一擲便成盧。", "少年决戰雖當力，健將銜枚不用呼。", "莫共癡兒論𦙤臊，不能再鼓定非夫。"]'),
('502aa5df-11b6-4cc4-b29a-5b789c3184d3','容之在藁城聞欲從帥辟用前韵戲之','趙鼎臣','宋','宋诗','song-poetry','','[]','使者爭飛薦鶚書，論才何止朔方無。',64,'全唐诗/poet.song.74000.json','["使者爭飛薦鶚書，論才何止朔方無。", "從軍更欲投毛穎，仗劍還思跨的盧。", "塞北吏民方眷戀，晉陽耆舊已歡呼。", "可憐公綽堪廊廟，漫作區區薛大夫。"]'),
('1edbe9aa-fff2-497f-baf6-ce9215b1de8c','再賦杉字韵呈美之','趙鼎臣','宋','宋诗','song-poetry','','[]','高卧終朝對碧巉，肯將志氣逐塵凡。',64,'全唐诗/poet.song.74000.json','["高卧終朝對碧巉，肯將志氣逐塵凡。", "眼穿斜谷雙蓬鬢，身在長安一布衫。", "未把漁竿栖漢瀨，定隨霖雨起商巖。", "明堂有日求梁棟，認取凌雲萬丈杉。"]'),
('3114c28a-0f8c-48c2-95ed-bb629108cf0a','閏月中澣與諸客會於葆真宮鄭顧道有詩次韵','趙鼎臣','宋','宋诗','song-poetry','','[]','野性宜將寂寞濱，林間景物倍曾親。',64,'全唐诗/poet.song.74000.json','["野性宜將寂寞濱，林間景物倍曾親。", "逢棋便可消長日，下馬何妨問主人。", "雨過夏畦供饌美，風來水閣送凉新。", "重遊更待秋風起，凈掃池頭醉一巡。"]'),
('7013a485-d06f-4e05-b040-97051ee325df','汪彥文以葆真韵見贈次韵答之','趙鼎臣','宋','宋诗','song-poetry','','[]','少年傾蓋海之濱，白髮相逢意轉親。',64,'全唐诗/poet.song.74000.json','["少年傾蓋海之濱，白髮相逢意轉親。", "三伏偶乘偷暇日，一枰聊作暫閑人。", "官清已怪腰金晚，詩好因緣夢筆新。", "火急著成封禪頌，屬車方欲議東巡。"]'),
('2dafbeb8-0e3e-4ac8-8297-00062f1d1b70','七月朔集于河沙方允迪辭疾不至已而聞新買妾甚美用葆真韵作俚語戲之','趙鼎臣','宋','宋诗','song-poetry','','[]','解佩時時夢漢濱，不將喜事報交親。',64,'全唐诗/poet.song.74000.json','["解佩時時夢漢濱，不將喜事報交親。", "圍棋頼作爭先客，買妾方成得意人。", "乍看梳裝傳內樣，剩供頭面買時新。", "拚須一醉金釵側，莫向罇前著暗巡。"]'),
('4033f2b2-a472-4d40-bc2f-8642654c91ab','楊時可蘇在廷家有聲伎之奉而又俱爲秋官屬諸公方以詩請之余恨未嘗識蘇然時可邀使同賦故亦用此韵','趙鼎臣','宋','宋诗','song-poetry','','[]','文章華翰九天開，二妙同時在一臺。',64,'全唐诗/poet.song.74000.json','["文章華翰九天開，二妙同時在一臺。", "高會競看文陣合，後堂新許客星來。", "評詩故自當歸遜，在寢何容敢望回。", "已請杏花留一笑，不勞羯鼓橫相催。"]'),
('6adc7aa8-7c2a-414b-b8ac-ca9c020bf5b0','賀韓子蒼遷居','趙鼎臣','宋','宋诗','song-poetry','','[]','南鄰歌舞北鄰呼，藏室仙人肯卜居。',64,'全唐诗/poet.song.74000.json','["南鄰歌舞北鄰呼，藏室仙人肯卜居。", "著撰初無千斛米，般移空有五車書。", "烏來屋上看殊好，燕集梁間喜有餘。", "莫把先生輕相料，錦囊猶自可專車。"]'),
('66ca555e-69dd-408a-9e00-7256616ff827','山中即事','趙鼎臣','宋','宋诗','song-poetry','','[]','山谷崎嶇路寂寥，我行今日是何朝。',64,'全唐诗/poet.song.74000.json','["山谷崎嶇路寂寥，我行今日是何朝。", "春歸陽木青先變，雪落陰崖凍不消。", "遲日映雲猶未暖，餘寒挾雨尚能驕。", "絕聞近舍村酤美，野老相逢苦見邀。"]'),
('02aa4ff5-211d-4830-94a3-a9ab29ad7b55','偶成','趙鼎臣','宋','宋诗','song-poetry','','[]','此身三十九年非，高論逡巡已少卑。',64,'全唐诗/poet.song.74000.json','["此身三十九年非，高論逡巡已少卑。", "未解營生窮似蝨，不堪作吏鈍如椎。", "春光爛熳然心火，愁緒牽連織鬢絲。", "却羨耦耕人最樂，只應沮溺是吾師。"]'),
('0ed337cb-8294-4d8f-8372-066ddd395f96','移疾','趙鼎臣','宋','宋诗','song-poetry','','[]','年來樂事不關身，藜杖繩床過了春。',64,'全唐诗/poet.song.74000.json','["年來樂事不關身，藜杖繩床過了春。", "窮在世間真有鬼，錢於我處獨無神。", "稍諳藥性都緣病，尚戀官糧只爲貧。", "不學小兒潘騎省，逢人驚怪二毛新。"]'),
('5f0faacc-1b81-4c2c-9374-10b02706e99c','不寐','趙鼎臣','宋','宋诗','song-poetry','','[]','秋光已向鬢毛催，寒色仍從枕簟來。',64,'全唐诗/poet.song.74000.json','["秋光已向鬢毛催，寒色仍從枕簟來。", "天外角聲風引去，日邊歸夢雨驚回。", "愁能醉客非關酒，老欲隨人不待媒。", "擬放此身無著處，閑時只合且銜杯。"]'),
('cae32429-a534-473a-8609-1a4603dba6b4','寄題寶應縣五柳亭','趙鼎臣','宋','宋诗','song-poetry','','[]','肯向明時事隠淪，亭邊五柳漫摇春。',64,'全唐诗/poet.song.74000.json','["肯向明時事隠淪，亭邊五柳漫摇春。", "當年未易勝今日，此地還如見古人。", "高興不隨霜葉盡，清風長與露條新。", "何妨便著先生傳，一洗淮南俗吏塵。"]'),
('6d9611c8-e710-4eef-88ba-b864907a8d32','歸雁亭','趙鼎臣','宋','宋诗','song-poetry','','[]','東風楊柳杏花飛，曾伴先生酒一巵。',64,'全唐诗/poet.song.74000.json','["東風楊柳杏花飛，曾伴先生酒一巵。", "前輩風流那復見，小亭煙雨漫相思。", "城邊春草路南北，山下河梁人別離。", "一尺短書湘水闊，年年愁絕雁歸時。"]'),
('6aedb868-a5ec-4e71-b076-4de1f0129684','錦繡亭','趙鼎臣','宋','宋诗','song-poetry','','[]','買花不惜萬錢空，點綴芳菲似畫工。',64,'全唐诗/poet.song.74000.json','["買花不惜萬錢空，點綴芳菲似畫工。", "十樣錦機翻劍外，一年春色在壺中。", "醒來莫遣風吹碧，醉裏何妨燭映紅。", "待得他年成步障，寄書來喚葦溪翁。"]'),
('bda0da10-d441-4382-8d0f-4835b815268f','大司成葛雅卿輓詩','趙鼎臣','宋','宋诗','song-poetry','','[]','兄弟同升世所難，公家伯仲盡鵷鸞。',64,'全唐诗/poet.song.74000.json','["兄弟同升世所難，公家伯仲盡鵷鸞。", "甘泉侍從雙狨坐，國子先生兩杏壇。", "丹旐隨舟千里哭，豐碑表墓萬人看。", "白頭故友空垂淚，一紙新書墨未乾。"]'),
('ffda9371-1e5e-4ae7-8390-206bb915e3a6','寄高陽宰張即功','趙鼎臣','宋','宋诗','song-poetry','','[]','方丈仙山客，高陽辯士鄉。',120,'全唐诗/poet.song.74000.json','["方丈仙山客，高陽辯士鄉。", "聖朝新命吏，茂宰近爲郎。", "烽火三關戍，塵埃百戰場。", "幽燕通聘問，蕃漢雜耕桑。", "政簡人安堵，刑清舍掩棠。", "萬家魚蟹賤，十里芰荷香。", "置酒時多暇，裁詩夜未央。", "水摇天影亂，風送角聲長。", "驟見秋雲白，相思塞草黄。", "無忘寄消息，看取雁南翔。"]'),
('76253e47-4b64-4453-87f9-66de29284ae9','九月二十六日韓弼夫與十九娘赴官郢州之京山携家出餞于城南郝氏之園席上作小詩送韓兒姪咸和','趙鼎臣','宋','宋诗','song-poetry','','[]','西風吹葉落，南浦送行人。',24,'全唐诗/poet.song.74000.json','["西風吹葉落，南浦送行人。", "白酒難留客，黄花不當春。"]'),
