('cb11a900-93b6-4cc1-a704-9629a610413e','建炎丞相成國呂忠穆公退老堂  其一','黄叔敖','宋','宋诗','song-poetry','','[]','今代勳名第一人，聊從小築藝松筠。',64,'全唐诗/poet.song.74000.json','["今代勳名第一人，聊從小築藝松筠。", "風雲天上千齡運，雨露人閒萬井春。", "莫倚丘園甘獨樂，須知海宇仰洪鈞。", "行聞勉爲蒼生起，衮繡來歸聳搢紳。"]'),
('e64788c4-1b95-480f-9dbc-e3921a0f3451','建炎丞相成國呂忠穆公退老堂  其二','黄叔敖','宋','宋诗','song-poetry','','[]','望隆江左謝太傅，功冠淮西裴晉公。',64,'全唐诗/poet.song.74000.json','["望隆江左謝太傅，功冠淮西裴晉公。", "何事東山却高卧，空餘綠野想遺風。", "矯情鎮物端誰似，晚節全身與俗同。", "再拜祝公追往轍，中興周室頼元功。"]'),
('dd9092fe-7cf7-4ba3-b1bd-a96fe1976ae6','禁苑','韓浩','宋','宋诗','song-poetry','','[]','星斗疏時禁漏殘，紫泥封後獨凭欄。',64,'全唐诗/poet.song.74000.json','["星斗疏時禁漏殘，紫泥封後獨凭欄。", "露和玉屑金盤冷，月射珠光貝闕寒。", "天襯樓臺籠苑外，風吹歌管下雲端。", "長卿祇爲長門賦，未識君王際會難。"]'),
('bd49d270-d37f-408d-a9e2-61b794c78e34','高陽道中','劉汲','宋','宋诗','song-poetry','','[]','杏花開遍野桃紅，榆柳中間一徑通。',32,'全唐诗/poet.song.74000.json','["杏花開遍野桃紅，榆柳中間一徑通。", "禽鳥不呼村塢靜，滿川烟雨晝濛濛。"]'),
('90772002-aa85-4c40-b98e-a8f4d8b9ac78','西巖','劉汲','宋','宋诗','song-poetry','','[]','卜築西巖最可人，青山爲屋水爲鄰。',64,'全唐诗/poet.song.74000.json','["卜築西巖最可人，青山爲屋水爲鄰。", "身將隠矣文何用，人不知之味更真。", "自古交游少同志，到頭聲利不關身。", "清泉便當如澠酒，澆盡胸中累劫塵。"]'),
('c5a6c5a6-ef8c-45c9-92ba-0c1b28e25728','哀隆德守臣張確確浮休張舜民之弟嘗爲烏延帥幕獨不廷謁童貫作詩弔之','滕茂實','宋','宋诗','song-poetry','','[]','睢陽萬古一張巡，忠義傳家有世臣。',64,'全唐诗/poet.song.74000.json','["睢陽萬古一張巡，忠義傳家有世臣。", "顔子伏膺當入室，潘郎望拜肯同塵。", "圍城已陷天猶晦，仗劍臨危氣益振。", "餘子鄰邦盡曹李，偷生端作九泉人。"]'),
('3e242342-2498-4c67-ab75-2baf99b2e1c2','天寧節有感','滕茂實','宋','宋诗','song-poetry','','[]','節臨重十慶天寧，古殿焚香祝帝齡。',64,'全唐诗/poet.song.74000.json','["節臨重十慶天寧，古殿焚香祝帝齡。", "身在北方金佛剎，眼看南極老人星。", "千官花覆常陪燕，萬里雲遥阻在廷。", "松柏滿山聊獻壽，小臣孤操亦青青。"]'),
('251d5fd9-ae47-434a-aba2-d1240406e370','雨後蔬盤可喜偶成','滕茂實','宋','宋诗','song-poetry','','[]','過雨盤蔬日日新，從今休歎庾郎貧。',64,'全唐诗/poet.song.74000.json','["過雨盤蔬日日新，從今休歎庾郎貧。", "寒虀安取咄嗟辦，火食不憂生苑鄰。", "野莧何施雖可鄙，美芹欲獻去無因。", "干戈萬里風塵晦，慚媿平生肉食人。"]'),
('7cf3d88f-3234-422a-b67a-4502be36c2f8','五日','滕茂實','宋','宋诗','song-poetry','','[]','節物驚心動遠思，薰風又見浴蘭時。',64,'全唐诗/poet.song.74000.json','["節物驚心動遠思，薰風又見浴蘭時。", "空尋好句書紈扇，無復佳人繫綵絲。", "酒注菖蒲唯欲醉，筒包菰黍不勝悲。", "明年此日當何處，風裏孤蓬自不知。"]'),
('cb19488e-62fa-4726-bd68-438e0d6ebef4','喜雨','滕茂實','宋','宋诗','song-poetry','','[]','旱暵雨霑渥，豐穰都不疑。',48,'全唐诗/poet.song.74000.json','["旱暵雨霑渥，豐穰都不疑。", "商羊應屢舞，布穀强多知。", "龍見寧非數，雲行自有時。", "當年班夏令，曾得近丹墀。"]'),
('c134945c-f993-4e45-b82b-da6f44b4206f','偶成','滕茂實','宋','宋诗','song-poetry','','[]','纖雲卷盡見秋容，古木交陰一埽空。',64,'全唐诗/poet.song.74000.json','["纖雲卷盡見秋容，古木交陰一埽空。", "雪壓羣山曉來雨，葉侵缺甃幾番風。", "欲歸未得人將老，屢送還來鬼亦窮。", "頼得子卿佳傳在，整冠時讀慰飄蓬。"]'),
('2ff523b8-46f3-46e6-8834-07c1aa8dd77b','立春','滕茂實','宋','宋诗','song-poetry','','[]','東皇布政物皆春，山色禽聲便可人。',64,'全唐诗/poet.song.74000.json','["東皇布政物皆春，山色禽聲便可人。", "滿谷和風消積雪，半窗晴日動游塵。", "宮花插帽枝枝秀，菜甲堆槃種種新。", "拘窘經時成土俗，聊從一醉適天真。"]'),
('576bb219-eb59-4e49-a8f9-64d7d915f416','臨終詩','滕茂實','宋','宋诗','song-poetry','','[]','虀鹽老書生，謬列王都官。',288,'全唐诗/poet.song.74000.json','["虀鹽老書生，謬列王都官。", "索米了無補，從事敢辭難。", "殊鄰復盟好，仗節來榆關。", "城守久不下，川塗望漫漫。", "儉輩果不惜，一往何當還。", "牧羊困蘇武，假道拘張騫。", "流離念窘束，坐閱四序遷。", "同來悉言歸，我獨留塞垣。", "形影自相吊，國破家亦殘。", "呼天竟不聞，痛甚傷肺肝。", "相逢老兄弟，悼歎安得掛。", "金人自南歸，得志鞍馬間。", "波瀾卷大厦，一木難求安。", "世事寧有此，聊發我所存。", "爵祿非所慕，金珠敢懷貪。", "就不違我心，渠不汗我顔。", "昔燕破齊王，羣臣望風奔。", "王蠋猶守節，燕人有甘言。", "經首自絕脰，感槩今昔聞。", "未嘗食齊祿，徒以世爲民。", "況我祿數世，一死何足論。", "遠或死江海，近或死朝昏。", "斂我不須衣，裹尸以黄幡。", "題作宋臣墓，篆字當深刊。"]'),
('8b0f0c0d-9d2e-4275-a5dc-7903d2ff7f2a','贈吳德夫','郭忠孝','宋','宋诗','song-poetry','','[]','雲霄拂衣早，幽意滿江湖。',48,'全唐诗/poet.song.74000.json','["雲霄拂衣早，幽意滿江湖。", "天地英聲在，風流何代無。", "屬辭還兩漢，垂釣合三吳。", "倚棹傷今古，長歌擊唾壺。"]'),
('ec714bab-e81c-4bf6-a9cc-63af9be7c046','與呂微仲范彝叟登福山寺','郭忠孝','宋','宋诗','song-poetry','','[]','夾路東風花欲燃，羣仙携傍翠微巔。',64,'全唐诗/poet.song.74000.json','["夾路東風花欲燃，羣仙携傍翠微巔。", "空階遍撒金蓮火，虛殿高燒寶篆烟。", "禪寂靜談支遁後，道源真悟伏羲前。", "尋僧未及鳩蓮社，且共清樽石榻連。"]'),
('058a16b8-0c19-4046-8ebe-59e3064fe23f','寄張元德秘書','郭忠孝','宋','宋诗','song-poetry','','[]','良覿暌違數載餘，故人蹤跡近何如。',64,'全唐诗/poet.song.74000.json','["良覿暌違數載餘，故人蹤跡近何如。", "春秋藉子發精義，周易慚余無特書。", "山閣停雲愁絕處，屋梁落月夢回初。", "何時共剪西堂燭，尊酒論文剪野蔬。"]'),
('38db2283-31a7-49f5-9f22-bad1b752767e','句','潘中','宋','宋诗','song-poetry','','[]','二帝蒙塵事北征，小臣無計淚如傾。',16,'全唐诗/poet.song.74000.json','["二帝蒙塵事北征，小臣無計淚如傾。"]'),
('1cf377e6-272c-478e-9654-e37b4a68a01f','答問','釋思浄','宋','宋诗','song-poetry','','[]','平生只解念彌陀，不解參禪可奈何。',32,'全唐诗/poet.song.74000.json','["平生只解念彌陀，不解參禪可奈何。", "但得五湖風月在，太平不用起干戈。"]'),
('032324b4-3f21-4e07-96a9-b205aececcfd','過東湖','程邁','宋','宋诗','song-poetry','','[]','樞密中朝傑，常懷物外心。',48,'全唐诗/poet.song.74000.json','["樞密中朝傑，常懷物外心。", "碧山高杖履，黄髮樂泉林。", "菊釀上尊酒，風傳太古琴。", "烏衣佳子弟，玉樹正森森。"]'),
('bfb6de70-e9f9-41a0-aa16-360ed349db55','止戈堂和諸公韵','程邁','宋','宋诗','song-poetry','','[]','天河誰挽洗兵塵，遠播皇威到海濱。',64,'全唐诗/poet.song.74000.json','["天河誰挽洗兵塵，遠播皇威到海濱。", "畏壘草封悲戰月，樂郊農滿際春耕。", "七閩草木無腥氣，諸將恩勤有賜珍。", "穆穆清風堪作頌，猶沾湛露及微臣。"]'),
('b795249b-fc58-4350-ade7-c4bf3847588d','送友福建轉運判官','程邁','宋','宋诗','song-poetry','','[]','談經草檄鬢華生，初擁閩山傳節行。',64,'全唐诗/poet.song.74000.json','["談經草檄鬢華生，初擁閩山傳節行。", "江入桐廬青欲斷，溪從劍浦碧來迎。", "茶雖戶種租宜薄，鹽不家煎價欲平。", "要使祈招歌德意，君恩不爲遠人輕。"]'),
('cad3e379-5ac7-4389-8118-c2a3c806dbbb','靄山院','程邁','宋','宋诗','song-poetry','','[]','丙午峰前翠作堆，白雲深處現樓臺。',32,'全唐诗/poet.song.74000.json','["丙午峰前翠作堆，白雲深處現樓臺。", "老僧法地有神力，能使兇徒念佛回。"]'),
('24e0abf2-9ba2-4218-b8bf-a1bb3cea52bf','句  其一','詹默','宋','宋诗','song-poetry','','[]','茅屋不聞雪，紙窗宜讀書。',12,'全唐诗/poet.song.74000.json','["茅屋不聞雪，紙窗宜讀書。"]'),
('9b1092a3-0b97-480c-b78c-13cd9ef334d9','句  其二','詹默','宋','宋诗','song-poetry','','[]','山人誤採槍旗信，却怪枝頭雪未消。',16,'全唐诗/poet.song.74000.json','["山人誤採槍旗信，却怪枝頭雪未消。"]'),
('bb750798-9d92-48d9-9662-56eb55eda35c','句  其三','詹默','宋','宋诗','song-poetry','','[]','下僚竊有隨車喜，遥見枝頭少女風。',16,'全唐诗/poet.song.74000.json','["下僚竊有隨車喜，遥見枝頭少女風。"]'),
('f23852c0-6b58-4443-b0a6-e53d6e4b154a','句  其四','詹默','宋','宋诗','song-poetry','','[]','莫似公家三十五，時來不寄一行書。',16,'全唐诗/poet.song.74000.json','["莫似公家三十五，時來不寄一行書。"]'),
('e61c5bf8-bcca-4418-a688-a451b20c7b0f','三門砥柱','張保源','宋','宋诗','song-poetry','','[]','鑿開山骨過長河，水土方平敘九歌。',32,'全唐诗/poet.song.74000.json','["鑿開山骨過長河，水土方平敘九歌。", "舉世但傳神禹力，誰人知是帝功多。"]'),
('64fd2202-874c-4c2a-aba6-8c9eda8cd0b3','夫人城','王宗旦','宋','宋诗','song-poetry','','[]','詩人刺哲婦，老氏戒佳兵。',24,'全唐诗/poet.song.74000.json','["詩人刺哲婦，老氏戒佳兵。", "何此金湯固，長存粉黛名。"]'),
('b5d0edb1-9256-42cd-8288-4ae9615ccbde','石姥山','周兌','宋','宋诗','song-poetry','','[]','石貌蒼顔迥不殊，天工偶爾賦形軀。',32,'全唐诗/poet.song.74000.json','["石貌蒼顔迥不殊，天工偶爾賦形軀。", "頑然本是無情物，應誤行人指望夫。"]'),
('210d3eb5-d928-4dae-9da5-b4fb91f0edea','雨湧泉','周兌','宋','宋诗','song-poetry','','[]','楊岐山下出靈泉，與海相通亙古傳。',32,'全唐诗/poet.song.74000.json','["楊岐山下出靈泉，與海相通亙古傳。", "洶湧便知天欲雨，爲言陰石不須鞭。"]'),
('bc0103eb-a7d4-4c44-9fe7-15dd9b7e11d3','題毛仙山','周兌','宋','宋诗','song-poetry','','[]','仙翁辟穀綠毛生，假向人間作姓稱。',32,'全唐诗/poet.song.74000.json','["仙翁辟穀綠毛生，假向人間作姓稱。", "應與桐君爲伴侶，丹成白日共飛昇。"]'),
('c54558ae-1f53-4efb-98b2-9330975c9aac','羅漢影','周兌','宋','宋诗','song-poetry','','[]','法身無著本來空，應供隨緣處處同。',32,'全唐诗/poet.song.74000.json','["法身無著本來空，應供隨緣處處同。", "偶向石間留箇影，一輪秋日碧潭中。"]'),
('050f3765-7914-42fd-a93d-c3ce0ef96643','葛仙壇','周兌','宋','宋诗','song-poetry','','[]','稚川不戀晉衣冠，勾漏仙成九轉丹。',32,'全唐诗/poet.song.74000.json','["稚川不戀晉衣冠，勾漏仙成九轉丹。", "剩得數行風雨竹，人間珍重掃空壇。"]'),
('a2e46ba6-f089-4ea4-93db-51be4d8b33f4','九房石','周兌','宋','宋诗','song-poetry','','[]','巍巍古殿峙中央，匼匝屏風列九房。',32,'全唐诗/poet.song.74000.json','["巍巍古殿峙中央，匼匝屏風列九房。", "莫惜冥搜訪仙跡，其間恐有紫金林。"]'),
('6aea980d-ec77-4bc0-9150-09afdfa0cadf','鄂渚作','楊克一','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭無風時，上下皆明月。',24,'全唐诗/poet.song.74000.json','["洞庭無風時，上下皆明月。", "微波不敢興，甚靜蛟蜃穴。"]'),
('f9e40e43-e056-44ed-b0c2-8eec518cde6e','遺滎陽公','楊克一','宋','宋诗','song-poetry','','[]','雨綠霜紅郭外田，山濃水澹欲寒天。',32,'全唐诗/poet.song.74000.json','["雨綠霜紅郭外田，山濃水澹欲寒天。", "參軍抱病陪清賞，一檄呼歸亦可憐。"]'),
('bca68441-ae57-4392-be34-e0f37d8b8d9e','寄呂本中','楊克一','宋','宋诗','song-poetry','','[]','東平佳公子，好學到此郎。',24,'全唐诗/poet.song.74000.json','["東平佳公子，好學到此郎。", "別去今幾日，結交皆老蒼。"]'),
('c554ec83-6a18-4b74-90a3-58fa19be8755','句','楊克一','宋','宋诗','song-poetry','','[]','不知更事多，但覺拜人少。',12,'全唐诗/poet.song.74000.json','["不知更事多，但覺拜人少。"]'),
('2c7e6524-a144-4046-a1c8-a28136fa963c','端午','黄朝英','宋','宋诗','song-poetry','','[]','孟君此日鍾英氣，王鳳今朝襲慶源。',64,'全唐诗/poet.song.74000.json','["孟君此日鍾英氣，王鳳今朝襲慶源。", "五色呈祥文必顯，丙時先誕位非尊。", "蘭湯備浴傳荆俗，水馬浮江弔屈魂。", "因笑唐家公主騃，預令馳驛剪祗洹。"]'),
('892fddf3-ae3a-45c0-ab1c-5c2e6d0f0350','和運使修昇陽觀落成','吉康國','宋','宋诗','song-poetry','','[]','被命經營始，鳩工結構初。',168,'全唐诗/poet.song.74000.json','["被命經營始，鳩工結構初。", "深嚴開殿奧，高敞稱樓居。", "室外飛簷巘，岩隈下屋渠。", "鐘聲薄霄漢，祠事走邱墟。", "遯世誰能灑，登高迥莫如。", "鶴遊三島駕，人望五雲車。", "綺井風光潤，疏寮月影舒。", "威儀模紫極，形勢鞏堪輿。", "池有泉球舊，壇空級石餘。", "霓旌那復下，絳簡更誰書。", "童子追前躅，愚生泣太虛。", "烟霞猶赫奕，松竹自扶疏。", "封號方連進，休祥已密儲。", "躋茲仁壽域，率土慶于胥。"]'),
('d2d898fe-9a38-4c45-8287-833b8a5d56e2','田舍作','薛唐','宋','宋诗','song-poetry','','[]','世業存五畝，家風守二南。',48,'全唐诗/poet.song.74000.json','["世業存五畝，家風守二南。", "適情無過睡，幽事不妨貪。", "母老厨增肉，朋來樹選柑。", "每慚躬稼穡，未及野農諳。"]'),
('082feb57-dda2-409f-8097-75894db555ab','秋眠','薛唐','宋','宋诗','song-poetry','','[]','凉色正堪弄，新碪絕可憐。',48,'全唐诗/poet.song.74000.json','["凉色正堪弄，新碪絕可憐。", "况兼梧葉響，槭槭到床邊。", "群雁叫遠渚，孤雲停莫天。", "郊居迎送寡，秋日足高眠。"]'),
('37f9d730-a7c7-4b1b-822a-64c1d1ec264e','書壁','薛唐','宋','宋诗','song-poetry','','[]','自甘藜藿不求魚，大笑馮生出想車。',64,'全唐诗/poet.song.74000.json','["自甘藜藿不求魚，大笑馮生出想車。", "才子座中悲鄴下，高篇社裏厭黄初。", "不臣未遂忠臣志，生子猶能讀父書。", "酒後放言揮禿管，元龍豪氣本難除。"]'),
('89ec3089-cc30-4d0a-80d1-e8a5c6042be1','登州黄縣盧山延真觀紀異','徐三畏','宋','宋诗','song-poetry','','[]','芝陰舊是神仙宅，駕鶴泠風著前籍。',256,'全唐诗/poet.song.74000.json','["芝陰舊是神仙宅，駕鶴泠風著前籍。", "青冥倒影不可尋，閒有遺靈表奇跡。", "往時瑞草出西楹，蟠莖引蔓緣屋壁。", "蓊鬰青葱浄點塵，覆被仙容周幄帟。", "通人備考神農經，無說無名終不識。", "傳之於今三十年，目睹耳聆猶歷歷。", "邇來復見古砌下，冰結池面堅鐵石。", "中有鎖細百千狀，貫玉聯珠相倚植。", "鑪形塔影最明察，儼如天匠窮彫刻。", "堵觀魄動駭且疑，試爲求端一推覈。", "有道致祥聞自古，諒由叶氣潜薰炙。", "川珍嶽貢惟恐後，器車丹甑何由惜。", "舜廊淵默正垂衣，鴻塞清夷方偃伯。", "宜哉殊像發重□，□應興龍靡差忒。", "至聖謙沖美不居，瑞合圖書禁牋冊。", "草茅爵躍賦巴□，竊與堯民喧壤擊。"]'),
('18859ebc-2a99-4f12-8eeb-94fb6a30ee13','正月五日從德儉大夫遊盧山聖境坐中作以紀一時異事','守億','宋','宋诗','song-poetry','','[]','明庭事業青雲上，蹔屈鳴弦非所望。',192,'全唐诗/poet.song.74000.json','["明庭事業青雲上，蹔屈鳴弦非所望。", "聞有靈蹤在境中，何從揮鞭時一訪。", "石路盤紆入道家，老松偃蹇枝槎枒。", "昔年煮藥盧童子，嘗聞白日乘雲霞。", "紅塵不到神仙窟，殿宇荒凉古突兀。", "海近幽深春未來，寒風吹池水生骨。", "厚冰無文印沈冥，一泓斜卧雲母屏。", "屏底有物色如玉，隠隠結就浮圖形。", "澄澄照眼琉璃瑩，還同倒影落明鏡。", "殆非人巧出天工，聾俗安知凡與聖。", "吾皇德澤被四夷，産此正是興龍時。", "畫圖難展丹青手，聊作昇平瑞應詩。"]'),
('ddd46bcb-23f9-4a54-8f24-e833949bb31a','江梅','田亙','宋','宋诗','song-poetry','','[]','千林含凍鬰蒼蒼，只有江梅獨自芳。',64,'全唐诗/poet.song.74000.json','["千林含凍鬰蒼蒼，只有江梅獨自芳。", "暗吐幽香穿別院，半敧斜影入寒塘。", "冰膚宛是姑仙女，粉面端疑騎省郎。", "若是蜜奴曾拂掠，肯收紅艷貯蜂房。"]'),
('005c4821-65ae-455d-9048-0339c81f6599','飛鳶','田亙','宋','宋诗','song-poetry','','[]','涎涎晴空作鶻盤，仰空誰不羨高閑。',32,'全唐诗/poet.song.74000.json','["涎涎晴空作鶻盤，仰空誰不羨高閑。", "豈知盡日勞心眼，只在塵寰腐鼠間。"]'),
('9b9333c1-bd92-47d6-84fd-dcc427388402','王晉卿圖瀛山筆畫精緻京師貴遊蓄之爲希代之寶自圖書棄擲於路陽翟張飛卿見而得之過九江以遺友人傅延之延之出以示余余悲而賦詩','田亙','宋','宋诗','song-poetry','','[]','他日緘幐屬貴遊，詎知遷徙過南州。',32,'全唐诗/poet.song.74000.json','["他日緘幐屬貴遊，詎知遷徙過南州。", "天涯與汝共淪落，淚濕湓江烟雨秋。"]'),
('5108da75-e363-4ef6-89ca-f4d4dccaab2a','句  其一','田亙','宋','宋诗','song-poetry','','[]','趁暖不隨千卉折，凌寒先伴六花開。',16,'全唐诗/poet.song.74000.json','["趁暖不隨千卉折，凌寒先伴六花開。"]'),
('49b0220f-b324-42d3-bc40-59a946628265','句  其二','田亙','宋','宋诗','song-poetry','','[]','臨溪照影爲誰好，映竹無人空自憐。',16,'全唐诗/poet.song.74000.json','["臨溪照影爲誰好，映竹無人空自憐。"]'),
('67dbe1f8-74fa-4373-9870-af1db2ff6acf','句  其三','田亙','宋','宋诗','song-poetry','','[]','巡簷一笑屑瓊瑰。',8,'全唐诗/poet.song.74000.json','["巡簷一笑屑瓊瑰。"]'),
('5bfd25a0-6a8a-4a18-a207-0272a9f973bb','句  其四','田亙','宋','宋诗','song-poetry','','[]','幽姿高韵獨翛然。',8,'全唐诗/poet.song.74000.json','["幽姿高韵獨翛然。"]'),
('c435cd7a-5c4e-4383-8dd5-480d4ed5d733','句  其五','田亙','宋','宋诗','song-poetry','','[]','粉蝶風烟外，黄雲草樹秋。',12,'全唐诗/poet.song.74000.json','["粉蝶風烟外，黄雲草樹秋。"]'),
('5116a3a1-1391-4aa3-aa27-85d14536c13a','句  其六','田亙','宋','宋诗','song-poetry','','[]','已呼白面書生去，更約青腰玉女來。',16,'全唐诗/poet.song.74000.json','["已呼白面書生去，更約青腰玉女來。"]'),
('cf47ccaa-d89b-40d5-8747-3ebe3bc15e2b','句  其七','田亙','宋','宋诗','song-poetry','','[]','少時解奏三千牘，老去猶繙十二經。',16,'全唐诗/poet.song.74000.json','["少時解奏三千牘，老去猶繙十二經。"]'),
('c9814170-41e4-4bdc-8200-ed19cff90af8','蠟梅','王直方','宋','宋诗','song-poetry','','[]','紛紛紅紫雖無韵，映带園林却要渠。',32,'全唐诗/poet.song.74000.json','["紛紛紅紫雖無韵，映带園林却要渠。", "誰遺一枝香最勝，故應有客問何如。"]'),
('345d65e0-f8c6-42b3-8f73-07f4bf1c20e2','上巳遊金明池','王直方','宋','宋诗','song-poetry','','[]','游絲墮絮惹行人，酒肆歌樓駐畫輪。',64,'全唐诗/poet.song.74000.json','["游絲墮絮惹行人，酒肆歌樓駐畫輪。", "鳳管遏回雲冉冉，龍舟衝破浪粼粼。", "日斜黄繖歸馳道，風約青簾認別津。", "朝野歡娛真有象，壺中要看四時春。"]'),
('4695a576-b5e7-4c05-b4ac-da268ff758a0','淮安園','王直方','宋','宋诗','song-poetry','','[]','賢王經別墅，深窈近嚴城。',48,'全唐诗/poet.song.74000.json','["賢王經別墅，深窈近嚴城。", "花竹四時好，賓朋一座傾。", "闔奩爭弈罷，擊鉢記詩成。", "明日朝天去，門扃鳥雀驚。"]'),
('b44bc74b-c178-4cdf-a63b-b6034fe849e9','玉蕊花','王直方','宋','宋诗','song-poetry','','[]','閬苑瑶林春晚芳，仙妃舞困卸霓裳。',32,'全唐诗/poet.song.74000.json','["閬苑瑶林春晚芳，仙妃舞困卸霓裳。", "蠙珠委地隳雲佩，尚带天邊風露香。"]'),
('711ed5e5-17af-443f-b8d0-f10b00b60937','題清芬閣','王直方','宋','宋诗','song-poetry','','[]','人以詩自業，在唐如蜂房。',96,'全唐诗/poet.song.74000.json','["人以詩自業，在唐如蜂房。", "香英衆採擷，論功歸其王。", "恭維少陵老，實提六義綱。", "人能分一體，猶足生輝光。", "元英蕭散人，亦以詩道昌。", "餘雋獨不吮，嘉殽常自將。", "滄江下千尋，便足知流長。", "元英不可見，看取尚書郎。"]'),
('3bea6d94-8ef0-4de1-b98c-c069fb7da168','句','王直方','宋','宋诗','song-poetry','','[]','嚥服十二環，奄有仙人房。',36,'全唐诗/poet.song.74000.json','["嚥服十二環，奄有仙人房。", "暮騎紫鱗去，海氣侵肌凉。", "贈我纍纍珠，靡靡明月光。"]'),
('f3f586f0-7fdd-494f-8771-c7828fa52f67','臨終頌','何士昭','宋','宋诗','song-poetry','','[]','五十年住人世，靈臺不染纖瑕。',28,'全唐诗/poet.song.74000.json','["五十年住人世，靈臺不染纖瑕。", "壬午三更子時，天開萬里無霞。"]'),
('3affbe60-c73a-4206-868a-3facf7e434d9','句','韓瑨','宋','宋诗','song-poetry','','[]','已束歸鞍逐去鴻。',8,'全唐诗/poet.song.74000.json','["已束歸鞍逐去鴻。"]'),
('b738e372-2f47-43a7-bd69-df37f0f309ad','方潭展墓示子姪','劉安上','宋','宋诗','song-poetry','','[]','舊菴在山頂，去此五里餘。',276,'全唐诗/poet.song.74000.json','["舊菴在山頂，去此五里餘。", "創謀自吾祖，遷就今所居。", "往時僧不多，苟且完室廬。", "至於五十載，風雨荒榛蕪。", "先人樂溪山，每到嘗躊躇。", "深憐棟宇弊，締構新是圖。", "鑿巖闢幽徑，開門揖清虛。", "高堂閎且深，三山列庭隅。", "或禪或教律，濟濟蹌衣裾。", "先塋舊所卜，乃在西南隅。", "松筠老且茂，雲氣時卷舒。", "政和甲午歲，予解壽春符。", "寬恩得真祠，展省來郊墟。", "清酹奠墓隧，誥軸焚金朱。", "報效未云訖，涕泗徒漣如。", "朅來就堂宇，會飲族屬俱。", "夜深燈火明，山靜竹柏疏。", "翻思昔日營，似爲今所須。", "先人篤好善，雅志在詩書。", "于公有陰德，高大其門閭。", "虞詡名升卿，其後果不誣。", "嗟余忝厥修，覆敗良可虞。", "作詩以自警，其無迷厥初。"]'),
('cbb3ff98-f4bb-4f52-be58-912ed3ea0bd6','歲寒亭','劉安上','宋','宋诗','song-poetry','','[]','茲亭予所作，再到異疇昔。',48,'全唐诗/poet.song.74000.json','["茲亭予所作，再到異疇昔。", "江梅老半枯，檜柏春逾碧。", "易名爲歲寒，表此蒼翠色。", "森然一徑幽，步屧時取適。"]'),
('30452bfe-f00c-408b-88a4-c95033fad735','清漣亭泛舟','劉安上','宋','宋诗','song-poetry','','[]','高樹環清池，波平春正綠。',48,'全唐诗/poet.song.74000.json','["高樹環清池，波平春正綠。", "移舟近南崖，倒影見華屋。", "危梁屬修徑，幽思生遠目。", "更登狎鷗亭，可以忘寵辱。"]'),
('12464c6d-e239-49c8-b7d8-427cb793064c','西齋雜詠六首 葵花','劉安上','宋','宋诗','song-poetry','','[]','物性不可奪，葵藿傾太陽。',24,'全唐诗/poet.song.74000.json','["物性不可奪，葵藿傾太陽。", "爲臣茲取節，萬古有餘芳。"]'),
('6d0d4b3b-248c-4df8-a788-cde83c87570b','西齋雜詠六首 檜','劉安上','宋','宋诗','song-poetry','','[]','蔚蔚傲霜葉，亭亭綠池畔。',24,'全唐诗/poet.song.74000.json','["蔚蔚傲霜葉，亭亭綠池畔。", "莫言盈尺材，要是淩雲幹。"]'),
('a2a4a7ff-9303-476f-89f1-fd55e1ae262c','西齋雜詠六首 竹','劉安上','宋','宋诗','song-poetry','','[]','繁枝喜刪除，勁節見獨立。',24,'全唐诗/poet.song.74000.json','["繁枝喜刪除，勁節見獨立。", "灌溉未逾浹，新筍已戢戢。"]'),
('90687c67-9005-48f1-99c4-485d3da5880a','西齋雜詠六首 冬青','劉安上','宋','宋诗','song-poetry','','[]','得名固不誣，對植近庭廡。',24,'全唐诗/poet.song.74000.json','["得名固不誣，對植近庭廡。", "葉綠带寒烟，花繁泣微雨。"]'),
('99edbb24-cd98-496f-b93d-4b433de635a6','西齋雜詠六首 菊','劉安上','宋','宋诗','song-poetry','','[]','移根近軒墀，不使衆草沒。',24,'全唐诗/poet.song.74000.json','["移根近軒墀，不使衆草沒。", "會見黄金英，泛我杯中物。"]'),
('50fb4682-a65c-4f3d-a106-adb4574865f0','西齋雜詠六首 石斛','劉安上','宋','宋诗','song-poetry','','[]','鑿石空其中，貯水凡幾斛。',24,'全唐诗/poet.song.74000.json','["鑿石空其中，貯水凡幾斛。", "淵渟或可鑒，童子慎毋觸。"]'),
('395d9981-317b-48d7-8408-e2e20e474ce5','萬田道中','劉安上','宋','宋诗','song-poetry','','[]','水闊疑無路，雲深僅有山。',24,'全唐诗/poet.song.74000.json','["水闊疑無路，雲深僅有山。", "兒童划小艇，出沒稻塍間。"]'),
('afea5fa4-1447-4a9f-b168-404c2199ae09','方潭','劉安上','宋','宋诗','song-poetry','','[]','飯飽雲巖粟，茶甘碧澗泉。',24,'全唐诗/poet.song.74000.json','["飯飽雲巖粟，茶甘碧澗泉。", "我來無一事，危坐聽山蟬。"]'),
('e5daac56-12d6-4c18-b29b-5f4d8d5e8075','花靨鎮二首  其一','劉安上','宋','宋诗','song-poetry','','[]','下蔡嬉遊地，春風萬杏繁。',24,'全唐诗/poet.song.74000.json','["下蔡嬉遊地，春風萬杏繁。", "誰家堪繫馬，青壁竹籬門。"]'),
('493f77b8-144f-4728-9897-5ba740e0242e','花靨鎮二首  其二','劉安上','宋','宋诗','song-poetry','','[]','花靨誰名鎮，梅裝自古傳。',24,'全唐诗/poet.song.74000.json','["花靨誰名鎮，梅裝自古傳。", "家家小兒女，滿額點花鈿。"]'),
('98b42b85-0dd0-4caa-ab0f-c15083edd0bd','長溪建善寺四首 繡谷堂','劉安上','宋','宋诗','song-poetry','','[]','山谷誰能繡，華堂得此名。',24,'全唐诗/poet.song.74000.json','["山谷誰能繡，華堂得此名。", "春風無轍迹，紅紫自敷榮。"]'),
('de0d2459-5e88-40ac-ae34-b0776516fb01','長溪建善寺四首 龍湫亭','劉安上','宋','宋诗','song-poetry','','[]','亭下一杯水，澄泓如有容。',24,'全唐诗/poet.song.74000.json','["亭下一杯水，澄泓如有容。", "不因求得雨，那信有神龍。"]'),
('07821546-2934-4866-9594-5884589093d9','長溪建善寺四首 燕菴','劉安上','宋','宋诗','song-poetry','','[]','已涉艱危地，方能處燕安。',24,'全唐诗/poet.song.74000.json','["已涉艱危地，方能處燕安。", "人間不可忽，須向靜中看。"]'),
('b04702ef-f8da-4366-98de-fcdab0d902fe','長溪建善寺四首 白蓮堂','劉安上','宋','宋诗','song-poetry','','[]','瀟洒獻公房，幽深古道旁。',24,'全唐诗/poet.song.74000.json','["瀟洒獻公房，幽深古道旁。", "山形半環小，池面一奩方。"]'),
('959dd396-7021-4287-9ef1-34a7ab67f08a','長溪建善寺四首 仙巖莊','劉安上','宋','宋诗','song-poetry','','[]','山勢從東轉，河流自北來。',48,'全唐诗/poet.song.74000.json','["山勢從東轉，河流自北來。", "地幽饒水竹，山迥少塵埃。", "城郭居何遠，舟船暮可回。", "此中棲息穩，懷抱一時開。"]'),
('9ee61fa0-f9c8-4932-b494-ee74179a736f','重九宴集天柱間','劉安上','宋','宋诗','song-poetry','','[]','皖國逢重九，登臨摇落天。',48,'全唐诗/poet.song.74000.json','["皖國逢重九，登臨摇落天。", "盍簪追往事，吹帽想前賢。", "入眼吳萸紫，開觴鄧菊鮮。", "五雲亭最好，爭奈近靈仙。"]'),
('7ebdc28a-5d33-41e5-8265-9230d483fcad','和胡子文遊山寺值雨','劉安上','宋','宋诗','song-poetry','','[]','偷閑出城府，聊以洗塵心。',48,'全唐诗/poet.song.74000.json','["偷閑出城府，聊以洗塵心。", "自得林泉趣，何妨雨霧深。", "野亭連竹色，古寺想潮音。", "幸接高人論，清風滿素襟。"]'),
('352c7f9f-93cd-4bf6-8206-ce2a1eb27f55','憶鸂鶒二首  其一','劉安上','宋','宋诗','song-poetry','','[]','鸂鶒知何許，南園春水多。',48,'全唐诗/poet.song.74000.json','["鸂鶒知何許，南園春水多。", "稻粱隨分有，烟雨想無他。", "世上貪毛羽，湖邊足網羅。", "池塘棲息穩，慎勿厭風波。"]'),
('222a4261-0d37-45d4-a2a1-992577b76a73','憶鸂鶒二首  其二','劉安上','宋','宋诗','song-poetry','','[]','幸有春池闊，雙雙戲晚暉。',48,'全唐诗/poet.song.74000.json','["幸有春池闊，雙雙戲晚暉。", "庭閑宜對立，翅短莫高飛。", "寇賊已聞熄，主人行且歸。", "相將芰荷畔，看汝浴紅衣。"]'),
('8c121bea-6871-4a3b-a7f7-aeaed398c0c5','獨遊竹閣','劉安上','宋','宋诗','song-poetry','','[]','極目盡天際，風烟杳靄間。',48,'全唐诗/poet.song.74000.json','["極目盡天際，風烟杳靄間。", "水光清滉日，野色遠連山。", "白鹿今何在，高僧此獨閑。", "我今無伴侶，乘興一躋攀。"]'),
('ba4ffbba-7858-4511-872e-7bd5967224a7','宿方潭','劉安上','宋','宋诗','song-poetry','','[]','山中何所有，一味靜難名。',48,'全唐诗/poet.song.74000.json','["山中何所有，一味靜難名。", "暗谷流泉響，疏林落葉聲。", "夜深寒月白，霜重曉鐘清。", "早出松間路，衣裘空翠凝。"]'),
('3d4970ac-1050-4157-a99b-35a0b35cdc9b','贈釋達夫','劉安上','宋','宋诗','song-poetry','','[]','雲房依古城，闃靜戶常扃。',48,'全唐诗/poet.song.74000.json','["雲房依古城，闃靜戶常扃。", "苦行人難及，高吟鬼亦聽。", "望餘秋水遠，定起暮山青。", "世諦都無念，逢人自說經。"]'),
('f1cca1d6-68e6-4c37-8abf-9e6e5023c4ff','和少伊同左經臣湖上作','劉安上','宋','宋诗','song-poetry','','[]','共訪招提去，輕舟漾曉風。',48,'全唐诗/poet.song.74000.json','["共訪招提去，輕舟漾曉風。", "水光雲影裏，山色酒樽中。", "邊戍今休卒，吾生免轉蓬。", "茲遊惜不與，猶喜一篇同。"]'),
('4f4d3e16-fb98-4825-9075-b5ddf90d61ad','小飲','劉安上','宋','宋诗','song-poetry','','[]','南窗閑徙倚，風露已秋深。',48,'全唐诗/poet.song.74000.json','["南窗閑徙倚，風露已秋深。", "晚色兼凉至，浮雲带日陰。", "池荷欺碧玉，籬菊暗黄金。", "時序將遒盡，翻驚壯士心。"]'),
('aeb68819-5f66-4aed-bbc2-efaf9f8a554a','茶院紫翠閣','劉安上','宋','宋诗','song-poetry','','[]','小閣面空闊，下臨寒水清。',48,'全唐诗/poet.song.74000.json','["小閣面空闊，下臨寒水清。", "前山掛錦繡，日落轉分明。", "沙際小舟遠，雲間歸翅輕。", "我來看不厭，佇立獨含情。"]'),
('6b99eaa9-f1f7-4de3-9d44-f1e121fd9500','便齋','劉安上','宋','宋诗','song-poetry','','[]','芙蓉已過菊花殘，獨有松筠耐歲寒。',32,'全唐诗/poet.song.74000.json','["芙蓉已過菊花殘，獨有松筠耐歲寒。", "一榻蕭然無箇事，坐看紅日上欄干。"]'),
('ebf3ac7f-fc4c-47fe-860a-80b84262b15d','登煉丹山三絕句  其一','劉安上','宋','宋诗','song-poetry','','[]','攀沿絕壁上高峰，下瞰塵寰杳靄中。',32,'全唐诗/poet.song.74000.json','["攀沿絕壁上高峰，下瞰塵寰杳靄中。", "未飲刀圭跨鸞鶴，已如身世脫樊籠。"]'),
('03bbf99e-a189-42e6-88bc-7658393f5a90','登煉丹山三絕句  其二','劉安上','宋','宋诗','song-poetry','','[]','神仙已往遺基在，丹井淒清絕點埃。',32,'全唐诗/poet.song.74000.json','["神仙已往遺基在，丹井淒清絕點埃。", "歸去漏殘初睡醒，恍疑身到洞天來。"]'),
('7f0eafb3-edce-4b30-9b2d-b6107ad97328','登煉丹山三絕句  其三','劉安上','宋','宋诗','song-poetry','','[]','羣峰聳拔更迴環，鶴駕分明縹渺間。',32,'全唐诗/poet.song.74000.json','["羣峰聳拔更迴環，鶴駕分明縹渺間。", "金鼎丹成人不見，但留名字鎮空山。"]'),
('768b0d4f-76f0-4c48-aec1-5f2cd45ccee6','德翬梅軒月下小酌','劉安上','宋','宋诗','song-poetry','','[]','疏影橫斜落酒樽，誰知寒月上梅軒。',32,'全唐诗/poet.song.74000.json','["疏影橫斜落酒樽，誰知寒月上梅軒。", "昔年山相棲真地，我亦全家寄此村。"]'),
('9d4ac6a7-b97e-425e-b42d-162a5ca51146','宿棲林三首  其一','劉安上','宋','宋诗','song-poetry','','[]','誰知蹤跡到桐山，頼有禪僧數往還。',32,'全唐诗/poet.song.74000.json','["誰知蹤跡到桐山，頼有禪僧數往還。", "溪路水深行未得，小窗幽閣總躋攀。"]'),
('aaa8ea3e-de4e-4eca-b974-941a0275542e','宿棲林三首  其二','劉安上','宋','宋诗','song-poetry','','[]','回首江鄉路渺瀰，雨天行色倍遲遲。',32,'全唐诗/poet.song.74000.json','["回首江鄉路渺瀰，雨天行色倍遲遲。", "最憐山寺留連日，恰是清明禁火時。"]'),
('918adc75-0d9e-4502-b734-f5d099ad5dbd','宿棲林三首  其三','劉安上','宋','宋诗','song-poetry','','[]','征鞍終日雨霏霏，投宿棲林旋燎衣。',32,'全唐诗/poet.song.74000.json','["征鞍終日雨霏霏，投宿棲林旋燎衣。", "天意似憐行客倦，放將紅日出巖扉。"]'),
('306ead8a-56eb-475a-8e97-1e55ace78289','建善即事三首  其一','劉安上','宋','宋诗','song-poetry','','[]','繡嶺峰高插晚空，雨餘烟霧淡朦朧。',32,'全唐诗/poet.song.74000.json','["繡嶺峰高插晚空，雨餘烟霧淡朦朧。", "瓊枝細葉知多少，最愛團欒竹一叢。"]'),
('0fda1626-163f-44bd-936d-d7a783cd0fae','建善即事三首  其二','劉安上','宋','宋诗','song-poetry','','[]','春歸枝上餘花少，轉午濃陰綠滿蹊。',32,'全唐诗/poet.song.74000.json','["春歸枝上餘花少，轉午濃陰綠滿蹊。", "何事黄鸝語音好，慇懃飛傍粉牆啼。"]'),
('f46db4fe-40db-411e-bb08-48d721270dd5','建善即事三首  其三','劉安上','宋','宋诗','song-poetry','','[]','籜龍亭下知誰種，旋見新篁破綠苔。',32,'全唐诗/poet.song.74000.json','["籜龍亭下知誰種，旋見新篁破綠苔。", "到此不知纔幾日，抽梢今已過牆來。"]'),
('897817d4-5663-49c5-a31a-e20c808d2f24','玄沙二首  其一','劉安上','宋','宋诗','song-poetry','','[]','軒窗高下傍巖隈，花木層層取次栽。',32,'全唐诗/poet.song.74000.json','["軒窗高下傍巖隈，花木層層取次栽。", "誰道山深春色晚，等閑桃李已齊開。"]'),
('ad21523e-2f18-46c7-8249-e3e256bd9404','玄沙二首  其二','劉安上','宋','宋诗','song-poetry','','[]','飛山彷彿如天竺，環合峰巒一徑通。',32,'全唐诗/poet.song.74000.json','["飛山彷彿如天竺，環合峰巒一徑通。", "何日再來亭上宿，靜聽猿叫月明中。"]'),
('7501eb74-19d1-4a5e-adc3-8874ce44f831','大中西菴','劉安上','宋','宋诗','song-poetry','','[]','借得西菴不似菴，宛如蝸舍住城南。',32,'全唐诗/poet.song.74000.json','["借得西菴不似菴，宛如蝸舍住城南。", "晚來一盞亮功酒，更薦棲林八寸柑。"]'),
('012d0d1b-ca00-47a8-afee-e1791ad2bd8c','硤石相對有項羽廟','劉安上','宋','宋诗','song-poetry','','[]','乘閒驅馬向高原，楚漢遺基尚宛然。',32,'全唐诗/poet.song.74000.json','["乘閒驅馬向高原，楚漢遺基尚宛然。", "堪憐項羽成何事，占得淮邊屋數椽。"]'),
('126dca0d-fd88-4503-bd06-8ae9ca213d04','江村漁舍','劉安上','宋','宋诗','song-poetry','','[]','江邊茅屋被風掀，雨打疏窗夜小眠。',32,'全唐诗/poet.song.74000.json','["江邊茅屋被風掀，雨打疏窗夜小眠。", "催喚兒童五更起，重添篾纜繫漁船。"]'),
('3a3f61a4-22fd-4a9b-819f-f70c59cb0bda','晚步','劉安上','宋','宋诗','song-poetry','','[]','秋半淒然客思清，杖藜何處暢幽情。',32,'全唐诗/poet.song.74000.json','["秋半淒然客思清，杖藜何處暢幽情。", "晚天風雨莓苔活，閒傍欄干取次行。"]'),
('a75c0fa4-70eb-468e-9546-40573f2502bb','出局紀懷','劉安上','宋','宋诗','song-poetry','','[]','國爾忘家是所先，如何交構競爭權。',32,'全唐诗/poet.song.74000.json','["國爾忘家是所先，如何交構競爭權。", "霜臺白簡真可畏，一日五公俱左遷。"]'),
('229e2134-0dce-4684-b5d9-0a6091b516fb','蠟梅','劉安上','宋','宋诗','song-poetry','','[]','雙成送我蠟梅花，夜靜幽香自一家。',32,'全唐诗/poet.song.74000.json','["雙成送我蠟梅花，夜靜幽香自一家。", "疑是素娥乘月下，淡黄衣袂紫雲車。"]'),
('23e793b1-a328-40ad-9559-f666ebbff6fe','宿桐城驛二首  其一','劉安上','宋','宋诗','song-poetry','','[]','大農遺愛在桐川，血食於今幾百年。',32,'全唐诗/poet.song.74000.json','["大農遺愛在桐川，血食於今幾百年。", "應想歲豐秋賽日，送迎歌舞獨喧闐。"]'),
('8909fb49-b719-46dd-886a-e9e20305d3b0','宿桐城驛二首  其二','劉安上','宋','宋诗','song-poetry','','[]','桐溪古驛聞來久，我到梅黄雨細時。',32,'全唐诗/poet.song.74000.json','["桐溪古驛聞來久，我到梅黄雨細時。", "砌下流泉無復有，空餘松柏覆簷垂。"]'),
('75d965c3-539c-4bdf-bcd1-16e8c6300e83','即事','劉安上','宋','宋诗','song-poetry','','[]','江烟淡淡日落後，山雨纖纖潮上初。',32,'全唐诗/poet.song.74000.json','["江烟淡淡日落後，山雨纖纖潮上初。", "黄鶑引雛過林杪，羣雞就食喧階除。"]'),
('4faa7d00-8c51-41c4-b664-111680ba1cf5','澄源堂落梅如茵','劉安上','宋','宋诗','song-poetry','','[]','落英迴旋雪飛餘，誰向庭中細細鋪。',32,'全唐诗/poet.song.74000.json','["落英迴旋雪飛餘，誰向庭中細細鋪。", "借與翠娥相應舞，絕勝西蜀錦氍毹。"]'),
('b59c0f1d-71ba-42dd-8c63-05e470947fae','安豐道中','劉安上','宋','宋诗','song-poetry','','[]','陂渠積水與田通，彷彿江鄉意趣同。',32,'全唐诗/poet.song.74000.json','["陂渠積水與田通，彷彿江鄉意趣同。", "引起三吳耕釣興，小舟來往藕花中。"]'),
('083b8224-7e49-40eb-b61d-d53ae6e0b7bd','甘露亭二首  其一','劉安上','宋','宋诗','song-poetry','','[]','涵碧軒前甘露亭，暑天凉夕此閑行。',32,'全唐诗/poet.song.74000.json','["涵碧軒前甘露亭，暑天凉夕此閑行。", "琅玕一畝森如玉，影入池心徹底清。"]'),
('c52c77f4-6b87-49ed-8201-3f1399ec3c71','甘露亭二首  其二','劉安上','宋','宋诗','song-poetry','','[]','水斛安排鏡面平，菰蒲初種已齊生。',32,'全唐诗/poet.song.74000.json','["水斛安排鏡面平，菰蒲初種已齊生。", "晚來雨過浮萍少，看見魚兒作隊行。"]'),
('e2b82401-af2f-4a09-9bfe-a7de87b00f45','舒州西門送客亭','劉安上','宋','宋诗','song-poetry','','[]','拂雲亭外竹千竿，靜聽清聲戛玉寒。',32,'全唐诗/poet.song.74000.json','["拂雲亭外竹千竿，靜聽清聲戛玉寒。", "却憶謝公巖下路，水風凉處戰檀欒。"]'),
('56428ad3-51ed-4e5d-8aad-9810b982cd77','友人新居','劉安上','宋','宋诗','song-poetry','','[]','門向平湖靜處開，雨餘山色入簾來。',64,'全唐诗/poet.song.74000.json','["門向平湖靜處開，雨餘山色入簾來。", "連雲競秀千巖竹，隔水飄香一徑梅。", "觀裏紫芝元不老，柱頭玄鶴幾時回。", "此峰信是神仙窟，子晉吹簫有舊臺。"]'),
('64222abf-7c82-4f38-9343-fcff05fe7949','登謝公樓分韵得心字','劉安上','宋','宋诗','song-poetry','','[]','高峙危樓壓翠岑，登臨遥想昔賢心。',64,'全唐诗/poet.song.74000.json','["高峙危樓壓翠岑，登臨遥想昔賢心。", "人隨歲月有興廢，名逐江山無古今。", "殘日汀邊生晚思，斷雲簾外捲晴陰。", "清風凜凜今何在，芳草池塘恨獨深。"]'),
('587cd08c-5733-40c2-aaf7-24216523d4f5','即事','劉安上','宋','宋诗','song-poetry','','[]','未尋南郭舊生涯，且向淮堧太守家。',64,'全唐诗/poet.song.74000.json','["未尋南郭舊生涯，且向淮堧太守家。", "西圃學栽陶令菊，後園時種邵平瓜。", "民淳訟少看空圄，吏散庭空聽報衙。", "更得歲豐多樂事，宦遊誰復問年華。"]'),
('b420a2ad-7d85-4892-b320-ea9798d024ed','寄叔靜','劉安上','宋','宋诗','song-poetry','','[]','頻年京闕暗胡塵，竊發桐廬更駭聞。',64,'全唐诗/poet.song.74000.json','["頻年京闕暗胡塵，竊發桐廬更駭聞。", "食盡犬羊還自斃，火炎螻蟻却須焚。", "中原已有汾陽將，二浙誰驅下瀨軍。", "州郡雖嚴防守計，可將知略佐忠勤。"]'),
('603268f8-5a6a-4351-a65e-663a48084966','和左經臣見過','劉安上','宋','宋诗','song-poetry','','[]','爲愛端居上郡章，里閭何幸得徜徉。',64,'全唐诗/poet.song.74000.json','["爲愛端居上郡章，里閭何幸得徜徉。", "買田郭外春耕早，築室湖濱野趣長。", "且把舊書遮病眼，了無塵事擾中腸。", "故人訪我留佳句，應笑年來兩鬢蒼。"]'),
('77814973-b6a4-4368-8b17-016045170fac','荆溪有懷','劉安上','宋','宋诗','song-poetry','','[]','自從南郭得三椽，怕趁荆溪半夜船。',64,'全唐诗/poet.song.74000.json','["自從南郭得三椽，怕趁荆溪半夜船。", "每望白雲驚歲月，空將清夢遶林泉。", "雖因追遠時來此，又見登高意慘然。", "極目不知多少恨，一聲孤雁夕陽天。"]'),
('b37eb925-5e1e-4174-9011-a83d3fb8f850','聖泉','劉安上','宋','宋诗','song-poetry','','[]','聞道東山有聖泉，杖藜侵曉到山前。',64,'全唐诗/poet.song.74000.json','["聞道東山有聖泉，杖藜侵曉到山前。", "一泓寒玉流無盡，萬頃良田大有年。", "茶鼎曉煎雲脚嫩，齋厨夜引溜聲圓。", "我來一酌磁甌去，終日餘甘齒頰邊。"]'),
('7491b5d8-d5bd-45e4-b0a4-40d4076b5bab','四月一日壽陽樓遇雨','劉安上','宋','宋诗','song-poetry','','[]','黑雲滃蔚自西來，佇立危樓亦壯哉。',64,'全唐诗/poet.song.74000.json','["黑雲滃蔚自西來，佇立危樓亦壯哉。", "遠壑烟生千里雨，寒潭龍起數聲雷。", "田疇坐看還豐歲，里巷遥欣弭旱災。", "慚愧外官逃吏責，歸鞍何憚踏泥回。"]'),
('a50356df-9c66-41ea-a270-341719ffc02a','和馮中丞中秋夜月','劉安上','宋','宋诗','song-poetry','','[]','捲盡浮雲見碧虛，初傳更漏滴銅壺。',64,'全唐诗/poet.song.74000.json','["捲盡浮雲見碧虛，初傳更漏滴銅壺。", "入秋爽氣迥然別，此地冰輪何處無。", "共想姮娥依桂魄，獨憐飛鵲遶庭梧。", "西園飲散歸來早，不用紅紗照路隅。"]'),
('0716b609-6de7-4fdc-ad04-811892ff523b','又和十六夜月','劉安上','宋','宋诗','song-poetry','','[]','雲頭依舊尚團圓，未覺清光有兩般。',64,'全唐诗/poet.song.74000.json','["雲頭依舊尚團圓，未覺清光有兩般。", "自是人心重佳節，故將今夕不同看。", "望中銀漢祇如昨，坐久園亭又更寒。", "莫把盈虧妄分別，一杯到手且須乾。"]'),
('df0f3438-c261-4395-a839-6e7567a178fa','天柱峰','劉安上','宋','宋诗','song-poetry','','[]','天柱峰頭星斗紅，月明秋殿玉玲瓏。',32,'全唐诗/poet.song.74000.json','["天柱峰頭星斗紅，月明秋殿玉玲瓏。", "仙人夜半來吹笛，騎著吳江小赤龍。"]'),
('4aac7407-a8aa-47ac-84e8-92a2b021b2af','偈','釋應端','宋','宋诗','song-poetry','','["\u592a\u6e56"]','六合傾翻劈面來，暫披麻縷混塵埃。',64,'全唐诗/poet.song.74000.json','["六合傾翻劈面來，暫披麻縷混塵埃。", "因風吹火渾閑事，引得遊人不肯回。", "壞不壞，隨不隨，徒將聞見强針錐。", "太湖三萬六千頃，月在波心說向誰。"]'),
('d6bf1dda-90f6-485f-a4f6-3b5755e6131c','偈四首  其一','釋知昺','宋','宋诗','song-poetry','','[]','此事最希奇，不礙當頭說。',48,'全唐诗/poet.song.74000.json','["此事最希奇，不礙當頭說。", "東鄰田舍翁，隨例得一橛。", "非唯貫聲色，亦乃應時節。", "若問是何宗，八字不著丿。"]'),
('102bd75b-d422-4cd1-991d-40ebf1cb1e21','偈四首  其二','釋知昺','宋','宋诗','song-poetry','','[]','日日說，時時舉，似地擎山爭幾許。',64,'全唐诗/poet.song.74000.json','["日日說，時時舉，似地擎山爭幾許。", "隴西鸚鵡得人憐，大都祇爲能言語。", "休思惟，带伴侶，智者聊聞猛提取。", "更有一般也大奇，貓兒偏解捉老鼠。"]'),
('7bbf5bcd-4c7a-4c74-8898-caeb7c7c9e8c','偈四首  其三','釋知昺','宋','宋诗','song-poetry','','[]','春光爛熳華爭發，子規啼落西山月。',32,'全唐诗/poet.song.74000.json','["春光爛熳華爭發，子規啼落西山月。", "憍梵鉢提長吐舌，底事分明向誰說。"]'),
('c8717715-c987-4fee-9404-d2b92fd6641e','偈四首  其四','釋知昺','宋','宋诗','song-poetry','','[]','迷不自迷，對悟立迷。',66,'全唐诗/poet.song.74000.json','["迷不自迷，對悟立迷。", "悟不自悟，因迷說悟。", "所以悟爲迷之體，迷爲悟之用。", "迷悟兩無從，箇中無別共。", "無別共，撥不動。", "祖師不將來，鼻孔千斤重。"]'),
('378ab968-4892-4c78-b694-1603be27afc8','頌古二首 僧問清平有漏無漏。','釋知昺','宋','宋诗','song-poetry','','[]','笊籬木杓，錢買井索。',32,'全唐诗/poet.song.74000.json','["笊籬木杓，錢買井索。", "打瓦鑽龜，徒勞卜度。", "休卜度，麒麟只有一隻角。"]'),
('0aab222c-4002-4eec-8ee8-822334f2e730','頌古二首 僧問雪竇明覺如何是佛，曰四山圍繞。','釋知昺','宋','宋诗','song-poetry','','[]','狂狗逐塊，瞎馿趁隊。',20,'全唐诗/poet.song.74000.json','["狂狗逐塊，瞎馿趁隊。", "只許我知，不許你會。"]'),
('87b701ab-366e-498b-aa32-8e7221f2d62a','句','陳淬','宋','宋诗','song-poetry','','[]','數奇不是登壇將，竹杖芒鞋歸去來。',16,'全唐诗/poet.song.74000.json','["數奇不是登壇將，竹杖芒鞋歸去來。"]'),
('8f05cd0e-5827-481b-9a93-42ccd0ef346e','建炎丞相成國呂忠穆公退老堂詩  其一','汪伯彥','宋','宋诗','song-poetry','','[]','尚父重來國有瘳，再移雙袖揖浮丘。',64,'全唐诗/poet.song.74000.json','["尚父重來國有瘳，再移雙袖揖浮丘。", "進爲初迫人閒世，退老仍懷天下憂。", "娛戲烟霞資辟穀，栽培松菊助吟秋。", "天心此欲中興去，蕙帳山猿恐莫留。"]'),
('7f6a1819-6c1e-4078-8618-a406ad3210b3','建炎丞相成國呂忠穆公退老堂詩  其二','汪伯彥','宋','宋诗','song-poetry','','[]','脫冕遺軒息萬緣，歸來閒地作神仙。',64,'全唐诗/poet.song.74000.json','["脫冕遺軒息萬緣，歸來閒地作神仙。", "涉園靖節初成趣，得志莊周正樂全。", "物外情隨雲鵠舉，尊前身傍海鷗眠。", "功成者去天之道，知退如公法自然。"]'),
('1866cdc0-707b-49c3-99b7-77fd75531cb5','建炎丞相成國呂忠穆公退老堂詩  其三','汪伯彥','宋','宋诗','song-poetry','','[]','燕南三世識非羆，謀策江淮見吐奇。',64,'全唐诗/poet.song.74000.json','["燕南三世識非羆，謀策江淮見吐奇。", "千載五龍扶日轂，十年兩袂各天涯。", "知公卜築聊如此，嗟我求田昧所之。", "遥想園亭賓客會，夢飛胡蝶到芳帷。"]'),
('c0b11f3a-8da3-4cb3-9628-3e0343fd8614','東松庵','汪伯彥','宋','宋诗','song-poetry','','[]','萬夫屹立若臨衝，四十年來謁上峰。',32,'全唐诗/poet.song.74000.json','["萬夫屹立若臨衝，四十年來謁上峰。", "名遂歸來人物改，青青惟有歲寒松。"]'),
('1dab0f43-f39a-43d7-ada8-eddefe03f02f','句','汪伯彥','宋','宋诗','song-poetry','','[]','兩兩泰階星一色，亭亭華表鶴雙歸。',16,'全唐诗/poet.song.74000.json','["兩兩泰階星一色，亭亭華表鶴雙歸。"]'),
('09c6a5b5-ccc0-4192-b001-0b0fec12c7d5','過曹娥廟','釋覺先','宋','宋诗','song-poetry','','[]','縱步青蘿嶂，吟邊景更寬。',48,'全唐诗/poet.song.74000.json','["縱步青蘿嶂，吟邊景更寬。", "沙紋潮落見，山色雨餘看。", "汀草含清韵，江猨啼暮寒。", "娥祠重致敬，忍讀漢碑殘。"]');
